-- Poems batch 178
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('404ad3cc-9f1f-4d95-b14f-e8cc9a03f52a','開井','葛天民','宋','宋诗','song-poetry','','[]','小圃新穿土，中藏一丈空。',48,'全唐诗/poet.song.173000.json','["小圃新穿土，中藏一丈空。", "山腰泉脈透，井口樹陰蒙。", "澆藥先資用，煎茶已見功。", "甘凉羞自薦，汲許四鄰同。"]'),
('c6e6c337-10d0-4ce4-81b9-d22f9b94b05d','龍井','葛天民','宋','宋诗','song-poetry','','[]','龍護深潭草木昏，斷碑元祐典刑存。',32,'全唐诗/poet.song.173000.json','["龍護深潭草木昏，斷碑元祐典刑存。", "蜀仙已去吳僧少，嶺上松篁亦斷魂。"]'),
('541e57fe-2916-4d6f-98dc-fdeaa98536b7','江山','葛天民','宋','宋诗','song-poetry','','[]','連天芳草雨漫漫，贏得鷗邊野水寬。',32,'全唐诗/poet.song.173000.json','["連天芳草雨漫漫，贏得鷗邊野水寬。", "花欲盡時風撲起，柳綿無力護春寒。"]'),
('11d6bfbe-8f21-482d-855c-b35cf210b014','望越懷親','葛天民','宋','宋诗','song-poetry','','[]','高帝陵邊我故廬，白雲慘淡带蒼梧。',32,'全唐诗/poet.song.174000.json','["高帝陵邊我故廬，白雲慘淡带蒼梧。", "歸心政與江流動，更著青山隔岸呼。"]'),
('e833515c-1a1c-4d4c-babc-5a597260673d','寄輔漢卿','葛天民','宋','宋诗','song-poetry','','[]','憶殺平生輔漢卿，武夷山裏話寒更。',32,'全唐诗/poet.song.174000.json','["憶殺平生輔漢卿，武夷山裏話寒更。", "不知新歲還家未，白髮衝冠有幾莖。"]'),
('6d8e53e5-6a6b-4edf-b5a2-83029679e458','訪端叔提幹','葛天民','宋','宋诗','song-poetry','','[]','月趁潮頭上，山隨柁尾行。',48,'全唐诗/poet.song.174000.json','["月趁潮頭上，山隨柁尾行。", "大江中夜滿，雙櫓半空鳴。", "鴈冷來無幾，鷗清睡不成。", "平生師友地，此夕最關情。"]'),
('b84ad9af-0baa-46b3-88ce-210b2de4f28f','山中題古墓','葛天民','宋','宋诗','song-poetry','','[]','冢荒無樹亦無碑，土面磚痕似灼龜。',64,'全唐诗/poet.song.174000.json','["冢荒無樹亦無碑，土面磚痕似灼龜。", "壞道尚存翁仲守，傳家知是子孫誰。", "又成東海終難料，欲錮南山最可悲。", "要寄此情浮世去，臨流說與落花知。"]'),
('f8bdafdc-ca2a-44b6-9fff-d890a9f9fafd','題謝耕道一犁春雨圖','葛天民','宋','宋诗','song-poetry','','[]','耿耿思田舍，攸攸倚釣竿。',48,'全唐诗/poet.song.174000.json','["耿耿思田舍，攸攸倚釣竿。", "一犁歌短闋，十口飯長安。", "老覺驅馳倦，生知稼穡難。", "畫圖詩卷在，留與後人看。"]'),
('c946fb35-cf83-4e2e-9991-539abe17b6f5','即事','葛天民','宋','宋诗','song-poetry','','[]','暮年居柳下，終日閉柴門。',48,'全唐诗/poet.song.174000.json','["暮年居柳下，終日閉柴門。", "壁爲題詩暗，池因洗硯渾。", "閑知真冨貴，醉到古乾坤。", "回首長安道，無言只斷魂。"]'),
('28f9098a-d4cf-4551-bf7f-18bf4d447818','偶成','葛天民','宋','宋诗','song-poetry','','[]','始參龍象種，終現馬牛身。',48,'全唐诗/poet.song.174000.json','["始參龍象種，終現馬牛身。", "再整衝冠髻，難忘漉酒巾。", "散花天上女，撥草道中人。", "寄語林和靖，非翁不卜鄰。"]'),
('00569dcf-fac3-47a2-ba77-c90c045b6208','竹','葛天民','宋','宋诗','song-poetry','','[]','此君別後稍添丁，留得清風鎮戶庭。',64,'全唐诗/poet.song.174000.json','["此君別後稍添丁，留得清風鎮戶庭。", "老鬢不禁霜點綴，舊鄰多似樹凋零。", "一竿带雪寒垂釣，數畝連苔晝掩扃。", "此話有誰堪委似，幾回無語向青青。"]'),
('13d1c9ab-fac1-4ee3-ab78-637bdc35c10c','蓬居詠枇杷','葛天民','宋','宋诗','song-poetry','','[]','早誦相如賦，知渠舊姓盧。',48,'全唐诗/poet.song.174000.json','["早誦相如賦，知渠舊姓盧。", "花香冰裏見，風味藥中須。", "細雨同梅熟，清聲混樂呼。", "山禽嗔老子，拍竹護金珠。"]'),
('20679f10-ec80-45da-8bcb-dfcd42f80011','元夕','葛天民','宋','宋诗','song-poetry','','[]','天街夜鼓徹雲霄，一望星河影動摇。',64,'全唐诗/poet.song.174000.json','["天街夜鼓徹雲霄，一望星河影動摇。", "佳節無如元夕盛，老懷不似少年豪。", "紅塵巷陌青絲鞚，明月樓臺紫玉簫。", "誰料南坡招野叟，詩肩相對兩峰高。"]'),
('6a8f94b1-2b0a-44bd-aedd-a4c907addd08','簡道安','葛天民','宋','宋诗','song-poetry','','[]','相將除夜南風起，鴈已聲聲向北飛。',64,'全唐诗/poet.song.174000.json','["相將除夜南風起，鴈已聲聲向北飛。", "驟暖定知爲雪骨，瘦年終不似冬肥。", "日來病可方開酒，節下春回稍減衣。", "正好伴公湖上去，孤山觀裏看梅歸。"]'),
('f1cda375-542b-44cf-a4f0-6ed90fe59139','澗泉招飲次日乃生朝','葛天民','宋','宋诗','song-poetry','','[]','平生南磵古遺民，初度招呼我輩人。',64,'全唐诗/poet.song.174000.json','["平生南磵古遺民，初度招呼我輩人。", "每聽謔談須絕倒，極知老氣政輪囷。", "盃盤滿坐添燈火，兒女成行勸主賓。", "但願吾儕似梅柳，年年相見一回新。"]'),
('e34255a2-da79-4149-aefb-8e87b186ab0a','平居遣興','葛天民','宋','宋诗','song-poetry','','[]','隔籬人語自喧嘲，緊閉苔扉不許敲。',64,'全唐诗/poet.song.174000.json','["隔籬人語自喧嘲，緊閉苔扉不許敲。", "談麈带塵懸屋角，牽牛承露上林梢。", "投閑得計心常足，擬古成編手自抄。", "風雨欲來偏感處，蟻先移穴鵲移巢。"]'),
('e1bdf310-2ece-41fe-9a0b-4b6d5fca586f','桃花','葛天民','宋','宋诗','song-poetry','','[]','洞裏桃花自古初，人間塵事幾乘除。',64,'全唐诗/poet.song.174000.json','["洞裏桃花自古初，人間塵事幾乘除。", "重來漁父難相覓，前度劉郎未忍疎。", "畫檝迎逢春女渡，采符供奉歲朝書。", "嫣然似共幽篁語，占盡風光奈得渠。"]'),
('c4c9a2ea-9164-4cf7-a3f2-ecb2a9609b97','偶題','葛天民','宋','宋诗','song-poetry','','[]','綠樹何稠疊，清風稍羨餘。',48,'全唐诗/poet.song.174000.json','["綠樹何稠疊，清風稍羨餘。", "枕縈雲片片，簾透雨疎疎。", "脩筧通泉壑，殘碑出野鉏。", "丘陵知幾變，耕稼雜陶漁。"]'),
('79e45790-c500-4eef-b0ff-30a0329012aa','西湖泛舟入靈隠山','葛天民','宋','宋诗','song-poetry','','["\u897f\u6e56"]','晴嵐漠漠水溶溶，落葉遮船翠蓋重。',64,'全唐诗/poet.song.174000.json','["晴嵐漠漠水溶溶，落葉遮船翠蓋重。", "秋色盡爲漁者占，山光多向道人濃。", "雲連合抱前村樹，磵繞飛來小朵峰。", "送罷夕陽迎素月，樓臺高下自鳴鍾。"]'),
('78e731da-c378-4d6f-b1c5-b664cbf60096','梅花','葛天民','宋','宋诗','song-poetry','','[]','寄遠含芳別隴頭，胡沙漠漠去無休。',64,'全唐诗/poet.song.174000.json','["寄遠含芳別隴頭，胡沙漠漠去無休。", "誰招青塚千年魄，散作黄昏萬斛愁。", "畫角霜清腸屢斷，花光墨淡影空留。", "年年最憶前村夜，一段孤明雪亦羞。"]'),
('d5d2bbce-b5a9-4a40-af6b-4eaf26bfda58','幽居','葛天民','宋','宋诗','song-poetry','','[]','遠懷日與靜相宜，山色窺簾澗撼扉。',64,'全唐诗/poet.song.174000.json','["遠懷日與靜相宜，山色窺簾澗撼扉。", "野草自花聊獻笑，重雲不雨謾垂衣。", "人間事業難爭長，睡裏工夫獨造微。", "却怪蒙莊猶寐語，夢爲胡蝶未忘機。"]'),
('e59db976-5540-4d86-99a3-7dce195ce5a4','秋日西湖閑泛','葛天民','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雨洗千峰曉，波涵萬頃秋。',48,'全唐诗/poet.song.174000.json','["雨洗千峰曉，波涵萬頃秋。", "菱花開古鏡，蓮葉度輕舟。", "思遠人誰識，身閑世不收。", "望中時得句，倚櫂雜吳謳。"]'),
('38aa899b-3ecf-47d6-9932-dd722d208f31','郊園避暑','葛天民','宋','宋诗','song-poetry','','[]','有暑猶當避，無憂可得忘。',48,'全唐诗/poet.song.174000.json','["有暑猶當避，無憂可得忘。", "竹疏身共瘦，湖近意先凉。", "靜勝寧須弈，幽酣不待觴。", "還同殘夢樂，炙背負朝陽。"]'),
('614b9bf3-8588-473e-9fc3-90687c63b24c','小峰行樂却望北山','葛天民','宋','宋诗','song-poetry','','[]','霜高群木落，湖上數峰秋。',48,'全唐诗/poet.song.174000.json','["霜高群木落，湖上數峰秋。", "野笛歸牛徑，烟蓑宿鷺洲。", "望中多隠約，佳處小遲留。", "百歲無虛日，能堪幾度游。"]'),
('8c2e0057-90c9-4964-be64-f9bf010694d9','蝶','葛天民','宋','宋诗','song-poetry','','[]','黛拂雙眉粉襯毫，翅烘晴日伴相遭。',64,'全唐诗/poet.song.174000.json','["黛拂雙眉粉襯毫，翅烘晴日伴相遭。", "戲勾穉子從花遠，恐惹遊絲莫鬭高。", "栩栩倏來仍易散，深深交舞爲誰勞。", "吳王花草滕王筆，千載風流敵楚騷。"]'),
('77c56832-121c-4359-9007-a84e8ff731e7','杏花','葛天民','宋','宋诗','song-poetry','','[]','陌上春泥苦未乾，絳唇漸吐不禁寒。',64,'全唐诗/poet.song.174000.json','["陌上春泥苦未乾，絳唇漸吐不禁寒。", "海棠尚晚教誰伴，山帽衝風每自看。", "聲好最憐清曉賣，味甘長記綠陰團。", "年年過雨臙脂落，時序關心有幾般。"]'),
('0107f24f-a628-42a4-a532-e3f9db29969a','林間石','葛天民','宋','宋诗','song-poetry','','[]','摩挲只作釣磯看，相伴秦翁且住山。',64,'全唐诗/poet.song.174000.json','["摩挲只作釣磯看，相伴秦翁且住山。", "霜洗舊稜人共瘦，蘚侵孤韵鶴同閑。", "因思樵牧分爭處，已過唐虞揖遜間。", "風月滿林時憇寂，三生幽事夢中還。"]'),
('6ed0014b-efad-498f-98ba-947dcb79a120','小隠自題','葛天民','宋','宋诗','song-poetry','','[]','水拍荒籬外，山攢落照邊。',48,'全唐诗/poet.song.174000.json','["水拍荒籬外，山攢落照邊。", "鴉鴉乘犢去，鴨鴨伴鷗眠。", "思淡秋雲薄，情高隴月圓。", "武陵知避世，初不爲求仙。"]'),
('1c53e28d-ceda-4196-a7de-428c47fdd60d','夏日池上','葛天民','宋','宋诗','song-poetry','','[]','微波漾漾雨濛濛，岸脚烟莎間水葓。',64,'全唐诗/poet.song.174000.json','["微波漾漾雨濛濛，岸脚烟莎間水葓。", "照影已無雙鬢綠，關心猶有一絲風。", "鴛鴦對浴紅衣撲，菡萏相親翠蓋籠。", "醉舞夢吟皆勝處，箇中非異亦非同。"]'),
('4ce40d91-44f4-4848-bd67-71cf74e9aa39','孤山後寫望','葛天民','宋','宋诗','song-poetry','','[]','凭高每嘆昔人非，空有群峰礙落暉。',64,'全唐诗/poet.song.174000.json','["凭高每嘆昔人非，空有群峰礙落暉。", "大雅風流誰舉似，長安秋草又衰微。", "寒花負約開猶懶，幽鳥忘機趁不飛。", "來往半生堪記處，西村燈火夜船歸。"]'),
('5514944f-edc3-41ab-a01c-5a8d209a501d','小舟','葛天民','宋','宋诗','song-poetry','','[]','萬頃波中獨釣身，短倉低屋舊絲綸。',32,'全唐诗/poet.song.174000.json','["萬頃波中獨釣身，短倉低屋舊絲綸。", "自憐清夜歌明月，誰共滄洲采白蘋。"]'),
('5b158ec3-af70-4e87-afa2-d191188d3f0f','梅花','葛天民','宋','宋诗','song-poetry','','[]','桃李粗疎合負荆，歲寒標格許誰并。',64,'全唐诗/poet.song.174000.json','["桃李粗疎合負荆，歲寒標格許誰并。", "花中有道須稱最，天下無香可鬭清。", "倚竹向人如少訴，臨流窺影更多情。", "何當喚取湘纍起，伴我空山茹落英。"]'),
('a6988afa-7970-41e0-91ae-83ef20707e3d','孤山後舟中寫望','葛天民','宋','宋诗','song-poetry','','[]','水接遥空分外寬，孤山月出靜中看。',64,'全唐诗/poet.song.174000.json','["水接遥空分外寬，孤山月出靜中看。", "疑從弱水移圓嶠，似共姮娥住廣寒。", "秋雨秋風初過後，荷花荷葉半凋殘。", "西村數點歸鴉濕，老子新題墨未乾。"]'),
('cc1a6a02-bf6d-4e33-8734-0bcdf5059d7f','酬畫上人石湖春望','葛天民','宋','宋诗','song-poetry','','[]','蕩蕩春風草木香，茫茫澤國水雲長。',64,'全唐诗/poet.song.174000.json','["蕩蕩春風草木香，茫茫澤國水雲長。", "鶑來占柳爲歌院，蝶去尋花作醉鄉。", "閑與物情聊品带，老於文字懶巡行。", "望中別有關情處，幾度朝陽又夕陽。"]'),
('4aeab271-8558-4b03-8226-a7c6a4911a17','湖村晚興','葛天民','宋','宋诗','song-poetry','','[]','殘霞伴孤鶩，遠燒雜斜暉。',48,'全唐诗/poet.song.174000.json','["殘霞伴孤鶩，遠燒雜斜暉。", "秋向詩中出，人從畫裏歸。", "柳塘雙槳急，茅舍一燈微。", "小艇穿籬入，蒲蓬正擁扉。"]'),
('d30fbcb5-9152-46cc-b975-dcaac9275be1','雪後  其一','葛天民','宋','宋诗','song-poetry','','[]','雪中多日靜，湖上少人遊。',48,'全唐诗/poet.song.174000.json','["雪中多日靜，湖上少人遊。", "禿樹花爲市，斷槎鷗當舟。", "一杯殘臘酒，萬古夕陽愁。", "富貴非吾願，葛天雲正浮。"]'),
('7ccda3c2-ae43-40de-8f6c-fbeeff96bb04','雪後  其二','葛天民','宋','宋诗','song-poetry','','[]','冷蕊通幽信，孤山欠幾遭。',48,'全唐诗/poet.song.174000.json','["冷蕊通幽信，孤山欠幾遭。", "盃因寒更滿，句到淡方高。", "雪滴晴簷雨，松翻夜壑濤。", "布衾雖似鐵，猶念早趨朝。"]'),
('6c73e56f-7906-418d-9404-1707e0a248c1','臘雪','葛天民','宋','宋诗','song-poetry','','[]','片片嘉平瑞，無聲有耿光。',48,'全唐诗/poet.song.174000.json','["片片嘉平瑞，無聲有耿光。", "來雖成頃刻，釀亦費商量。", "天闊花無頼，風休絮不狂。", "孤山林處士，魂在隴頭香。"]'),
('d6c2dcc2-caff-47d7-b9d2-2b623a93543b','和子舒冷泉夜坐','葛天民','宋','宋诗','song-poetry','','[]','亭空山盡入，人靜夜初分。',48,'全唐诗/poet.song.174000.json','["亭空山盡入，人靜夜初分。", "喬木陰遮月，清泉影浸雲。", "不題波上葉，只採磵中芹。", "澗水令人憶，何當入郡聞。"]'),
('879d39ac-39cb-45f7-aa9c-3e3b9ba0e2a7','宿裴庵','葛天民','宋','宋诗','song-poetry','','[]','一徑松杉迥，成陰見日稀。',48,'全唐诗/poet.song.174000.json','["一徑松杉迥，成陰見日稀。", "山晴僧盡出，風暖燕交飛。", "結子花拋樹，攔人犬護扉。", "閑看山月上，清坐更添衣。"]'),
('aed1a4b3-8533-415e-ad32-bd112e7c389e','答趙紫芝','葛天民','宋','宋诗','song-poetry','','[]','九月離東嘉，長安了歲華。',48,'全唐诗/poet.song.174000.json','["九月離東嘉，長安了歲華。", "未登楊子渡，先訪葛翁家。", "天作今朝雪，燈開昨夜花。", "一杯能强飲，不必問丹砂。"]'),
('10889d0e-392a-4c0b-89bc-bad5224f68b7','簡趙紫芝','葛天民','宋','宋诗','song-poetry','','[]','紫芝雖漫仕，五字已專城。',48,'全唐诗/poet.song.174000.json','["紫芝雖漫仕，五字已專城。", "清坐有仙骨，苦吟無宦情。", "囊因詩句重，分與酒盃輕。", "所好煎茶外，燒香過一生。"]'),
('f101e095-e70f-4097-b964-09056b0dda69','清明前四日泛湖','葛天民','宋','宋诗','song-poetry','','[]','繞岸堆青嶂，游船滿綠波。',48,'全唐诗/poet.song.174000.json','["繞岸堆青嶂，游船滿綠波。", "樓臺臨水近，楊柳占春多。", "老去誰同調，尊前且放歌。", "韶華能幾日，隨棹已新荷。"]'),
('07e8057a-b15b-49df-9089-f58f9bfd0ebd','送薛予舒船官','葛天民','宋','宋诗','song-poetry','','[]','憶君江上去，船重載書多。',48,'全唐诗/poet.song.174000.json','["憶君江上去，船重載書多。", "學乃從吾好，閑應喜客過。", "薰風新綠樹，明月舊滄波。", "自古關情處，相思入詠歌。"]'),
('b409feda-4fbb-46b3-8b54-eb1ca05627e9','訪紫芝回與子舒集','葛天民','宋','宋诗','song-poetry','','[]','君參唐句法，親得浪仙衣。',48,'全唐诗/poet.song.174000.json','["君參唐句法，親得浪仙衣。", "薄宦因吟苦，高風與世違。", "春寒留夜飲，月黑借燈歸。", "共隠知何日，空山老蕨薇。"]'),
('917de5c3-43bf-4e24-8cef-9385eb010d08','即事用天竺韵','葛天民','宋','宋诗','song-poetry','','[]','寒食少逢天氣佳，十朝九日雨如麻。',32,'全唐诗/poet.song.174000.json','["寒食少逢天氣佳，十朝九日雨如麻。", "新巢唯有燕生子，小巷已無人賣花。"]'),
('1963e525-64c9-4621-8500-1e4711df71ea','夏日','葛天民','宋','宋诗','song-poetry','','[]','曉荷承墜露，晚岫障斜陽。',48,'全唐诗/poet.song.174000.json','["曉荷承墜露，晚岫障斜陽。", "樹下地常蔭，水邊風最凉。", "蟬移驚鵲近，鷺起得魚忙。", "獨坐觀群動，閑消夏日長。"]'),
('b4e7b7f2-974f-43a9-909f-c6e02f9a3493','雜詩','葛天民','宋','宋诗','song-poetry','','[]','下竺山前打一遭，丁寧門子看溪橋。',32,'全唐诗/poet.song.174000.json','["下竺山前打一遭，丁寧門子看溪橋。", "恐驚繞磵梅花落，莫遣行人語笑高。"]'),
('371d9d45-e5c8-4a5d-a929-38b11f5a58bd','雨中','葛天民','宋','宋诗','song-poetry','','[]','梅雨朝仍暮，蓮塘夏似秋。',48,'全唐诗/poet.song.174000.json','["梅雨朝仍暮，蓮塘夏似秋。", "水高侵樹脚，屋漏滴人頭。", "歇晝厨烟出，占晴礎汗收。", "群山思會面，扶病一登樓。"]'),
('accf404a-79af-4f00-a053-ff7995e9f41f','元夕','葛天民','宋','宋诗','song-poetry','','[]','元宵有月便無愁，已是新年第一籌。',32,'全唐诗/poet.song.174000.json','["元宵有月便無愁，已是新年第一籌。", "說與素娥從此去，只須依樣做中秋。"]'),
('89388dec-a43c-4313-8943-8fffabf5dabd','送薛子舒  其一','葛天民','宋','宋诗','song-poetry','','[]','南渡今何似，中流欲濟船。',48,'全唐诗/poet.song.174000.json','["南渡今何似，中流欲濟船。", "雖憑人擊楫，要若水行川。", "竹木如山積，桑田與海連。", "吳宮猶可問，白鳥暮推煙。"]'),
('8ba5f13c-273d-49e7-985a-97bd4de3b53f','送薛子舒  其二','葛天民','宋','宋诗','song-poetry','','[]','海邑青龍鎮，船官野鶴身。',48,'全唐诗/poet.song.174000.json','["海邑青龍鎮，船官野鶴身。", "誰知貴公子，却是苦吟人。", "二陸多遺迹，三高屬近鄰。", "新篇因吊古，時寄葛天民。"]'),
('7d02bb6f-42e0-48a0-8bc2-c885f0fbfcc8','次紫芝韵','葛天民','宋','宋诗','song-poetry','','[]','欽羨私居好，樓深夏必凉。',48,'全唐诗/poet.song.174000.json','["欽羨私居好，樓深夏必凉。", "小窗通遠岫，古木蔽斜陽。", "露檻安花斛，塵編滿竹床。", "如君清到骨，只合靜焚香。"]'),
('4d3bb900-60ef-431c-89b4-4c066f1d523f','小亭','葛天民','宋','宋诗','song-poetry','','[]','小亭終日對幽叢，兀坐無言似定中。',64,'全唐诗/poet.song.174000.json','["小亭終日對幽叢，兀坐無言似定中。", "蒼蘚靜連湘竹紫，綠陰深映蜀葵紅。", "貓來戲捉穿花蝶，雀下偷銜卷葉蟲。", "斜照尚多高柳少，明年更欲種梧桐。"]'),
('e3a94b1f-47e8-492d-9f98-fb22ce7cd653','上巳呈嚴叟','葛天民','宋','宋诗','song-poetry','','[]','時俗常談已斷霜，雨寒翻著絮衣裳。',64,'全唐诗/poet.song.174000.json','["時俗常談已斷霜，雨寒翻著絮衣裳。", "花枝照眼堂堂去，茗椀關心故故香。", "楊柳稍傳鶑割據，茅茨敢望燕商量。", "舊遊莫誦蘭亭語，自覺中年易感傷。"]'),
('c4151781-07a7-425c-8abf-9974ee393390','荷葉浦中','葛天民','宋','宋诗','song-poetry','','[]','急雨捎荷分外奇，珠璣狼籍錦紛披。',64,'全唐诗/poet.song.174000.json','["急雨捎荷分外奇，珠璣狼籍錦紛披。", "下塘六月關心處，西塞扁舟入手時。", "却傍青蘆深處宿，還思白石去年詩。", "平生浩蕩煙波趣，月淡風微只自知。"]'),
('eacf3d81-d61f-4509-9979-6920f483e118','贈眇目道人說相','葛天民','宋','宋诗','song-poetry','','[]','道人只具一隻眼，覿面全提格外機。',32,'全唐诗/poet.song.174000.json','["道人只具一隻眼，覿面全提格外機。", "塵裏神仙誰做得，歸來試舉問麻衣。"]'),
('77f7fe49-76f7-4f21-b547-c780f1b5ad2c','戊辰夏五過抱朴岩','葛天民','宋','宋诗','song-poetry','','[]','北窗隠隠透南薰，老子全身是此君。',64,'全唐诗/poet.song.174000.json','["北窗隠隠透南薰，老子全身是此君。", "冷入魚腮池面雨，靜連禽語樹頭雲。", "苔因覓句行來破，石爲觀空坐得溫。", "時事自多無耳聽，長安雖近不曾聞。"]'),
('abd999e1-a95e-4197-aacf-e973daf27dc0','元夕西陵橋觀月','葛天民','宋','宋诗','song-poetry','','[]','年頭半月雪漫漫，養就姮娥玉一團。',32,'全唐诗/poet.song.174000.json','["年頭半月雪漫漫，養就姮娥玉一團。", "老子今宵奇絕處，西陵橋上獨凭欄。"]'),
('f702fff8-20ac-40cd-97a9-130de0b12a39','雨中郊外','葛天民','宋','宋诗','song-poetry','','[]','暖氣先回宿草根，青青行可藉芳尊。',32,'全唐诗/poet.song.174000.json','["暖氣先回宿草根，青青行可藉芳尊。", "未須著意催花柳，且爲乾坤補燒痕。"]'),
('8e76ec2f-8dea-49a5-816b-01a85ec88fa1','正月二日','葛天民','宋','宋诗','song-poetry','','[]','小巷春陰獨掩扉，峭寒著盡過冬衣。',32,'全唐诗/poet.song.174000.json','["小巷春陰獨掩扉，峭寒著盡過冬衣。", "老來情緒無多子，禁得梅花似雪飛。"]'),
('f2573e16-ce79-47cc-a1c9-0364db21443a','正月二十七雨中過蘇堤','葛天民','宋','宋诗','song-poetry','','[]','一堤楊柳占春風，柳外群山細雨中。',32,'全唐诗/poet.song.174000.json','["一堤楊柳占春風，柳外群山細雨中。", "人苦未晴渾不到，只宜老眼看空濛。"]'),
('b6f2196a-7106-42b7-9390-b16507e34c93','清明日訪白石不值','葛天民','宋','宋诗','song-poetry','','[]','花薺懸燈柳插簷，老懷那得似餳甜。',32,'全唐诗/poet.song.174000.json','["花薺懸燈柳插簷，老懷那得似餳甜。", "畫船已載先生去，燕子無人自入簾。"]'),
('f421690c-cd1a-46cc-8b11-095f5223af64','送劉僧善行','葛天民','宋','宋诗','song-poetry','','[]','西望群山碧入吳，故人一笠片雲俱。',32,'全唐诗/poet.song.174000.json','["西望群山碧入吳，故人一笠片雲俱。", "東風不斷村村柳，展盡陽關送客圖。"]'),
('8f2a6338-e143-417f-8aaa-3ba36a0816dc','湖堤晚步','葛天民','宋','宋诗','song-poetry','','[]','照影憐寒水，關情奈夕陽。',48,'全唐诗/poet.song.174000.json','["照影憐寒水，關情奈夕陽。", "雪慳天欠冷，年近日添長。", "好句誰相寄，浮生各自忙。", "有身聊頓放，亡事可思量。"]'),
('e3bc873e-0569-40e8-a8ac-0d94ddb555a9','懷天竺磵梅','葛天民','宋','宋诗','song-poetry','','[]','根在巖邊結，枝從水際橫。',48,'全唐诗/poet.song.174000.json','["根在巖邊結，枝從水際橫。", "此花殊近道，凡木欠修行。", "密雪籠幽片，疎篁倚瘦莖。", "那時香不淺，憶我話無生。"]'),
('b01c9167-f314-490c-81bd-f8692536368a','柳下即事','葛天民','宋','宋诗','song-poetry','','[]','老柳中間野岸濱，水清常照村邊身。',32,'全唐诗/poet.song.174000.json','["老柳中間野岸濱，水清常照村邊身。", "白鷗黄鳥相忘久，來往如今不避人。"]'),
('b9b56bc8-c272-4afc-a530-fe9f522ab64e','睡少','葛天民','宋','宋诗','song-poetry','','[]','睡少秋難曉，吟多食愈貧。',24,'全唐诗/poet.song.174000.json','["睡少秋難曉，吟多食愈貧。", "南柯無近闕，差盡夢中人。"]'),
('69e1cbcc-a6be-4dc2-a9b4-a202ed1c8c96','湖上新秋','葛天民','宋','宋诗','song-poetry','','["\u897f\u6e56"]','十里荷風蓋盡傾，城中憶殺水邊清。',32,'全唐诗/poet.song.174000.json','["十里荷風蓋盡傾，城中憶殺水邊清。", "催詩末用西湖雨，且送新凉入帝城。"]'),
('a624692f-4f00-4d79-b904-510a19b27b2b','六月一日同姜白石泛湖','葛天民','宋','宋诗','song-poetry','','["\u897f\u6e56"]','六月西湖带雨山，小舟終日傍鷗閑。',64,'全唐诗/poet.song.174000.json','["六月西湖带雨山，小舟終日傍鷗閑。", "風煙如許關情甚，賓主相推下語難。", "幾點送君歸大雅，一凉今夜滿長安。", "江湖遠思知多少，歸去風前各倚欄。"]'),
('515ead86-422d-47be-a7d6-c984a078cf97','正月十二日夜姚江','葛天民','宋','宋诗','song-poetry','','[]','斷岸春風峭，江空夜雨清。',48,'全唐诗/poet.song.174000.json','["斷岸春風峭，江空夜雨清。", "蕭疎蓬上點，彷彿葉間聲。", "今古雙眸冷，乾坤一棹輕。", "鬢從湖海白，誰識謝郎情。"]'),
('c9154bf7-33fe-495d-ab8e-75005aff34a1','雨中獨酌','葛天民','宋','宋诗','song-poetry','','[]','平生寡合雖竭斗，幾曾自飲一杯酒。',160,'全唐诗/poet.song.174000.json','["平生寡合雖竭斗，幾曾自飲一杯酒。", "不因風月與湖山，更爲松篁與花柳。", "今夕何夕風雨來，知儂渴肺生秋埃。", "麴生三緘忽自薦，請爲風雨聊一開。", "老夫呼前呼未了，死生脫帽傾懷抱。", "風雨橫斜入坐中，賓主淋漓俱醉倒。", "須臾風止雨亦休，主人送客凝雙眸。", "葛天無懷不可狀，但覺兩耳風颼颼。", "匆匆便是中秋節，更與麴生潜地說。", "此夜寧容著雜賓，一尊只辦澆明月。"]'),
('b459c0b6-8780-4223-8ded-431a54f7e0a2','水仙','葛天民','宋','宋诗','song-poetry','','[]','玉澗金寒窈窕身，翩翩翠袖挽青春。',64,'全唐诗/poet.song.174000.json','["玉澗金寒窈窕身，翩翩翠袖挽青春。", "水晶宮裏成仙女，香醉山中得道人。", "朔雪幾回埋不死，南洲一出浄無塵。", "朴翁老矣誰同調，相對無言意轉親。"]'),
('45570bb0-57cc-4185-a08f-6665fb6e9b00','丈亭館','葛天民','宋','宋诗','song-poetry','','[]','青山歷歷映江流，半是明州半越州。',32,'全唐诗/poet.song.174000.json','["青山歷歷映江流，半是明州半越州。", "亭下寒潮亭上客，不知來往幾時休。"]'),
('8bc73906-d9d8-4294-870b-880481d229e8','絕句','葛天民','宋','宋诗','song-poetry','','[]','二十四友金谷宴，千三百里錦帆遊。',32,'全唐诗/poet.song.174000.json','["二十四友金谷宴，千三百里錦帆遊。", "人間無此春風樂，樂極人間無此愁。"]'),
('e6344252-6520-4e13-89ee-b1ce1ae8b409','嘗北梨','葛天民','宋','宋诗','song-poetry','','[]','每到年頭感物華，新嘗梨到野人家。',32,'全唐诗/poet.song.174000.json','["每到年頭感物華，新嘗梨到野人家。", "甘酸尚带中原味，腸斷春風不見花。"]'),
('1ac556ff-2d5a-48d4-b653-b6e18ef1da1f','船子鈞灘','葛天民','宋','宋诗','song-poetry','','[]','澤國茫茫水接天，孰云無法與人傳。',32,'全唐诗/poet.song.174000.json','["澤國茫茫水接天，孰云無法與人傳。", "見成風月難迴避，盡在華亭一釣船。"]'),
('f0e38271-3ec2-479b-9f6c-00b5cd956b59','題南翔寺','葛天民','宋','宋诗','song-poetry','','[]','南翔建自梁天監，白鶴不歸江自轉。',176,'全唐诗/poet.song.174000.json','["南翔建自梁天監，白鶴不歸江自轉。", "深禪空憶祖師齊，昔有老堪今有遠。", "我趁江鷗訪遠公，遠公不有湖天晚。", "七歲驅鳬有幾房，三百苾蒭無半面。", "殿閣參差高入雲，一堂可著千僧飯。", "古柏槎牙不記年，柯如屈鐵色蒼蘚。", "古意偏關倦客懷，歸舟有句無人遣。", "明日中流遇阿英，連宵細說南翔院。", "少待崇蓮寶塔成，春風共看巢梁燕。", "我欲婆娑借數椽，子當力學如吾願。", "一任江花惱殺人，閒邊自數飛花片。"]'),
('86b30f6e-a29f-462b-9c3a-05b5a6df7a5d','和葛天民南翔寺韵','釋普洽','宋','宋诗','song-poetry','','[]','白鶴南翔何日返，香雲不動春風轉。',176,'全唐诗/poet.song.174000.json','["白鶴南翔何日返，香雲不動春風轉。", "屋爲鱗次枕江安，江作蛇行到門遠。", "的的明燈金殿寒，沉沉複道長廊晚。", "老翁矍鑠皎須眉，愛客將迎笑盈面。", "自言天監拓基來，食指數千猶共飯。", "斷碑壁下試摩挲，龜趺剝落生苔蘚。", "茫茫往事比寒潮，蒼烟落日愁難遣。", "遣中何處愜深深，玉甃新池開別院。", "二齊已去老堪殂，故壘空來巢舊燕。", "吾宗有弟知此懷，炊黍功名豈云願。", "便呼阿買寫新詩，研池澀擁清冰片。"]'),
('4e027bcd-c278-4c5c-b414-13e4477baf1b','紹熙辛亥歲遷居星洲述懷','朱權','宋','宋诗','song-poetry','','[]','別墅今爲宅，芳洲古號星。',216,'全唐诗/poet.song.174000.json','["別墅今爲宅，芳洲古號星。", "一溪縈似带，羣岫列如屏。", "繚繞蟠龍勢，迴旋翥鳳形。", "紫峰鍾美瑞，秀麗炳神靈。", "峻嶺通山去，寒潭對剎渟。", "高巖雙傑出，斜谷獨深扃。", "鷗鷺遵幽渚，牛羊散遠汀。", "春花紛外野，秋月可中庭。", "築室歌鴻雁，謀鄰詠鶺鴒。", "來居猶未久，補弊不遑寧。", "愛竹留新笋，看松養茯苓。", "採山收美茹，釣水得鮮鯖。", "檠短親諸子，窗明勘六經。", "桂香思璧水，槐影記楓庭。", "事業姑藏器，功名會發鉶。", "豈無牙父志，當遇子期聽。", "鵰鶚須逢運，驊騮豈戀坰。", "祇今時合待，拄笏謾名亭。"]'),
('6563e5da-0d9f-42ad-86fc-42083aee123d','象耳山','袁倚','宋','宋诗','song-poetry','','[]','昔聞神龍蟠九淵，今睹大象扶諸天。',96,'全唐诗/poet.song.174000.json','["昔聞神龍蟠九淵，今睹大象扶諸天。", "何年幻此一佛國，兩耳不動山蒼然。", "上乘菩薩踞其上，妙千手眼化大千。", "衆生顛倒夢始覺，熱病得汗諸魔跧。", "兩客游山飲崖泉，拍手喚醒書臺仙。", "一邱一壑儻如願，同竟大悲香火緣。"]'),
('33b8f63a-e56e-414a-b9c6-0b260dd7e2e1','句','袁倚','宋','宋诗','song-poetry','','[]','江頭曉夜日月出，九頂三峨相吐吞。',16,'全唐诗/poet.song.174000.json','["江頭曉夜日月出，九頂三峨相吐吞。"]'),
('31c1a594-7f4f-4af9-9567-3c07fdb9d20c','十二峰 望霞','閻伯敏','宋','宋诗','song-poetry','','[]','東皇君來流曉霞，莫看西北王母家。',32,'全唐诗/poet.song.174000.json','["東皇君來流曉霞，莫看西北王母家。", "雲華夫人王母女，肯爲廟食留三巴。"]'),
('41f95588-103c-4781-a603-b1d2a0ecc6f2','十二峰 翠屏','閻伯敏','宋','宋诗','song-poetry','','[]','秋山黄落春山青，不識仙家雲錦屏。',32,'全唐诗/poet.song.174000.json','["秋山黄落春山青，不識仙家雲錦屏。", "六銖天衣下拂石，香風馥郁朝真亭。"]'),
('88c9cc9e-56e9-488b-bdbf-a01b3b12d741','十二峰 朝雲','閻伯敏','宋','宋诗','song-poetry','','[]','山頭行雲自朝朝，陽臺莫色聯雲霄。',32,'全唐诗/poet.song.174000.json','["山頭行雲自朝朝，陽臺莫色聯雲霄。", "朝來莫去變雲雨，送老行客無回橈。"]'),
('d693f163-e421-4298-ad47-fba062a2bd43','十二峰 松巒','閻伯敏','宋','宋诗','song-poetry','','[]','舟船摇摇大巫前，松間絲蘿望纏綿。',32,'全唐诗/poet.song.174000.json','["舟船摇摇大巫前，松間絲蘿望纏綿。", "屏風角轉恰匝背，心在山頭人倚船。"]'),
('022f2c22-fe1b-4b25-8bd0-31f01d44b7d9','十二峰 集仙','閻伯敏','宋','宋诗','song-poetry','','[]','綠蓑鞋緊青行纏，束薪藴火開山田。',32,'全唐诗/poet.song.174000.json','["綠蓑鞋緊青行纏，束薪藴火開山田。", "雲間仰聽仙佩響，蓬鬢拂掠燒畬煙。"]'),
('7f9b9384-2893-455d-bf0a-b6fa9e800558','十二峰 聚鶴','閻伯敏','宋','宋诗','song-poetry','','[]','望夫石女春復秋，巴歌楚舞隨遨遊。',32,'全唐诗/poet.song.174000.json','["望夫石女春復秋，巴歌楚舞隨遨遊。", "夜深九皇清唳響，仙禽亦替離人愁。"]'),
('59d15640-d452-44ac-bfff-42e84471dc0d','十二峰 浄壇','閻伯敏','宋','宋诗','song-poetry','','[]','山頭枝枝竹掃壇，舟子竹枝歌上灘。',32,'全唐诗/poet.song.174000.json','["山頭枝枝竹掃壇，舟子竹枝歌上灘。", "炷香上廟擲杯珓，但乞如願舟平安。"]'),
('0b21cf30-71db-4733-9c3a-19f580025db5','十二峰 上昇','閻伯敏','宋','宋诗','song-poetry','','[]','黄麾白馬功告成，雲華夫人朝玉京。',32,'全唐诗/poet.song.174000.json','["黄麾白馬功告成，雲華夫人朝玉京。", "虞后夏后引音節，高低峽船摇艣聲。"]'),
('45f80361-a890-4f1d-999f-8012069504f4','十二峰 起雲','閻伯敏','宋','宋诗','song-poetry','','[]','釵頭嫋嫋山花枝，裙尾舊纈山麻衣。',32,'全唐诗/poet.song.174000.json','["釵頭嫋嫋山花枝，裙尾舊纈山麻衣。", "朝隨雲起采薪去，莫趁女伴穿雲歸。"]'),
('91771e1e-c8c3-4b97-8dce-61290313f327','十二峰 栖鳳','閻伯敏','宋','宋诗','song-poetry','','[]','山頭鳳鳴求其凰，山前家家背鳳筐。',32,'全唐诗/poet.song.174000.json','["山頭鳳鳴求其凰，山前家家背鳳筐。", "竹花結實未忍食，刀耕火種五里香。"]'),
('9df3acc3-6e8e-4c29-92cf-eb28f0b47d16','十二峰 登龍','閻伯敏','宋','宋诗','song-poetry','','[]','散而成章合爲龍，回風混合游鴻濛。',32,'全唐诗/poet.song.174000.json','["散而成章合爲龍，回風混合游鴻濛。", "舟人上下神女供，俗粧鉛粉臙脂紅。"]'),
('836a1eaf-6fb4-4ef3-88a9-db2d0e95ed97','十二峰 聖泉','閻伯敏','宋','宋诗','song-poetry','','[]','雲源一派瑶池分，灑落掉石隨東奔。',32,'全唐诗/poet.song.174000.json','["雲源一派瑶池分，灑落掉石隨東奔。", "楚人但憂香溪水，溪邊惟有昭君村。"]'),
('5e955f35-a461-48b8-8a55-592741bfb18d','送王木叔黄州教職','戴溪','宋','宋诗','song-poetry','','[]','龍飛乙科郎，白面如琢玉。',216,'全唐诗/poet.song.174000.json','["龍飛乙科郎，白面如琢玉。", "去作幕下士，年少二十六。", "壯心直如弦，不耐公事曲。", "寧知太守尊，箠吏驚羣目。", "太守豈不賢，去郡秉鈞軸。", "銓曹有格法，那肯煩薦牘。", "依然舊官職，再傍天之麓。", "六考未作縣，冷官到淮服。", "向來豪氣舉，斟酒能半斛。", "只今長說病，伏飲在胸腹。", "皇皇一世憂，隠隠兩眉蹙。", "中年苦節省，未必不爲福。", "我生更迂闊，立意要違俗。", "誤使塵網纓，同君被纏束。", "兩家各生子，丁壬合天祿。", "但得佳兒婦，兩翁志願足。", "岷山有舊約，相從結□□。", "明朝江上館，持被共君宿。"]'),
('a3358d68-273e-4364-8c37-eb679bce8412','養蠶行','姚寅','宋','宋诗','song-poetry','','[]','南村老婆頭欲雪，曉傍牆陰採桑葉。',227,'全唐诗/poet.song.174000.json','["南村老婆頭欲雪，曉傍牆陰採桑葉。", "我行其野偶見之，試問春蠶何日結。", "老婆斂手復低眉，未足四眠那知得。", "自從紙上掃青子，朝夕餧飼如嬰兒。", "只今上筐十日許，食葉如風響如雨。", "夜深人靜不敢眠，自遶牀頭逐饑鼠。", "又聞野祟能相侵，典衣買紙燒蠶神。", "一家心在陰雨裏，只恐葉溼繰難勻。", "明朝滿簇收銀繭，軋軋車聲快如剪。", "小姑促湯娘剝紕，嬉嬉始覺雙眉展。", "繰成白雪不敢閑，錦上織成雙鳳團。", "天寒尺寸不得著，盡與乃翁輸縣官。", "君不見長安女兒嫩如水，十指不動衣羅綺。", "我曹辛苦徒爾耳，依舊績麻冬日裏。"]'),
('4529a74c-eb74-45f1-9577-24918d005ae6','投戴岷隠分教','姚寅','宋','宋诗','song-poetry','','[]','重席先生間世才，相逢青眼必須開。',32,'全唐诗/poet.song.174000.json','["重席先生間世才，相逢青眼必須開。", "手遮紅日汗如雨，不是雪中乘興來。"]'),
('81ab87bf-2956-4635-88a8-83c04b8072d3','梅花','王默','宋','宋诗','song-poetry','','[]','知己林和靖，論心何水曹。',48,'全唐诗/poet.song.174000.json','["知己林和靖，論心何水曹。", "平生懷玉雪，獨立占風騷。", "月落香方覺，天寒韻更高。", "冥搜吟未就，清夢滿江皋。"]'),
('19f8029d-a6d3-4bd4-a799-0f6b97ad1b7f','春花歎','王默','宋','宋诗','song-poetry','','[]','春花復春花，紅紅間白白。',72,'全唐诗/poet.song.174000.json','["春花復春花，紅紅間白白。", "相看待明發，已不如昨日。", "雨露費濡染，秉芳幾何時。", "姚魏殿春事，濃綠已盈枝。", "長安池館多，新故如轉燭。", "所以山中人，但種松與竹。"]'),
('909ffaaf-989a-4901-b84f-35bd5f8751ff','春雪','陳洪','宋','宋诗','song-poetry','','[]','光映粧樓月，花承歌扇風。',24,'全唐诗/poet.song.174000.json','["光映粧樓月，花承歌扇風。", "欲妬梅將柳，故落早春中。"]'),
('e041136b-981c-4bcc-b5af-ee875feae18a','椒溪灘','李鏜','宋','宋诗','song-poetry','','[]','一梁中截兩山連，雪布寒飛幾竅穿。',64,'全唐诗/poet.song.174000.json','["一梁中截兩山連，雪布寒飛幾竅穿。", "深鑿却疑通禹穴，長流應不比潮泉。", "崆峒影裏分三峽，太極圖中會百川。", "神斧何年平石壁，新題許我得深鎸。"]'),
('3ad3f096-8414-497a-84bf-93170d03d40a','金紫巖','李鐊','宋','宋诗','song-poetry','','[]','百尺雲巖道院邊，曉鐘疎磬思悠然。',64,'全唐诗/poet.song.174000.json','["百尺雲巖道院邊，曉鐘疎磬思悠然。", "荷間酌酒和清露，石上題詩染翠烟。", "半嶺泉鳴通古澗，數家秋盡隔寒川。", "西風似欲吹人起，去逐騎鯨汗漫仙。"]'),
('f05adecc-c27e-46a1-8453-8c26990dcc90','挽蔡西山先生','吳雅','宋','宋诗','song-poetry','','[]','天乎不可問，吾道是耶非。',48,'全唐诗/poet.song.174000.json','["天乎不可問，吾道是耶非。", "國論成貝錦，臺評及布衣。", "乾坤豈終否，泉壤再生輝。", "遺恨舂陵路，生存不見歸。"]'),
('dbfaa638-5452-4022-b994-071cf7741336','小亭','任希夷','宋','宋诗','song-poetry','','[]','幅巾清曉入西園，春動園林物物鮮。',32,'全唐诗/poet.song.174000.json','["幅巾清曉入西園，春動園林物物鮮。", "却想小亭纔日出，海棠花發麝香眠。"]'),
('5de2b016-1090-4346-a5df-65657b6c4fa3','花','任希夷','宋','宋诗','song-poetry','','[]','今年輕作東風客，愁紫愁紅滿故園。',32,'全唐诗/poet.song.174000.json','["今年輕作東風客，愁紫愁紅滿故園。", "邂逅妖嬈成一笑，待歸端有幾枝存。"]'),
('4f21ee5e-9e85-4265-8f71-8c78f806922e','牡丹','任希夷','宋','宋诗','song-poetry','','[]','沉香亭北露華春，曾識霓裳第一人。',32,'全唐诗/poet.song.174000.json','["沉香亭北露華春，曾識霓裳第一人。", "千載不歸羅襪夢，綠枝紅艷只如新。"]'),
('5643f305-eec4-4933-88f6-96441df41fd1','海棠','任希夷','宋','宋诗','song-poetry','','[]','海棠花上問春歸，豈料春風雪滿枝。',32,'全唐诗/poet.song.174000.json','["海棠花上問春歸，豈料春風雪滿枝。", "應爲紅粧太妖豔，故施微粉著胭脂。"]'),
('71f79de9-fde2-4f4e-9603-8e3e4128ccd6','垂絲海棠','任希夷','宋','宋诗','song-poetry','','[]','宛轉風前不自持，妖嬈微傅淡胭脂。',32,'全唐诗/poet.song.174000.json','["宛轉風前不自持，妖嬈微傅淡胭脂。", "花如剪綵層層見，枝似輕絲裊裊垂。"]'),
('c9e9395f-23a1-451d-9d65-a2562aa4f5b5','海棠二首  其一','任希夷','宋','宋诗','song-poetry','','[]','山碧花尤好，徑長人自閒。',24,'全唐诗/poet.song.174000.json','["山碧花尤好，徑長人自閒。", "錦圍春照耀，紅雨暮闌斑。"]'),
('e3e83bcb-e435-4809-a932-b555aaa14226','海棠二首  其二','任希夷','宋','宋诗','song-poetry','','[]','紅粧翠袖一番新，又向園林作好春。',32,'全唐诗/poet.song.174000.json','["紅粧翠袖一番新，又向園林作好春。", "却笑華清誇睡足，只今羅襪久無塵。"]'),
('ab1a4639-480e-4e14-b264-942541c87c61','蓮','任希夷','宋','宋诗','song-poetry','','[]','五月荷池未見花，但擎餘蓋碧參差。',32,'全唐诗/poet.song.174000.json','["五月荷池未見花，但擎餘蓋碧參差。", "何人喚起凌波步，要見晨粧出曉霞。"]'),
('fa011e4b-9712-4c2c-9794-0a798090a9de','賞桂  其一','任希夷','宋','宋诗','song-poetry','','[]','人間植物月中根，碧樹分敷散寶熏。',32,'全唐诗/poet.song.174000.json','["人間植物月中根，碧樹分敷散寶熏。", "自是莊嚴等金粟，不將妖豔比紅裙。"]'),
('c24a423b-55cd-40d8-b313-8172816a0dae','賞桂  其二','任希夷','宋','宋诗','song-poetry','','[]','金英翠葉庇靈根，吹作清秋寶篆熏。',32,'全唐诗/poet.song.174000.json','["金英翠葉庇靈根，吹作清秋寶篆熏。", "四客對花飛玉斚，八眉和葉舞紅裙。"]'),
