('eeab55d5-2dbc-424d-a3cc-2380ae7b3076','郊壇齋宮七首  其一','任希夷','宋','宋诗','song-poetry','','[]','郊禋從昔重升中，八陛崇尊典禮隆。',32,'全唐诗/poet.song.174000.json','["郊禋從昔重升中，八陛崇尊典禮隆。", "聖主寅恭先事舉，雲陽新築望祠宮。"]'),
('ba4d5aef-b342-4700-a7f0-cfa8ee0f70f8','郊壇齋宮七首  其二','任希夷','宋','宋诗','song-poetry','','[]','上林日射蒼龍闕，九陌風清野馬塵。',32,'全唐诗/poet.song.174000.json','["上林日射蒼龍闕，九陌風清野馬塵。", "恰似樓臺臨渭水，未饒桃李滿天津。"]'),
('9d687f2f-d4b0-444f-85be-34b7883da011','郊壇齋宮七首  其三','任希夷','宋','宋诗','song-poetry','','[]','玉津宏建中興初，禁籞風光勝兩都。',32,'全唐诗/poet.song.174000.json','["玉津宏建中興初，禁籞風光勝兩都。", "慚愧逢辰瞻蠖濩，却思歸老卧廜㢝。"]'),
('ba95ad47-6d38-4987-b22c-3a7831aeb851','郊壇齋宮七首  其四','任希夷','宋','宋诗','song-poetry','','[]','榮路輝輝日月依，雲霄奕奕孔鸞飛。',32,'全唐诗/poet.song.174000.json','["榮路輝輝日月依，雲霄奕奕孔鸞飛。", "輔臣對罷升金殿，日日絲絇侍衮衣。"]'),
('96e9ca5c-111b-4b5b-a988-6d4743b11f35','郊壇齋宮七首  其五','任希夷','宋','宋诗','song-poetry','','[]','當日金階白玉堂，不知春事到垂楊。',32,'全唐诗/poet.song.174000.json','["當日金階白玉堂，不知春事到垂楊。", "休驚冉冉花飛片，正愛青青麥耀芒。"]'),
('72bf8053-130d-4dd6-8bbb-0d0a43ad03d1','郊壇齋宮七首  其六','任希夷','宋','宋诗','song-poetry','','[]','帝籍傍連繭館桑，禁林喬木晝陰涼。',32,'全唐诗/poet.song.174000.json','["帝籍傍連繭館桑，禁林喬木晝陰涼。", "却從射殿臨江閣，中有通衢夾苑牆。"]'),
('874d1339-1e45-4d39-b5c8-d754a2c4e8b2','郊壇齋宮七首  其七','任希夷','宋','宋诗','song-poetry','','[]','漢苑空傳承露盤，不聞臨幸又春殘。',32,'全唐诗/poet.song.174000.json','["漢苑空傳承露盤，不聞臨幸又春殘。", "吾君恭儉前無比，只向郊祠響玉鑾。"]'),
('4f864c13-0f56-4f6d-bf36-3bba5c621d3c','明堂慶成五首  其一','任希夷','宋','宋诗','song-poetry','','[]','國重明禋預戒期，九筵宏敞肅宗祈。',64,'全唐诗/poet.song.174000.json','["國重明禋預戒期，九筵宏敞肅宗祈。", "階前萬旅皆花帽，庭下千官盡絳衣。", "三日齋心嚴殿宿，一聲清蹕響簾幃。", "聖躬靡恃皇天眷，夙夜寅恭但畏威。"]'),
('eda6412b-14ce-47b2-bc22-bdceba7c2fb4','明堂慶成五首  其二','任希夷','宋','宋诗','song-poetry','','[]','芝房羽駕備通宵，昧爽天興輦路遥。',64,'全唐诗/poet.song.174000.json','["芝房羽駕備通宵，昧爽天興輦路遥。", "原廟出遊卑漢祀，太清先獻踵唐朝。", "冕旒穆穆陞前殿，鐘石鏘鏘達九霄。", "謬忝侍臣分奏告，嘉觴肅薦徧宗祧。"]'),
('c7201123-d001-42af-be24-9916461010e0','明堂慶成五首  其三','任希夷','宋','宋诗','song-poetry','','[]','合宮三歲縟儀收，太室先期肇自周。',64,'全唐诗/poet.song.174000.json','["合宮三歲縟儀收，太室先期肇自周。", "玉瓚黄流躬祼鬯，大圭玄冕薦嘉羞。", "靈臺畢舉三千禮，鑾路安行十二斿。", "導從却歸齋殿去，詰朝牡璧對天休。"]'),
('8d988d5d-ebba-4eb1-8f57-ff965ccd56b1','明堂慶成五首  其四','任希夷','宋','宋诗','song-poetry','','[]','仲辛肆事展明堂，磬管鏘鳴更令芳。',64,'全唐诗/poet.song.174000.json','["仲辛肆事展明堂，磬管鏘鳴更令芳。", "蒼璧肅陳勤聖主，二觴嘉薦屬儲皇。", "雲車天上紛紛下，月鑑庭中穆穆光。", "八舉親祠俱響答，吾皇誠意感穹蒼。"]'),
('83a35dff-c9e8-4210-8875-f0f10715d20c','明堂慶成五首  其五','任希夷','宋','宋诗','song-poetry','','[]','紫宸朝罷御端門，天宇澄清景氣溫。',64,'全唐诗/poet.song.174000.json','["紫宸朝罷御端門，天宇澄清景氣溫。", "丹鳳樓中黄繖立，金雞竿上綵旗翻。", "萬人聳聽風雷號，四海均霑雨露恩。", "須信卑宮勤肆祀，君王本意在元元。"]'),
('a335d21c-81f2-457a-af05-51e104867938','扈從朝獻四首  其一','任希夷','宋','宋诗','song-poetry','','[]','齊宿連宵鳳掖西，纔交五鼓著朝衣。',32,'全唐诗/poet.song.174000.json','["齊宿連宵鳳掖西，纔交五鼓著朝衣。", "明當接盞天興殿，免從金輿入殿幃。"]'),
('a220a148-e77f-4d26-9545-4202d77dc9de','扈從朝獻四首  其二','任希夷','宋','宋诗','song-poetry','','[]','夕郎同列升金殿，分立虛皇寶座前。',32,'全唐诗/poet.song.174000.json','["夕郎同列升金殿，分立虛皇寶座前。", "天子參神來縟位，侍臣夾跪御爐邊。"]'),
('b85ce1cc-4e3c-40c7-aee8-b6dc5f9fba7c','扈從朝獻四首  其三','任希夷','宋','宋诗','song-poetry','','[]','扈從齊宮每賜茶，玉甌常瀹建溪芽。',32,'全唐诗/poet.song.174000.json','["扈從齊宮每賜茶，玉甌常瀹建溪芽。", "今朝值雨傳宣免，只向階前侍翠華。"]'),
('d3a94ebf-cf08-4ff0-8703-eb3f319e6271','扈從朝獻四首  其四','任希夷','宋','宋诗','song-poetry','','[]','禮官前導赭黄袍，陟降靈宮九陛高。',32,'全唐诗/poet.song.174000.json','["禮官前導赭黄袍，陟降靈宮九陛高。", "二十七筵俱再拜，精虔不憚聖躬勞。"]'),
('9a18ed0b-75d8-4fed-a5fe-1797a28c938b','接盞天興殿','任希夷','宋','宋诗','song-poetry','','[]','遥望黄袍赭色鮮，微臣先已立鈞天。',64,'全唐诗/poet.song.174000.json','["遥望黄袍赭色鮮，微臣先已立鈞天。", "褥旁跪接金杯酒，衣上濃熏寶篆煙。", "閶闔纔囘紅曲蓋，瑣扉亟驟錦鞍韉。", "今晨特爲君王霽，羽仗方停又沛然。"]'),
('190773cc-3a2b-45ea-8b8f-0a27961c9be0','後省紫薇花','任希夷','宋','宋诗','song-poetry','','[]','清曉開軒俯鳳池，小山經雨石增輝。',32,'全唐诗/poet.song.174000.json','["清曉開軒俯鳳池，小山經雨石增輝。", "琉璃葉底珊瑚榦，立出池邊是紫薇。"]'),
('5fcbfe7d-634c-40fd-a17c-3e24332241da','檢院即事','任希夷','宋','宋诗','song-poetry','','[]','禁路風清飛蚤鴉，官卑難望紫宸衙。',32,'全唐诗/poet.song.174000.json','["禁路風清飛蚤鴉，官卑難望紫宸衙。", "了無公事鉤簾坐，一本冬青落細花。"]'),
('f55fb332-838a-4d1e-83e5-a5286c2c8e62','攝鼓院','任希夷','宋','宋诗','song-poetry','','[]','分曹正在壁門東，兼假猶慚兩院通。',64,'全唐诗/poet.song.174000.json','["分曹正在壁門東，兼假猶慚兩院通。", "諫鼓無聲誰訟枉，匭函有疏爲平戎。", "柳分御路曉煙碧，花遶宮牆初日紅。", "退食心閒了無補，西風吹影鬢如蓬。"]'),
('360fd246-dab4-4154-bb58-77a1ae71c083','禮闈奏號畢呈天官侍郎','任希夷','宋','宋诗','song-poetry','','[]','奉詔程文閲四旬，紛來萬卷日橫陳。',64,'全唐诗/poet.song.174000.json','["奉詔程文閲四旬，紛來萬卷日橫陳。", "憐渠燈火勤三歲，惱我簾帷度一春。", "勝日鶑花辜樂事，它年桃李識何人。", "遥知吏部尋春徧，紅紫芳菲得句新。"]'),
('7a644580-fae6-48f4-9203-dc6f95cb3c17','太乙宮迎駕','任希夷','宋','宋诗','song-poetry','','[]','侵夕猶煩雨灑塵，鑾輿纔御霽光分。',64,'全唐诗/poet.song.174000.json','["侵夕猶煩雨灑塵，鑾輿纔御霽光分。", "龍顔喜動雙黄繖，花帽裝成五采雲。", "清蹕一聲天下喜，簫韶九奏世閒聞。", "侍臣扈從沾天宴，親舉堯觴更一欣。"]'),
('e701b6c7-9a1b-436c-bdfc-64a04bbf3169','聚景園宴集','任希夷','宋','宋诗','song-poetry','','[]','晚排閶闔披雲霧，身躡仙脩遊禁宇。',160,'全唐诗/poet.song.174000.json','["晚排閶闔披雲霧，身躡仙脩遊禁宇。", "始知天上自清涼，不信人閒有炎暑。", "庭前青松笙竽聲，望處紅蕖錦繡雲。", "月卿領客意繾綣，冰盤照坐光繽紛。", "薰堂盡却蒲葵扇，瑶階細展桃枝簟。", "加籩新采波上菱，如珠更剝盤中芡。", "老罷慚無翰墨功，臭味喜入芝蘭叢。", "二妙不偕阿鳳至，四老但許商山同。", "明當入直須隨仗，夕陽未下催歸槳。", "重城街鼓已鼕鼕，舉頭桂魄層霄上。"]'),
('1cacf8e6-4895-4ce1-a97e-439f5ba639f4','宴玉津園江樓七首  其一','任希夷','宋','宋诗','song-poetry','','[]','風靜潮痕減，江空夕照多。',24,'全唐诗/poet.song.174000.json','["風靜潮痕減，江空夕照多。", "星星波上艇，隠隠岸邊莎。"]'),
('3d5d6bee-9b68-4f0c-899e-4051138c7bba','宴玉津園江樓七首  其二','任希夷','宋','宋诗','song-poetry','','["\u897f\u6e56"]','風光連北闕，景物傍西湖。',24,'全唐诗/poet.song.174000.json','["風光連北闕，景物傍西湖。", "禁籞濤江上，茲樓天下無。"]'),
('0643a212-1ff8-4a87-9ca7-0e4041c18eb8','宴玉津園江樓七首  其三','任希夷','宋','宋诗','song-poetry','','[]','虛齋留御榻，小徑近層崖。',24,'全唐诗/poet.song.174000.json','["虛齋留御榻，小徑近層崖。", "再拜觀奎畫，渾疑侍玉階。"]'),
('643fc27f-8c62-4389-bd25-6cc80c422de5','宴玉津園江樓七首  其四','任希夷','宋','宋诗','song-poetry','','[]','參天宮柏翠，布地禁花紅。',24,'全唐诗/poet.song.174000.json','["參天宮柏翠，布地禁花紅。", "臺沼如文囿，規摹有汴風。"]'),
('586a31e8-f0ab-45c5-8dad-fedd316d6983','宴玉津園江樓七首  其五','任希夷','宋','宋诗','song-poetry','','[]','浙江天闕下，波惡祖龍知。',24,'全唐诗/poet.song.174000.json','["浙江天闕下，波惡祖龍知。", "在漢如西渭，於周比右伊。"]'),
('6b5869f3-6dd0-4072-af8f-8f7a1eae1bdd','宴玉津園江樓七首  其六','任希夷','宋','宋诗','song-poetry','','[]','翼翼瞻齋殿，深嚴步苑廊。',24,'全唐诗/poet.song.174000.json','["翼翼瞻齋殿，深嚴步苑廊。", "三人俱漢傑，一老玷周行。"]'),
('dba837f3-c483-4a29-9b54-4f41188b756a','宴玉津園江樓七首  其七','任希夷','宋','宋诗','song-poetry','','[]','柳花馳道雪，櫻子上林紅。',24,'全唐诗/poet.song.174000.json','["柳花馳道雪，櫻子上林紅。", "留得青春住，從教白髮翁。"]'),
('18eb3e45-3518-451b-9f64-5bf790535441','遊水樂洞詩','任希夷','宋','宋诗','song-poetry','','[]','萬舞列帝所，九韶奏虞庭。',144,'全唐诗/poet.song.174000.json','["萬舞列帝所，九韶奏虞庭。", "羣公日拱北，星斗光熒熒。", "茲辰適休沐，聯騎來郊坰。", "愛此一泓玉，中有太古聲。", "細響叶宮祉，大音希咸莖。", "自然天籟鳴，獨許幽耳聽。", "鎮以潛虬靈，衛以石獸獰。", "佳哉樂茲遊，驩言舉彼觥。", "誰歟昔經始，今已歸明廷。", "巨麗所未覩，幻眇真難名。", "健筆哦五字，當代推善鳴。", "清幽極模寫，細讀令人醒。"]'),
('28942555-015e-46c6-aa11-c07142c8e39b','贈卜者丁生','任希夷','宋','宋诗','song-poetry','','[]','誰識遼東丁令威，眼看世事熟興衰。',32,'全唐诗/poet.song.174000.json','["誰識遼東丁令威，眼看世事熟興衰。", "百年判我天休問，一笑相逢酒共持。"]'),
('6bb3f5b6-b13a-4923-81f2-e2de9740c346','植芙蓉有懷','任希夷','宋','宋诗','song-poetry','','[]','爲愛秋花霜後紅，故栽千樹待西風。',32,'全唐诗/poet.song.174000.json','["爲愛秋花霜後紅，故栽千樹待西風。", "却思少日拊頭語，淚落花前鬢影髼。"]'),
('5ca2f7af-438d-4dda-94fd-ed5e50fa033e','讀壬子以前詩','任希夷','宋','宋诗','song-poetry','','[]','一覽欲銷憂，萬感紛如昨。',36,'全唐诗/poet.song.174000.json','["一覽欲銷憂，萬感紛如昨。", "蘭萱新去叢，棠□無留萼。", "哀哉誰與言，淚雨九河落。"]'),
('20f68ca2-cbfa-42c0-ac58-bcafabe31588','謝和崇陽舊詩','任希夷','宋','宋诗','song-poetry','','[]','若效飛鳬客，多慚擊劍仙。',48,'全唐诗/poet.song.174000.json','["若效飛鳬客，多慚擊劍仙。", "閑吟五字句，近得故人編。", "方愧雷門鼓，俄揮草聖煙。", "侍郎詩思敏，百斛似泉淵。"]'),
('625da1c3-f6b0-4231-b096-a1caf1b78651','遊陶仙觀林公辨詩  其一','任希夷','宋','宋诗','song-poetry','','[]','偶來殊恨酒尊空，只有青山對禿翁。',32,'全唐诗/poet.song.174000.json','["偶來殊恨酒尊空，只有青山對禿翁。", "細把故人詩卷讀，却疑談笑在閩中。"]'),
('e2bfac33-f0a8-4eb5-92ee-2f04675efc18','遊陶仙觀林公辨詩  其二','任希夷','宋','宋诗','song-poetry','','[]','木落風高八月天，山荒屋老意蕭然。',32,'全唐诗/poet.song.174000.json','["木落風高八月天，山荒屋老意蕭然。", "道人香火但灰冷，何處如今更有仙。"]'),
('15b56ac3-83ae-401c-8e65-0dd01a96a090','毛詩','任希夷','宋','宋诗','song-poetry','','[]','三百詩刪麟筆前，周家積累瓞綿綿。',32,'全唐诗/poet.song.174000.json','["三百詩刪麟筆前，周家積累瓞綿綿。", "須知正始基王化，只在關雎第一篇。"]'),
('19a2de0a-15a3-4e12-9e00-44b07f7a5c6b','觀連江林宰詩卷有懷趙紫芝','任希夷','宋','宋诗','song-poetry','','[]','小小吟哦不足云，更憐蛙蚓漫紛紛。',32,'全唐诗/poet.song.174000.json','["小小吟哦不足云，更憐蛙蚓漫紛紛。", "紫芝一去齋房後，誰憶青山空白雲。"]'),
('b8c6a76b-5b70-46fc-812c-0e0c8ba7fc3a','與毛茶幹趙司法遊東湖四首  其一','任希夷','宋','宋诗','song-poetry','','[]','野迥塵襟豁，湖平望眼寬。',48,'全唐诗/poet.song.174000.json','["野迥塵襟豁，湖平望眼寬。", "山蹊新雪潤，木葉半霜乾。", "歲晚成三友，清遊集四難。", "樂哉忘爾汝，臭味本芝蘭。"]'),
('34dc5328-4fc4-43ed-863a-cd5ed71aa695','與毛茶幹趙司法遊東湖四首  其二','任希夷','宋','宋诗','song-poetry','','[]','湖曉冰澌結，江寒煙靄收。',48,'全唐诗/poet.song.174000.json','["湖曉冰澌結，江寒煙靄收。", "喜陪謝公屐，疑共李膺舟。", "醉袖翩翩舉，詞源衮衮流。", "興酣思夜獵，不用設罝罘。"]'),
('92009037-3292-4160-bf69-c76ec73a45de','與毛茶幹趙司法遊東湖四首  其三','任希夷','宋','宋诗','song-poetry','','[]','才雋真龍種，官閑似馬曹。',48,'全唐诗/poet.song.174000.json','["才雋真龍種，官閑似馬曹。", "班揚趨後勝，李杜漫殘膏。", "阿閣宜巢鳳，詞林合跨鼇。", "未應久留滯，湖海只詩豪。"]'),
('2058fa21-f0c8-4466-b07b-703733bdaf8b','與毛茶幹趙司法遊東湖四首  其四','任希夷','宋','宋诗','song-poetry','','[]','穎出三十客，今趨萬里程。',48,'全唐诗/poet.song.174000.json','["穎出三十客，今趨萬里程。", "才高官未稱，詞與筆俱精。", "珠玉忘形穢，江山共眼明。", "莫嫌巴蜀遠，揚馬各文鳴。"]'),
('979d3dfc-012e-42a6-a115-848b9516c434','中澣西湖之集斯遠有詩輒奉同遊一笑','任希夷','宋','宋诗','song-poetry','','["\u897f\u6e56"]','志士不厭朝市喧，幽人終愛山林靜。',160,'全唐诗/poet.song.174000.json','["志士不厭朝市喧，幽人終愛山林靜。", "一生遑遑爲斗食，匪石有懷徒烱烱。", "今朝結客來西湖，翛然會心塵慮屏。", "珠宮貝闕同天遊，閬風玄圃非人境。", "留連山色即傳觴，眷戀柳陰還繫艇。", "諸公湖海氣不除，萬里昂昂羽毛整。", "豈但笑語同娛嬉，正須樂石相箴警。", "東坡仙去今幾時，寥落風煙誰與領。", "浪言夏日如許長，樂哉未央等俄頃。", "不堪歸騎催入關，清夢猶應在雲嶺。"]'),
('a8952501-8e01-4b1c-9d2c-07c321b70c83','湖口縣齋即事','任希夷','宋','宋诗','song-poetry','','[]','門直九江水，人閑五柳家。',48,'全唐诗/poet.song.174000.json','["門直九江水，人閑五柳家。", "曉看沙上霧，暮對淮南霞。", "几席墮山影，軒窗臨浪花。", "悠悠寄食客，坐愁霜鬢華。"]'),
('28831eb9-a46a-499e-a772-015555acef17','仲一弟梅花一絕併簡丘玉父','任希夷','宋','宋诗','song-poetry','','[]','粲粲霜林白玉圍，誰將紅糝亂青枝。',32,'全唐诗/poet.song.174000.json','["粲粲霜林白玉圍，誰將紅糝亂青枝。", "天憐粉面太孤絕，故遣施朱出一奇。"]'),
('f3d77db9-0d84-4789-bcc5-f5c4c4e1bfe5','綠萼梅二首  其一','任希夷','宋','宋诗','song-poetry','','[]','綠趺黄蕊襯瑶華，霜雪林中自一家。',32,'全唐诗/poet.song.174000.json','["綠趺黄蕊襯瑶華，霜雪林中自一家。", "最好月寒迷粉素，翠鈿依約獨橫斜。"]'),
('9f247cbb-e45c-470c-84b9-5b81c843ab27','綠萼梅二首  其二','任希夷','宋','宋诗','song-poetry','','[]','萼綠華堂艮岳東，梅花萬數繞離宮。',32,'全唐诗/poet.song.174000.json','["萼綠華堂艮岳東，梅花萬數繞離宮。", "宣和舊事無人記，粉面含淒向朔風。"]'),
('7d70f5e3-8e86-47ca-ac76-a0ff23a52cb3','題藍道人畫梅詩軸  其一','任希夷','宋','宋诗','song-poetry','','[]','湖海知君歲月多，欲尋笙鶴問烟蘿。',32,'全唐诗/poet.song.174000.json','["湖海知君歲月多，欲尋笙鶴問烟蘿。", "相逢一笑江南陌，聽徹絲桐聽踏歌。"]'),
('3b194ff5-68e4-4d8e-a742-b9d2ab443c99','題藍道人畫梅詩軸  其二','任希夷','宋','宋诗','song-poetry','','[]','我家樵水東邊住，手種寒梢一萬栽。',32,'全唐诗/poet.song.174000.json','["我家樵水東邊住，手種寒梢一萬栽。", "客路十年清夢斷，誰將疏影巷中來。"]'),
('29c3dc83-ba8c-4de1-ac51-d2ff57de8772','人間','任希夷','宋','宋诗','song-poetry','','[]','人間無處著東風，萬紫千紅掃地空。',32,'全唐诗/poet.song.174000.json','["人間無處著東風，萬紫千紅掃地空。", "寂寞園林晴日永，柳花零落綠蔭中。"]'),
('84582b90-a408-42cc-8b7a-505879bb3e88','重五日出都門詩','任希夷','宋','宋诗','song-poetry','','[]','客路逢重五，吾年已半百。',120,'全唐诗/poet.song.174000.json','["客路逢重五，吾年已半百。", "顔羞綵縷紅，鬢與香蒲白。", "功名來何時，歲月等虛擲。", "常於沐芳辰，每念懷沙客。", "今年拜天恩，列邸綴朝蹟。", "趨班猶須時，俶載且行役。", "徊徨金閨辭，咫尺青門隔。", "短棹泛濤江，清觴懽祖席。", "後期邈歲年，賓言在朝夕。", "將扶鶴髮來，須徐幸毋迫。"]'),
('73b2f242-08ad-401e-a991-bacf8eaa97df','重五出都門後一日效樂府作','任希夷','宋','宋诗','song-poetry','','[]','滄江麗晴暉，揚鈴出王畿。',72,'全唐诗/poet.song.174000.json','["滄江麗晴暉，揚鈴出王畿。", "雙闕望中遠，片帆波上飛。", "殷雷車馬隔，遏雲歌吹希。", "歸東水浩浩，拱北心依依。", "難云周行寘，猶恨天顔違。", "年華易婉晚，何日當旋歸。"]'),
('d867eca2-e84e-45ba-b825-04a1624d37f5','盤沙行','任希夷','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u94b1\u5858\u6c5f"]','錢塘江狹沙成路，潮水來時人欲渡。',163,'全唐诗/poet.song.174000.json','["錢塘江狹沙成路，潮水來時人欲渡。", "沙隨浪沒未容知，人恐潮迴且爭去。", "倉皇競同蜂螘奔，只尺直恐蛟鼉怒。", "狂風一作浪如屋，可憐有時迫昏暮。", "長江渺渺前無航，平沙茫茫絕歸處。", "幾人到此不復反，海水西來更東注。", "君不見祖龍英雄吞九州，臨此江波尚懷懼。", "濟川舟楫果何人，莫說稻穰與芒履。", "龐公今爲鹿門行，將歸更作盤沙賦。", "我衰絕望釣連鼇，三復君詩返予步。"]'),
('48e38e53-13d4-40cc-99b3-992952de211c','野花','任希夷','宋','宋诗','song-poetry','','[]','野徑風來陣陣香，名花未省植何方。',32,'全唐诗/poet.song.174000.json','["野徑風來陣陣香，名花未省植何方。", "却思一卉何能爾，應是春原集衆芳。"]'),
('f005fd8a-d8d7-4174-a480-0327f012c9fb','寶鍾院','任希夷','宋','宋诗','song-poetry','','[]','九江淵輪彭蠡東，江濆上下懸石鍾。',192,'全唐诗/poet.song.174000.json','["九江淵輪彭蠡東，江濆上下懸石鍾。", "洪爐大冶見奇怪，千仞硉矹雲濤衝。", "旁羅簨虡萬石從，側立跂行勢飛動。", "螭蟠蛇結增層崖，神剜鬼劃森幽洞。", "有如萬鈞陳未央，猛獸怒翅將騰驤。", "豈同九耳豐山上，欲鳴猶待天雨霜。", "南音函胡北清越，未許人人盡幽絕。", "小聲鏜鞳大噌𠴈，留與坡仙汎明月。", "長風巨浪相吐吞，金鏞自奏天然聲。", "非雷非霆中清濁，龍淵蛟窟驚鏗鍧。", "獻子歌鍾景無射，千載寥寥聲寂寂。", "此石長留天地間，海若馮夷能拊擊。"]'),
('a7e25778-809f-4a3a-8cc1-6abffb131139','遺安堂','任希夷','宋','宋诗','song-poetry','','[]','苴茅動龔勝，屠晝恐王蠋。',192,'全唐诗/poet.song.174000.json','["苴茅動龔勝，屠晝恐王蠋。", "二君夭天年，千載歎莫贖。", "今代史伯存，危行光往躅。", "繄昔開禧年，狂童叛吾蜀。", "非招詎肯往，全身不受辱。", "平林萃羣鴞，高飛獨黄鵠。", "屹如中流柱，烱若崑山玉。", "元氣頼以存，餘風厲頹俗。", "平生慕龐公，以安貽嗣續。", "豈爲萬鍾加，居然一丘足。", "晚山雲自歸，春風草還綠。", "代謝紛吾前，靈臺獨無欲。", "一從身落南，先廬蜀江曲。", "中間亂離瘼，幾人惠文觸。", "爛額皆論功，考槃終不告。", "臨風一長謠，白駒在空谷。"]'),
('2a9d64bc-2c30-4a06-9f82-740dc310b3ee','付二郎','任希夷','宋','宋诗','song-poetry','','[]','望前一日正芳春，我祖當年慶誕辰。',32,'全唐诗/poet.song.174000.json','["望前一日正芳春，我祖當年慶誕辰。", "奕葉有孫同此日，吾門他日寵光新。"]'),
('5f41953e-8a13-45f1-aad4-8615dc5f817c','聞櫓聲','任希夷','宋','宋诗','song-poetry','','[]','屢督篙師趁月明，忽忽燈火過臨平。',32,'全唐诗/poet.song.174000.json','["屢督篙師趁月明，忽忽燈火過臨平。", "兼程不敢稽王事，坐聽鄰舟伊軋聲。"]'),
('4e2ea978-dbb0-4211-93a7-5332516d56d3','五日東宮賜酒肴','任希夷','宋','宋诗','song-poetry','','[]','重來六泛菖蒲酒，儲禁黄封歲歲攽。',32,'全唐诗/poet.song.174000.json','["重來六泛菖蒲酒，儲禁黄封歲歲攽。", "遥想三宮天上宴，肯分餘瀝到人間。"]'),
('8ad583c1-f7bf-4fa0-ae61-d3acf436e93b','題義亭鋪','任希夷','宋','宋诗','song-poetry','','[]','昨侍吾翁一再經，眼中歷歷短長亭。',32,'全唐诗/poet.song.174000.json','["昨侍吾翁一再經，眼中歷歷短長亭。", "五年人事隨陵谷，今夕重來淚雨零。"]'),
('8ae2c2cd-387f-48b1-8ece-b9d4d35ae7fa','假面鋪','任希夷','宋','宋诗','song-poetry','','[]','聖朝久變文身俗，四海誰非革面人。',32,'全唐诗/poet.song.174000.json','["聖朝久變文身俗，四海誰非革面人。", "此地胡爲名未改，猶勝酬僞必言真。"]'),
('44aba76b-5b06-423e-b1a7-2bea74954a27','壽丞相  其一','任希夷','宋','宋诗','song-poetry','','[]','春到三旬物物鮮，桃花如錦柳如綿。',32,'全唐诗/poet.song.174000.json','["春到三旬物物鮮，桃花如錦柳如綿。", "千春樂事生中旦，長占中和一日前。"]'),
('ad480ef9-a19e-4897-9359-24c0bb23a555','壽丞相  其二','任希夷','宋','宋诗','song-poetry','','[]','何許生賢踵世官，十洲風物四明山。',32,'全唐诗/poet.song.174000.json','["何許生賢踵世官，十洲風物四明山。", "股肱光輔唐虞際，衮繡親傳父子間。"]'),
('70114586-3d38-4b8b-b93e-a3aa01aa8f99','壽丞相  其三','任希夷','宋','宋诗','song-poetry','','[]','秉軸持衡歲五周，從今千載國同休。',32,'全唐诗/poet.song.174000.json','["秉軸持衡歲五周，從今千載國同休。", "汾陽謾校中書考，安得如公尚黑頭。"]'),
('7395817c-bd66-4a2c-b5c3-47d439a3ce0f','書故三司副使陳公詩軸後','任希夷','宋','宋诗','song-poetry','','[]','如彼泉流必有源，陳家詩律自專門。',32,'全唐诗/poet.song.174000.json','["如彼泉流必有源，陳家詩律自專門。", "后山得法因鹽鐵，不減唐朝杜審言。"]'),
('9c1bf9c2-54ca-4d9c-a72b-879169b8a8ce','句  其一','任希夷','宋','宋诗','song-poetry','','[]','綠柳陰中獅子巷，白蘋亭畔駱駝橋。',16,'全唐诗/poet.song.174000.json','["綠柳陰中獅子巷，白蘋亭畔駱駝橋。"]'),
('db0f5c3d-2169-400c-93d5-10dc68b0c101','句  其二','任希夷','宋','宋诗','song-poetry','','[]','二三疏竹夏無暑，一兩殘僧晝掩門。',16,'全唐诗/poet.song.174000.json','["二三疏竹夏無暑，一兩殘僧晝掩門。"]'),
('8a22cedc-edea-4e4f-bb38-ff3b84abbd92','偈頌二十五首  其一','釋普巖','宋','宋诗','song-poetry','','[]','豁開戶牖，直出直入。',22,'全唐诗/poet.song.174000.json','["豁開戶牖，直出直入。", "鮎魚上竹竿，俊鶻趁不及。"]'),
('46a5c05b-5aee-460e-a47b-b3e9f3411539','偈頌二十五首  其二','釋普巖','宋','宋诗','song-poetry','','[]','出現楊州，坐斷壽丘。',30,'全唐诗/poet.song.174000.json','["出現楊州，坐斷壽丘。", "脚跟不點地，贏得一身愁，不是冤家不聚頭。"]'),
('00f20bbc-fb3f-471e-a24b-99d93f19d0df','偈頌二十五首  其三','釋普巖','宋','宋诗','song-poetry','','[]','日面月面，霹靂閃電。',20,'全唐诗/poet.song.174000.json','["日面月面，霹靂閃電。", "直下來也，急著眼看。"]'),
('46abc4a2-f950-4f24-8b07-bccaee0d7ac3','偈頌二十五首  其四','釋普巖','宋','宋诗','song-poetry','','[]','馬頭回，牛頭沒。',20,'全唐诗/poet.song.174000.json','["馬頭回，牛頭沒。", "一字入公門，九牛曳不出。"]'),
('481f2207-291a-4e29-853f-7e32fd96d949','偈頌二十五首  其五','釋普巖','宋','宋诗','song-poetry','','[]','箇樣皮毛，千化萬變。',30,'全唐诗/poet.song.174000.json','["箇樣皮毛，千化萬變。", "黄梅鷲頭，謾自流傳。", "後代兒孫，可貴可賤。"]'),
('a498f398-9e07-464f-ab01-f4dbe15e9eaa','偈頌二十五首  其六','釋普巖','宋','宋诗','song-poetry','','[]','坐而不住，住而不坐。',20,'全唐诗/poet.song.174000.json','["坐而不住，住而不坐。", "滴水生冰，因風吹火。"]'),
('532d8f35-2bcf-494d-8927-ab871eec9b42','偈頌二十五首  其七','釋普巖','宋','宋诗','song-poetry','','[]','此香堪笑又堪悲，剛把愁腸說向誰。',32,'全唐诗/poet.song.174000.json','["此香堪笑又堪悲，剛把愁腸說向誰。", "冶父山前曾落節，千鈞之重一毫釐。"]'),
('e958af60-93b8-41f0-8b3d-2f35bf6d0ece','偈頌二十五首  其八','釋普巖','宋','宋诗','song-poetry','','[]','離四句，絕百非。',44,'全唐诗/poet.song.174000.json','["離四句，絕百非。", "清寥寥，白滴滴。", "直透萬重關，不住青霄外。", "千手大悲提不起，爍迦羅眼莫能窺。"]'),
('3c3a0678-20ba-4d0c-a8eb-34103a6376a4','偈頌二十五首  其九','釋普巖','宋','宋诗','song-poetry','','[]','風雲合匝，龍虎交馳。',46,'全唐诗/poet.song.174000.json','["風雲合匝，龍虎交馳。", "一進一退，各適其宜。", "叢林烜赫，慧命流輝。", "壽丘面皮厚多少，惟許通方作者知。"]'),
('fdd5d534-056b-431c-bbc7-f065d1ce4dae','偈頌二十五首  其一○','釋普巖','宋','宋诗','song-poetry','','[]','入院數日來，人事閙鬨鬨。',24,'全唐诗/poet.song.174000.json','["入院數日來，人事閙鬨鬨。", "兩脚走如烟，眼不見鼻孔。"]'),
('ec4345a5-489c-4caf-b098-692fe8b8bfa8','偈頌二十五首  其一一','釋普巖','宋','宋诗','song-poetry','','[]','歸來出去，迦葉貧，阿難富。',48,'全唐诗/poet.song.174000.json','["歸來出去，迦葉貧，阿難富。", "出去歸來，南天台，北五臺。", "目前包裹，滿面塵埃。", "禹力不到處，河聲流向西。"]'),
('26b21909-58f4-479a-b564-6aa4aad96540','偈頌二十五首  其一二','釋普巖','宋','宋诗','song-poetry','','[]','近之不遜，遠之則怨。',36,'全唐诗/poet.song.174000.json','["近之不遜，遠之則怨。", "無義無情，可貴可賤。", "一年一度雪深冤，畢竟無人是的傳。"]'),
('fd5502fc-2827-4ce5-aa7a-fed7ade8b932','偈頌二十五首  其一三','釋普巖','宋','宋诗','song-poetry','','[]','故人方外來，相見便相悉。',54,'全唐诗/poet.song.174000.json','["故人方外來，相見便相悉。", "倒指三十年，道義同一日。", "鐵壁銀山，十分狼藉。", "直得同聲相應，同氣相求，西河師子在汾州。"]'),
('bdffddaa-b423-4900-8be5-efa3faea2518','偈頌二十五首  其一四','釋普巖','宋','宋诗','song-poetry','','[]','毒攻毒，楔出楔。',25,'全唐诗/poet.song.174000.json','["毒攻毒，楔出楔。", "老曹山，不識別。", "那裏是者僧喫酒處。"]'),
('8a286afe-48c2-48f2-a697-e180a100f2b8','偈頌二十五首  其一五','釋普巖','宋','宋诗','song-poetry','','[]','令不虛行，箭不虛發。',20,'全唐诗/poet.song.174000.json','["令不虛行，箭不虛發。", "儻或躊躇，二九十八。"]'),
('b1745bc9-8991-443a-a63a-dbea97bbf007','偈頌二十五首  其一六','釋普巖','宋','宋诗','song-poetry','','[]','洞門無鑰，劍閣崔嵬。',48,'全唐诗/poet.song.174000.json','["洞門無鑰，劍閣崔嵬。", "風露高寒，且非人世。", "是則是，天上人間知幾幾。", "者僧一問不將來，黄蘗通身是泥水。"]'),
('ddede80c-7732-436b-b1e1-f71317996e37','偈頌二十五首  其一七','釋普巖','宋','宋诗','song-poetry','','[]','一陽生也，樹頭驚起雙雙魚，石上迸出長長筍。',54,'全唐诗/poet.song.174000.json','["一陽生也，樹頭驚起雙雙魚，石上迸出長長筍。", "即日伏惟兩序，高人現前清衆。", "履茲長至，倍膺戩穀。", "喝一喝，俗氣未除。"]'),
('4efe3fbb-2832-4823-89ac-4b88bafe4de1','偈頌二十五首  其一八','釋普巖','宋','宋诗','song-poetry','','[]','季春漸暄，鳥啼花笑。',23,'全唐诗/poet.song.174000.json','["季春漸暄，鳥啼花笑。", "恒沙數見聞覺知，悉皆了了。"]'),
('99dcb0f7-a578-4ee9-af99-c641eb455e5d','偈頌二十五首  其一九','釋普巖','宋','宋诗','song-poetry','','[]','一葉落，天下秋。',44,'全唐诗/poet.song.174000.json','["一葉落，天下秋。", "一塵起，大地收。", "臨濟掌黄蘗，南泉喚趙州。", "開口不在舌頭上，夜濤催發海南舟。"]'),
('a4e26c93-6df9-48c2-b4be-fd6059e81cf4','偈頌二十五首  其二○','釋普巖','宋','宋诗','song-poetry','','[]','顯慈鼻祖，諾庵法兄。',48,'全唐诗/poet.song.174000.json','["顯慈鼻祖，諾庵法兄。", "機如電掣，辯似河傾。", "無心相撞著，分外得人憎。", "彼此不堪爲種草，先師之道轉竛竮。"]'),
('54db2a7f-82cb-41e4-936c-4a53207a0a7f','偈頌二十五首  其二一','釋普巖','宋','宋诗','song-poetry','','[]','斷楊歧正脈，壞臨濟綱宗。',64,'全唐诗/poet.song.174000.json','["斷楊歧正脈，壞臨濟綱宗。", "赤土塗牛奶，密室不通風。", "身前身後不了，深瘞白雲之中。", "非父非子，狹路相逢。", "澗藻溪蘋相鈍置，謝郎錯認釣魚船。"]'),
('92b249d8-b1cc-4adf-ae06-17d7965b3e52','偈頌二十五首  其二二','釋普巖','宋','宋诗','song-poetry','','[]','老訥今朝死，老巖今日生。',50,'全唐诗/poet.song.174000.json','["老訥今朝死，老巖今日生。", "二俱無伎倆，有夢不同牀。", "夤緣繼踵，香火荒凉。", "肝腸鐵作也須裂，驪屎如何比麝香。"]'),
('871a2394-5f74-4f0f-ada7-c6297bdfecb6','偈頌二十五首  其二三','釋普巖','宋','宋诗','song-poetry','','[]','老洞山玷辱宗風，泰首座埋沒自己。',30,'全唐诗/poet.song.174000.json','["老洞山玷辱宗風，泰首座埋沒自己。", "雙雙繡出鴛鴦，千古扶持不起。"]'),
('f57ab4c6-3529-4dbc-bc4e-0c8717af3128','偈頌二十五首  其二四','釋普巖','宋','宋诗','song-poetry','','[]','四年承乏雲峰寺，暗寫秋腸寄阿誰。',74,'全唐诗/poet.song.174000.json','["四年承乏雲峰寺，暗寫秋腸寄阿誰。", "每到十一月初五，一狐疑了一狐疑。", "故我開山伏虎禪師，指柳駡楊，傷龜恕鼈，你死我活。", "莫說一碗粗茶一炷香，也勝和盲㪍訴瞎。"]'),
('d91dfa28-d364-4879-b591-7b19f4276ea4','偈頌二十五首  其二五','釋普巖','宋','宋诗','song-poetry','','[]','項短耳聵，千妖百怪。',42,'全唐诗/poet.song.174000.json','["項短耳聵，千妖百怪。", "如是三十年，續東山正脈。", "我也錯商量，三拜一爐香，一任傍人說短長。"]'),
('5628dcb3-1891-4a76-afc3-5c3de73b98ea','觀音大士贊','釋普巖','宋','宋诗','song-poetry','','[]','草木丘陵，風雷雲氣。',30,'全唐诗/poet.song.174000.json','["草木丘陵，風雷雲氣。", "具足妙相尊，證入三摩地。", "萬象森羅從鼎沸。"]'),
('4421cb8b-1c38-4e51-877d-20c44e93ecf1','達磨大師贊','釋普巖','宋','宋诗','song-poetry','','[]','葦航身險，風急水寒。',39,'全唐诗/poet.song.174000.json','["葦航身險，風急水寒。", "九年面壁，用盡心肝。", "大唐人不識隻履過西天，單傳直指待馿年。"]'),
('7f5bcb52-45c2-4a94-9fa4-07954bd54c0c','百丈大師贊','釋普巖','宋','宋诗','song-poetry','','[]','親見馬簸箕，面目甚奇怪。',40,'全唐诗/poet.song.174000.json','["親見馬簸箕，面目甚奇怪。", "鼻痛野鴨飛，漆桶好不快。", "只見祥麟一角尖，定知罪犯彌天大。"]'),
('6101ab2c-168c-4f99-9bf3-b484b76fe96c','布袋和尚贊','釋普巖','宋','宋诗','song-poetry','','[]','山月未出，海雲忽飄。',36,'全唐诗/poet.song.174000.json','["山月未出，海雲忽飄。", "瞑目而坐，歸路迢迢。", "布袋裏頭無長物，許誰胡蝶夢溪橋。"]'),
('2b27757e-9efb-423a-aa76-1993b9f68c8e','濟顛書記贊','釋普巖','宋','宋诗','song-poetry','','[]','毀不得，贊不得，天台出得箇般僧，一似青天轟霹靂。',82,'全唐诗/poet.song.174000.json','["毀不得，贊不得，天台出得箇般僧，一似青天轟霹靂。", "走京城，無處覓。", "業識忙忙，風流則劇。", "末後筋斗背翻，煅出水連天碧。", "稽首濟顛，不識不識。", "狹路相逢捻鼻頭，也是普州人送賊。"]'),
('5cd8cece-9931-4d54-b380-2bf3088c0939','頌古十首  其一','釋普巖','宋','宋诗','song-poetry','','[]','自謂五更侵早起，誰知更有夜行人。',32,'全唐诗/poet.song.174000.json','["自謂五更侵早起，誰知更有夜行人。", "條風塊雨今非昔，堯舜垂衣萬國賓。"]'),
('d0417573-b6ff-415f-8f59-51418de8619e','頌古十首  其二','釋普巖','宋','宋诗','song-poetry','','[]','擡頭霹靂不容追，缺齒胡僧陷鐵圍。',32,'全唐诗/poet.song.174000.json','["擡頭霹靂不容追，缺齒胡僧陷鐵圍。", "六合空空風悄悄，杜鵑啼月不如歸。"]'),
('58727556-ec74-4597-9250-ced013ad7a85','頌古十首  其三','釋普巖','宋','宋诗','song-poetry','','[]','月淡江空泛小舟，唱歌和月看江流。',32,'全唐诗/poet.song.174000.json','["月淡江空泛小舟，唱歌和月看江流。", "更深欹枕夢何處，兩峰清霜曉未收。"]'),
('d6dd38b0-8d4e-4bec-ac7d-fae8a5ebd2ec','頌古十首  其四','釋普巖','宋','宋诗','song-poetry','','[]','鐵壁銀山幾萬重，有無之字若爲通。',32,'全唐诗/poet.song.174000.json','["鐵壁銀山幾萬重，有無之字若爲通。", "斬關豈在搴旗手，枉有虛名落漢中。"]'),
('1b60c32f-b097-47cf-afa6-63bc974bd2cd','頌古十首  其五','釋普巖','宋','宋诗','song-poetry','','[]','洗鉢家家事一同，新羅不在海門東。',32,'全唐诗/poet.song.174000.json','["洗鉢家家事一同，新羅不在海門東。", "因行掉臂趙州老，身在烟蘿第幾重。"]'),
('4792e607-556d-45c3-a258-379bb8cf5d61','頌古十首  其六','釋普巖','宋','宋诗','song-poetry','','[]','搽抔抹粉沒人猜，五百生中與麽來。',32,'全唐诗/poet.song.174000.json','["搽抔抹粉沒人猜，五百生中與麽來。", "覿體風流有多少，不知何處可安排。"]'),
('a2d7d455-261c-4dd9-bf4a-6cecdebc0c08','頌古十首  其七','釋普巖','宋','宋诗','song-poetry','','[]','百骸一物貞薰天，風起今朝病一般。',32,'全唐诗/poet.song.174000.json','["百骸一物貞薰天，風起今朝病一般。", "酷恨雙雙醫不得，枕邊空聽鴈聲寒。"]'),
('66c596b3-f196-4122-9021-99889030404c','頌古十首  其八','釋普巖','宋','宋诗','song-poetry','','[]','等閑提起七斤衫，多少禪和著意參。',32,'全唐诗/poet.song.174000.json','["等閑提起七斤衫，多少禪和著意參。", "盡向青州做窠窟，不知春色在江南。"]'),
('8cf0aafd-6056-469b-b303-81f988380210','頌古十首  其九','釋普巖','宋','宋诗','song-poetry','','[]','洗腸換骨老芭蕉，拄杖拈來價轉高。',32,'全唐诗/poet.song.174000.json','["洗腸換骨老芭蕉，拄杖拈來價轉高。", "賣與買人人不買，翻令平地起波濤。"]'),
('f85de5ab-0618-4b00-b1d7-68fb0e1975fa','頌古十首  其一○','釋普巖','宋','宋诗','song-poetry','','[]','如是如何正法眼，驀然突出破沙盆。',32,'全唐诗/poet.song.174000.json','["如是如何正法眼，驀然突出破沙盆。", "依稀渭北春天樹，彷彿江東日暮雲。"]'),
('7e500920-668c-4c41-b3c4-67935b11d89d','大義渡','釋普巖','宋','宋诗','song-poetry','','[]','孩兒不見棄渾身，可惜婆婆眼不親。',32,'全唐诗/poet.song.174000.json','["孩兒不見棄渾身，可惜婆婆眼不親。", "白浪洪波無了日，至今愁殺渡頭人。"]'),
('cd2c16f2-9419-46a0-83cc-3be6d9dc5aa2','大藏主號鏡中','釋普巖','宋','宋诗','song-poetry','','[]','孤光不墮有無間，碧落衝開萬象寒。',32,'全唐诗/poet.song.174000.json','["孤光不墮有無間，碧落衝開萬象寒。", "撲破果然亡朕跡，從教大地黑漫漫。"]'),
('e57a0c03-f0d1-4010-866d-b5324cdc0e42','寄天目禮書記閩回','釋普巖','宋','宋诗','song-poetry','','[]','爪牙消息露三山，勘破曾郎想不難。',32,'全唐诗/poet.song.174000.json','["爪牙消息露三山，勘破曾郎想不難。", "一嘯歸來千嶂曉，於菟不似舊時斑。"]'),
('20014167-0933-4b74-bfba-f1de6e1d63ff','寄太白幸首座','釋普巖','宋','宋诗','song-poetry','','[]','糞火堆頭潦倒身，且無花鳥閙芳春。',32,'全唐诗/poet.song.174000.json','["糞火堆頭潦倒身，且無花鳥閙芳春。", "口邊白醭心如鐵，甘作叢林不義人。"]'),
('80f9ab60-0537-443b-8975-8b2068356366','題戢菴居士竹亭','釋普巖','宋','宋诗','song-poetry','','[]','疎疎綠葉起清風，屈指巡簷數不窮。',32,'全唐诗/poet.song.174000.json','["疎疎綠葉起清風，屈指巡簷數不窮。", "幽致果然難比況，此君未必在其中。"]'),
('6c2b0155-fcfc-41da-96a3-18d7f13582cf','送僧見孟侍郎','釋普巖','宋','宋诗','song-poetry','','[]','三秋月冷半山雲，來謁維摩必有因。',32,'全唐诗/poet.song.174000.json','["三秋月冷半山雲，來謁維摩必有因。", "特見嶺梅開一朶，也應知道不干春。"]'),
('551dad94-461b-4319-9e67-3c3e15c69da9','乘禪者歸蜀','釋普巖','宋','宋诗','song-poetry','','[]','出劍門兮入劍門，眼空寰宇一閑身。',32,'全唐诗/poet.song.174000.json','["出劍門兮入劍門，眼空寰宇一閑身。", "杖挑一滴江南水，散作西川劫外春。"]'),
('23985ef6-e67b-4490-acca-40f8a66e3bca','送洪維那','釋普巖','宋','宋诗','song-poetry','','[]','笑把虛空一口吞，髑髏瞥轉振乾坤。',32,'全唐诗/poet.song.174000.json','["笑把虛空一口吞，髑髏瞥轉振乾坤。", "破沙盆有兒孫在，玉笛橫吹出海門。"]'),
('73bbb4e2-e67e-4332-bc66-ee018fcbcd37','自贊','釋普巖','宋','宋诗','song-poetry','','[]','斷楊岐正脈，滅臨濟綱宗。',60,'全唐诗/poet.song.174000.json','["斷楊岐正脈，滅臨濟綱宗。", "猿啼碧嶂，月鎖千峰。", "影落于闐國，人在大遼東。", "應緣淡泊，無分從容。", "謂是運菴真面目，澄潭不許卧蒼龍。"]'),
('e8edbbe1-f574-4302-ad4a-81a6e332f965','又','釋普巖','宋','宋诗','song-poetry','','[]','妙在轉處，密在汝邊。',65,'全唐诗/poet.song.174000.json','["妙在轉處，密在汝邊。", "繪予面目，正中乖偏。", "踏翻却謝郎船。", "不撥萬象，火冷灰寒。", "我有丰子分，誰道不完全。", "十分狼藉難收拾，微風吹動碧琅玕。"]'),
('3c87f507-5505-45c1-bb04-a2f892b5c948','運庵普巖禪師像贊','夢庵在居士','宋','宋诗','song-poetry','','[]','松源嫡嗣，伏虎後身。',36,'全唐诗/poet.song.174000.json','["松源嫡嗣，伏虎後身。", "接物有驗，見地不親。", "叢林沾潤恩波闊，萬古雲峰翠色新。"]'),
('9fc01a0d-6529-41be-b0b6-7493bda6867a','感懷','趙軫','宋','宋诗','song-poetry','','[]','羣鱗戲清波，天青雲影白。',48,'全唐诗/poet.song.174000.json','["羣鱗戲清波，天青雲影白。", "濯足歌滄浪，一笑天地窄。", "山色秀而深，都言秘神物。", "眼底有真龍，何必雲中覓。"]'),
('99d294ea-6403-4454-a235-042f9eb77e2c','登雁門山絕頂','朱慶朝','宋','宋诗','song-poetry','','[]','萬丈仙山望欲寒，白雲中斷出欄干。',32,'全唐诗/poet.song.174000.json','["萬丈仙山望欲寒，白雲中斷出欄干。", "登登忽向峰頭立，好與凡人地上看。"]'),
('703a825d-46ad-468b-95c7-4c2d31d98714','從先生明哲道中呈伯廣炳道','時瀾','宋','宋诗','song-poetry','','[]','燕子楊花各自飛，雨乾溪路綠初肥。',32,'全唐诗/poet.song.174000.json','["燕子楊花各自飛，雨乾溪路綠初肥。", "無人會得風雩意，可是千年瑟竟希。"]'),
('68ca6ff5-94ad-4e04-8527-91275b234b9c','宿莢道驛','時澐','宋','宋诗','song-poetry','','[]','笋輿倦長途，夜投村邸宿。',48,'全唐诗/poet.song.174000.json','["笋輿倦長途，夜投村邸宿。", "市井倚巒岡，人烟半樵牧。", "茅檐俯清流，翠巘出前屋。", "山月照人寒，有意憐幽獨。"]'),
('932a62a3-f7d9-409e-aef3-844f6ea9d921','題竹齋指南詩','李燔','宋','宋诗','song-poetry','','[]','元量清標酷似僧，詩情書意兩相承。',32,'全唐诗/poet.song.174000.json','["元量清標酷似僧，詩情書意兩相承。", "於今自有高人處，不尚空窗尚巽升。"]'),
('dadc6b1a-180d-4563-94d2-254b9c35aa67','蘆江八詠 東橋柳色','羅仲舒','宋','宋诗','song-poetry','','[]','河橋數株柳，偏受東風多。',24,'全唐诗/poet.song.174000.json','["河橋數株柳，偏受東風多。", "柔條慎勿折，生意全天和。"]'),
('6b839c75-4979-4e27-9031-ec4fe56be9fe','蘆江八詠 西浦潮痕','羅仲舒','宋','宋诗','song-poetry','','[]','潮漲復潮退，盈縮痕常存。',24,'全唐诗/poet.song.174000.json','["潮漲復潮退，盈縮痕常存。", "渡口孤舟橫，濟川應有人。"]'),
('7443d3bc-d9eb-47b3-80c5-1454d331722b','蘆江八詠 前野耕雲','羅仲舒','宋','宋诗','song-poetry','','[]','春雨鳴布穀，土膏三月足。',24,'全唐诗/poet.song.174000.json','["春雨鳴布穀，土膏三月足。", "舉趾事深耕，竟畝水雲綠。"]'),
('456d6449-abf1-49af-96cb-a82f28c56636','蘆江八詠 後江釣月','羅仲舒','宋','宋诗','song-poetry','','[]','先將補衮線，綰作釣鼇絲。',24,'全唐诗/poet.song.174000.json','["先將補衮線，綰作釣鼇絲。", "投向蒼江月，經綸小試之。"]'),
('db915462-aef5-4f20-84e2-158448f5ccc5','蘆江八詠 義塾書燈','羅仲舒','宋','宋诗','song-poetry','','[]','夜深展書讀，伊吾聲比屋。',24,'全唐诗/poet.song.174000.json','["夜深展書讀，伊吾聲比屋。", "掩映杖頭光，穿破西園竹。"]'),
('2436bf0d-994c-4f15-9c1e-0e5ac5cc6e97','蘆江八詠 祠堂議禮','羅仲舒','宋','宋诗','song-poetry','','[]','春秋思報本，忠孝原有祠。',24,'全唐诗/poet.song.174000.json','["春秋思報本，忠孝原有祠。", "儀物修孔時，擊鼓吹豳詩。"]'),
('1921cee3-29a1-44aa-a170-a0641aee5c5b','蘆江八詠 蘆山樵唱','羅仲舒','宋','宋诗','song-poetry','','[]','秋山草木落，樵夫日相尋。',24,'全唐诗/poet.song.174000.json','["秋山草木落，樵夫日相尋。", "幽歌出空谷，金石有餘音。"]'),
('8bca1112-b74a-4e8f-808e-06d3d6285608','蘆江八詠 竹林梵鐘','羅仲舒','宋','宋诗','song-poetry','','[]','晨昏禮法供，擊鼓齊七衆。',24,'全唐诗/poet.song.174000.json','["晨昏禮法供，擊鼓齊七衆。", "堪笑木蘭僧，飯了空聲送。"]'),
('e2ebc430-fa6d-464a-9f05-8790ed11707e','與張樞密','羅仲舒','宋','宋诗','song-poetry','','[]','孤憤全憑尺素書，一官牢落竟何如。',64,'全唐诗/poet.song.174000.json','["孤憤全憑尺素書，一官牢落竟何如。", "兵威似火難言熄，世事猶棋祇報輸。", "魚棄青蒲歸淺渚，鳥忘白粒墮枯株。", "杞人縱有憂天志，忍見鴟夷賜子胥。"]'),
('0fda130c-617b-46ba-bf6d-dddba9aac17a','失題','羅仲舒','宋','宋诗','song-poetry','','[]','世情落落疏，林樹森森密。',48,'全唐诗/poet.song.174000.json','["世情落落疏，林樹森森密。", "乘興一登臨，峭然風景別。", "飛雲去不停，狂澗流無歇。", "巢許是何人，萬古稱豪傑。"]'),
('510344c7-3974-4382-acfd-26f68914d0e7','跋蘭亭考','楊長孺','宋','宋诗','song-poetry','','[]','石更青白故兼新，字看由中總是真。',64,'全唐诗/poet.song.174000.json','["石更青白故兼新，字看由中總是真。", "畢子一生三百紙，樓公四句幾千春。", "從來考古難題處，直到名流下筆親。", "奄有山陰多寶藏，草菴外面更無人。"]'),
('97ad78ee-81c5-48c4-9694-2c240ac919c2','代民輸租','楊長孺','宋','宋诗','song-poetry','','[]','兩年枉了鬢霜華，照管南人沒一些。',32,'全唐诗/poet.song.174000.json','["兩年枉了鬢霜華，照管南人沒一些。", "七百萬錢都不要，脂膏留放小民家。"]'),
('8cd79a7c-d5e9-4ff8-ae5d-9485b2e4385d','別石門','楊長孺','宋','宋诗','song-poetry','','[]','石門得得泊歸舟，江水依依別故侯。',32,'全唐诗/poet.song.174000.json','["石門得得泊歸舟，江水依依別故侯。", "擬把片香投贈汝，這回欲带忘來休。"]'),
('eb5ac3c2-f99c-4501-8d7c-19ab326f0838','貽羅竹谷','楊長孺','宋','宋诗','song-poetry','','[]','與世長多忤，持身轉覺孤。',48,'全唐诗/poet.song.174000.json','["與世長多忤，持身轉覺孤。", "夤緣新齒舌，收拾老頭顱。", "我已訶瀧吏，君誰誦子虛。", "同歸燈火讀，家裏石渠書。"]'),
('b0184921-f556-496e-a6a4-58e392c0972f','跋大人論配享書稿','楊長孺','宋','宋诗','song-poetry','','[]','覆羹真得皂囊書，錦水元來勝石渠。',32,'全唐诗/poet.song.174000.json','["覆羹真得皂囊書，錦水元來勝石渠。", "但寶銀鈎并鐵畫，何須玉带與金魚。"]'),
('00aeb19b-3936-423c-ab5b-76cd3b89e5a0','題湖州畫像','楊長孺','宋','宋诗','song-poetry','','[]','面有憂民色，天知報國心。',48,'全唐诗/poet.song.174000.json','["面有憂民色，天知報國心。", "三年風月少，兩鬢雪霜深。", "更莫留形迹，何曾廢古今。", "不如隨我去，相伴老山林。"]'),
('2709fad7-df81-4c3b-8400-3aa8424ff593','和徐思叔題貧樂圖','楊長孺','宋','宋诗','song-poetry','','[]','三間破屋一床書，錦心繡口冰肌膚。',32,'全唐诗/poet.song.174000.json','["三間破屋一床書，錦心繡口冰肌膚。", "自紉枯葉作袴襦，此君便是長鬚奴。"]'),
('1fef7b87-6155-480e-926a-ca2143e1b665','和曾無疑','楊長孺','宋','宋诗','song-poetry','','[]','雪舟不肯半塗回，直到荒林意盛哉。',64,'全唐诗/poet.song.174000.json','["雪舟不肯半塗回，直到荒林意盛哉。", "籬菊苞時披宿霧，木犀香裏絕纖埃。", "錦心綉口垂金薤，月露天漿貯玉杯。", "八十仙翁能許健，片雲得得出巢來。"]'),
('e4464919-52b3-4a55-beb2-f6fc17990ebe','王蕊花','楊長孺','宋','宋诗','song-poetry','','[]','纔入平園便有聲，唐昌觀裏久知名。',64,'全唐诗/poet.song.174000.json','["纔入平園便有聲，唐昌觀裏久知名。", "已堆玉琖分金粟，更插銀花小翠罌。", "蘿蔓春風藤薜長，山礬香氣晉齊盟。", "世間百卉應無恨，不遇王公枉一生。"]'),
('cd19caa7-92db-431d-b6ba-d7034500450c','茨菰花','楊長孺','宋','宋诗','song-poetry','','[]','折來趁得未晨光，清露晞風带月凉。',64,'全唐诗/poet.song.174000.json','["折來趁得未晨光，清露晞風带月凉。", "長葉剪刀廉不割，小花茉莉淡無香。", "稀疏略糝瑶臺雪，升降常涵翠管漿。", "恰恨山中窮到骨，茨菰也遣入詩囊。"]'),
('6efdee00-311b-405b-b463-d7f4d38b6c2a','送胡季昭竄象郡二首  其一','楊長孺','宋','宋诗','song-poetry','','[]','新來消息使人疑，一網如何盡去之。',32,'全唐诗/poet.song.174000.json','["新來消息使人疑，一網如何盡去之。", "元祐祇今爲紹聖，姬周嫠婦謾深悲。"]'),
('bd6dcc25-2493-41be-bb53-8afff4114cb6','送胡季昭竄象郡二首  其二','楊長孺','宋','宋诗','song-poetry','','[]','世事昏昏酒正酣，苦言難藥盜言甘。',32,'全唐诗/poet.song.174000.json','["世事昏昏酒正酣，苦言難藥盜言甘。", "李庭男子真奇絕，便是吾鄉小澹庵。"]'),
('96446849-d262-4e1e-b9a4-9447f7b844ae','梨','楊長孺','宋','宋诗','song-poetry','','[]','想像含消與接枝，英華集裏脆香詩。',64,'全唐诗/poet.song.174000.json','["想像含消與接枝，英華集裏脆香詩。", "外披翠羽中懷玉，嚼出清泉上滿池。", "溢齒應餐多正好，堆盤儘飣老將宜。", "炎蒸時節還能洗，不是梨侯更有誰。"]'),
('c2dde83a-fa50-46af-b0b6-4de63388777a','一滴泉','楊長孺','宋','宋诗','song-poetry','','[]','法眼三泓井，曹溪一滴泉。',48,'全唐诗/poet.song.174000.json','["法眼三泓井，曹溪一滴泉。", "經秋杜宇血，遺老徑山禪。", "衲子非常釋，叢林別是天。", "諸方多少淚，分灑汝江邊。"]'),
('9c35b728-3d90-4806-8e8b-42c667b59df6','題兩翁相見圖','楊長孺','宋','宋诗','song-poetry','','[]','侍講朱顔映白髮，尚書野服接通衢。',32,'全唐诗/poet.song.174000.json','["侍講朱顔映白髮，尚書野服接通衢。", "德星聚處人爭看，畫作兩翁相見圖。"]'),
('5849e29f-69af-4602-95f3-ee0ab3ec01ec','題匡山瑞木圖二首  其一','楊長孺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','孤根初作兩枝榮，五朵終連獨榦明。',64,'全唐诗/poet.song.174000.json','["孤根初作兩枝榮，五朵終連獨榦明。", "看取松楸天瑞好，如何草木世人輕。", "春花秋葉垂千載，雁字鴒原了一生。", "孝友編中圖畫底，子孫忽自占清名。"]'),
('5dafe78c-35b0-4b35-808e-026ef089525a','題匡山瑞木圖二首  其二','楊長孺','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','仙李從來別有源，手提造化發生權。',64,'全唐诗/poet.song.174000.json','["仙李從來別有源，手提造化發生權。", "冰霜不到雲間樹，風日偏和雨外阡。", "四海幾人傳盛事，一家雙美兩臞仙。", "同生同死仍同紀，花萼猶應照九泉。"]'),
('0ad48cbc-c5cf-4133-ad1d-748491c5dbf4','小飛來亭二首  其一','楊長孺','宋','宋诗','song-poetry','','[]','陰森古木石心栽，清澈寒溪鏡面開。',32,'全唐诗/poet.song.174000.json','["陰森古木石心栽，清澈寒溪鏡面開。", "斗起孤峰三百尺，從今喚作小飛來。"]'),
('6619efad-adc5-4bc4-ae88-8cc755b2b79b','小飛來亭二首  其二','楊長孺','宋','宋诗','song-poetry','','[]','拔地齊天可上不，倚巖危棧半空浮。',32,'全唐诗/poet.song.174000.json','["拔地齊天可上不，倚巖危棧半空浮。", "偶然憶得垂堂戒，前猛還成新懦休。"]'),
('c9090951-7b11-4e9e-87a9-3d736386bbd1','句  其一','楊長孺','宋','宋诗','song-poetry','','[]','地老天荒元子宅，煙霏霧結魯公碑。',16,'全唐诗/poet.song.174000.json','["地老天荒元子宅，煙霏霧結魯公碑。"]'),
('7dfb7dad-1893-4a74-8ced-70e934bec773','句  其二','楊長孺','宋','宋诗','song-poetry','','[]','不濃不淡勻脂粉，半醉半醒媚雨風。',16,'全唐诗/poet.song.174000.json','["不濃不淡勻脂粉，半醉半醒媚雨風。"]'),
('b10e195b-e495-493b-9c49-f0187a026803','句  其三','楊長孺','宋','宋诗','song-poetry','','[]','過眼一春春又夏，開殘芍藥更無花。',16,'全唐诗/poet.song.174000.json','["過眼一春春又夏，開殘芍藥更無花。"]'),
('de26475e-183d-473e-8489-4343307da91d','句  其四','楊長孺','宋','宋诗','song-poetry','','[]','淺著燕支調淡粉，細將瑪瑙碎鋪茸。',16,'全唐诗/poet.song.174000.json','["淺著燕支調淡粉，細將瑪瑙碎鋪茸。"]'),
('c60a3a9e-dfd5-46df-9663-423a118f12fb','句  其五','楊長孺','宋','宋诗','song-poetry','','[]','靈均九畹應無此，福地三茅浪自誇。',16,'全唐诗/poet.song.174000.json','["靈均九畹應無此，福地三茅浪自誇。"]'),
('9b63e6ae-ac87-4759-a0e7-5116f2af0ebd','句  其六','楊長孺','宋','宋诗','song-poetry','','[]','平林常常談俚蠻，玉山之産升金盤。',32,'全唐诗/poet.song.174000.json','["平林常常談俚蠻，玉山之産升金盤。", "其中一樹斷崖立，石乳蔭根多歲寒。"]'),
('afd3df72-c86a-4dfe-900c-03c0fd7b8f75','句  其七','楊長孺','宋','宋诗','song-poetry','','[]','一封無己帖，兩首樂天詩。',12,'全唐诗/poet.song.174000.json','["一封無己帖，兩首樂天詩。"]'),
