('bfa39532-afa5-4b6a-bc52-fcfad5d070ab','句','福州幕官','宋','宋诗','song-poetry','','[]','從渠腰下有金带，何處山中無菜羹。',16,'全唐诗/poet.song.174000.json','["從渠腰下有金带，何處山中無菜羹。"]'),
('12c32326-b3ec-447d-93e3-c9cf9c8af128','句','湖州士子','宋','宋诗','song-poetry','','[]','可憐戴工部，獨樹不成林。',12,'全唐诗/poet.song.174000.json','["可憐戴工部，獨樹不成林。"]'),
('3e3889c1-e465-4857-910d-45a3a7cdc496','贈談命余圓機','蔡淵','宋','宋诗','song-poetry','','[]','甲子難周日與時，不拘全闕是圓機。',32,'全唐诗/poet.song.174000.json','["甲子難周日與時，不拘全闕是圓機。", "只將八字縱橫看，禍福無差妙太虛。"]'),
('293d19a2-be10-4801-97fa-0008c40b0bf0','自詠','蔡淵','宋','宋诗','song-poetry','','[]','屈指摳衣四十年，自憐鬚鬢已皤然。',64,'全唐诗/poet.song.174000.json','["屈指摳衣四十年，自憐鬚鬢已皤然。", "久知軒冕應無分，但覺西山若有緣。", "下學功夫慚未到，先天事業敢輕傳。", "祇今已飽煙霞疾，更乞清溪著釣船。"]'),
('19944abb-8e67-4f47-a91e-a3c3031e07f8','仲弟未歸歲晚有懷','蔡淵','宋','宋诗','song-poetry','','[]','明月照席寒，生我愁百端。',108,'全唐诗/poet.song.174000.json','["明月照席寒，生我愁百端。", "冉冉歲云徂，遊子不顧還。", "相送荷花碧，相望楓葉丹。", "高樓日千回，散步東林隈。", "攀條復攬秀，日暮空徘徊。", "金杯白玉臺，猶能對寒梅。", "寄書豈不早，三月千里道。", "敢怨歸軒遲，但念堂中老。", "春風萱草生，更樹堂前庭。"]'),
('eed4b645-fdf0-418d-8c96-ff2cc60168f4','初度謾成','蔡淵','宋','宋诗','song-poetry','','[]','揆予初度又今時，老桂吹香滿翠微。',64,'全唐诗/poet.song.174000.json','["揆予初度又今時，老桂吹香滿翠微。", "回首六千餘里外，驚心四十九年非。", "閒尋舊藁黏吟卷，怕損團花理戰衣。", "一飯君恩何以報，貔貅按堵馬秋肥。"]'),
('7e454f41-d0f5-48b4-9bcc-4e636994400f','垂虹亭','陳直卿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','西望洞庭突兀，東連仙里人家。',28,'全唐诗/poet.song.174000.json','["西望洞庭突兀，東連仙里人家。", "笑指闌干三百，醉來就此乘槎。"]'),
('136fc15f-30f9-4946-ab3e-6ae750c9cb19','和太白感秋詩韵','易祓','宋','宋诗','song-poetry','','[]','我無適俗韻，濫剖江成竹。',96,'全唐诗/poet.song.174000.json','["我無適俗韻，濫剖江成竹。", "惟有南山雲，對之若可掬。", "秋堂風露清，豈不念羈獨。", "行年四十九，亦復此栖宿。", "二子亦有契，茲期定前卜。", "泛觀穹壤間，物剝繼以復。", "消息固常然，天地非反覆。", "姑置勿復言，新篘已清熟。"]'),
('92242ff6-5724-4b7c-a8a7-7660527f7cdf','和黄山谷龜殻詩韵二首  其一','易祓','宋','宋诗','song-poetry','','[]','一枝自足鷦鷯巢，一居猶勝蝸牛屋。',32,'全唐诗/poet.song.174000.json','["一枝自足鷦鷯巢，一居猶勝蝸牛屋。", "道人身外本無求，况有龜軒可棲宿。"]'),
('013ee3ca-d0c7-4cf4-9af2-4a8dbf931190','和黄山谷龜殻詩韵二首  其二','易祓','宋','宋诗','song-poetry','','[]','支牀納息三百年，也勝刳賜貯金屋。',32,'全唐诗/poet.song.174000.json','["支牀納息三百年，也勝刳賜貯金屋。", "問子多智亦多窮，何如蓮葉安巢宿。"]'),
('5133e48a-38ef-49bc-a654-0fc7931f2d5e','和黄山谷瓊芝詩韵','易祓','宋','宋诗','song-poetry','','[]','千歲蟾蜍猶得仙，百年枸杞足延命。',32,'全唐诗/poet.song.174000.json','["千歲蟾蜍猶得仙，百年枸杞足延命。", "也須點鐵自成金，未信磨磚能作鏡。"]'),
('ad9287cc-fdf1-47ed-b9be-e0d55055f09b','浯溪中興頌','易祓','宋','宋诗','song-poetry','','[]','湘江東西直浯溪，上有十丈中興碑。',160,'全唐诗/poet.song.174000.json','["湘江東西直浯溪，上有十丈中興碑。", "誰鑿豐碑鎮山曲，溪邊美人美如玉。", "想當歌頌大業時，胸蟠星斗光陸離。", "蠶須蠆尾更清勁，凜凜襟懷冰雪瑩。", "水部之文魯公書，兩翁寥寥千載餘。", "後來更有黄太史，健筆題詩起翁死。", "一派溪流徹底清，溪邊鏡石堅而明。", "我思古人不可見，水石猶作瓊瑰聲。", "朅來名山訪遺蹟，煙雨凄迷山路濕。", "野叟蒙頭看打碑，君其問諸水邊石。"]'),
('fb8c3a0b-2e4f-431b-8b19-3d79b86521e8','讀唐中興頌','易祓','宋','宋诗','song-poetry','','[]','唐家基業重於山，甯許胡雛據九關。',64,'全唐诗/poet.song.174000.json','["唐家基業重於山，甯許胡雛據九關。", "當日人心旋□堵，異時世變却循環。", "壤分旄鉞誰能制，政出貂璫不復還。", "千古高崖鎖蒼蘚，空留遺蹟蹈元顔。"]'),
('d4f9b01f-a1c0-43ad-ae01-966ae7c02ceb','寄御史節判陶岑','易祓','宋','宋诗','song-poetry','','[]','我醉欲眠君罷休，誰能倚杖聽江流。',64,'全唐诗/poet.song.174000.json','["我醉欲眠君罷休，誰能倚杖聽江流。", "蕉花當戶不知午，梧葉滿庭疑是秋。", "吾道從來無物累，此心何處不天游。", "鴻邊幸有音書至，春在江南雲夢洲。"]'),
('bd0ca60d-4b3f-4af3-930f-ce9d17835044','懸鐘石','易祓','宋','宋诗','song-poetry','','[]','不今不古不朝昏，只與南山伴白雲。',32,'全唐诗/poet.song.174000.json','["不今不古不朝昏，只與南山伴白雲。", "我既無聲亦無臭，衆生當以不聞聞。"]'),
('bbe9e7bf-78bd-4b73-8abc-4eca67ac7533','示從姪茂','易祓','宋','宋诗','song-poetry','','[]','萬事皆從忙處錯，寂然不動乃能通。',32,'全唐诗/poet.song.174000.json','["萬事皆從忙處錯，寂然不動乃能通。", "君看開濟規模事，却屬南陽高卧翁。"]'),
('1dd5f71e-84a8-4a7c-a805-dc2e24e3fae7','題識山樓','易祓','宋','宋诗','song-poetry','','[]','山外如何便識山，白雲出岫鳥知還。',32,'全唐诗/poet.song.174000.json','["山外如何便識山，白雲出岫鳥知還。", "更看面目知端的，却在先生几格閒。"]'),
('7fc7bfb4-9e91-4b34-a59c-cef18e7aa26c','安靈龍潭','易祓','宋','宋诗','song-poetry','','[]','流水淼無際，其源徧坤輿。',144,'全唐诗/poet.song.174000.json','["流水淼無際，其源徧坤輿。", "壓之以山麓，壅淤誰與疏。", "神物夜相宅，風雷發欷歔。", "擘開蒼玉峽，瀉作清泠渠。", "安得探其穴，扁舟武陵漁。", "吾聞覆載閒，不過一身如。", "九竅互開閤，血膚乃張舒。", "其閒或積滯，氣鬰成癰疽。", "山澤本通氣，自然厥中虛。", "明河轉地軸，喬岳并郊墟。", "脈絡無不寓，地行乃其餘。", "請觀千丈瀑，高出康谷廬。"]'),
('04fb247e-fecc-4f6b-8a35-7772f5e8c076','對雪','易祓妻','宋','宋诗','song-poetry','','[]','紛紛瑞雪壓山河，特出新奇和郢歌。',64,'全唐诗/poet.song.174000.json','["紛紛瑞雪壓山河，特出新奇和郢歌。", "樂道幽人方閉戶，高歌漁父正披蓑。", "自嗟老景光陰速，誰使佳時感愴多。", "更念鰥居憔悴客，映書無寐奈愁何。"]'),
('193328b6-2f9c-45e2-b1c1-60a831004f81','池荷','喬行簡','宋','宋诗','song-poetry','','[]','萱草軒窗處處幽，酒中不著客中愁。',32,'全唐诗/poet.song.174000.json','["萱草軒窗處處幽，酒中不著客中愁。", "芭蕉葉上無多雨，分與池荷一半秋。"]'),
('8e5a2970-6691-46b1-ac23-0044bb919d19','游三丘山','喬行簡','宋','宋诗','song-poetry','','[]','疑是乘風到九天，不知身在此山巔。',64,'全唐诗/poet.song.174000.json','["疑是乘風到九天，不知身在此山巔。", "萬家攢簇炊煙底，一水縈紆去鳥邊。", "便覺塵緣輕似羽，何妨詩意湧如泉。", "停杯更待林梢月，歸去家僮想未眠。"]'),
('131c8cd8-e8cd-4154-b79b-5ae008be9e58','書懷','趙子覺','宋','宋诗','song-poetry','','[]','柳影槐陰綠遶村，日長細得話詩情。',64,'全唐诗/poet.song.174000.json','["柳影槐陰綠遶村，日長細得話詩情。", "迎風紫燕忽雙去，隔雨黄鸝又一聲。", "筆墨生涯成冷淡，筍蔬盤饌易經營。", "世間微利真刀蜜，有底驅馳取重輕。"]'),
('e9f77349-f64b-4330-8990-42beca80fa48','句','宇文紹節','宋','宋诗','song-poetry','','[]','過口此舟方屬汝，行人何用較錐刀。',16,'全唐诗/poet.song.174000.json','["過口此舟方屬汝，行人何用較錐刀。"]'),
('090823b4-5acb-4882-83c6-598e0c96f7be','踏磧','宇文紹莊','宋','宋诗','song-poetry','','[]','八陣圖前凜古風，武侯英烈豈怱怱。',64,'全唐诗/poet.song.174000.json','["八陣圖前凜古風，武侯英烈豈怱怱。", "江流千載長嗚咽，山插孤雲亦蒨葱。", "陡覺新春忘病思，喜陪高論自情鍾。", "典刑前輩今能幾，歲晚相期華髮同。"]'),
('d08ec946-c076-4a44-a4b9-be3322432171','秋日郊居','郭秉哲','宋','宋诗','song-poetry','','[]','一葉驚初下，煩襟喜復清。',48,'全唐诗/poet.song.174000.json','["一葉驚初下，煩襟喜復清。", "雲邊開岫色，風外送溪聲。", "菊引陶潜興，蓴牽張翰情。", "迎眸秋色遠，頓覺杖藜輕。"]'),
('0fb4441f-d209-4406-ba78-6a28af4375f7','題畫','郭秉哲','宋','宋诗','song-poetry','','[]','蕭蕭風雨聲，一夜入修竹。',24,'全唐诗/poet.song.174000.json','["蕭蕭風雨聲，一夜入修竹。", "中有遺世人，歸雲掩茅屋。"]'),
('1427fd68-eaf2-4bbf-931b-5430e6ed8a6a','飛來峰','張履信','宋','宋诗','song-poetry','','[]','飛來何處峰，木杪夜千尺。',24,'全唐诗/poet.song.174000.json','["飛來何處峰，木杪夜千尺。", "愁猿喚不譍，月色同一白。"]'),
('8514eb38-ddd7-4f7c-97a2-aa15b5a5ae89','冷泉亭','張履信','宋','宋诗','song-poetry','','[]','水石一欄干，僧歸四山靜。',24,'全唐诗/poet.song.174000.json','["水石一欄干，僧歸四山靜。", "携琴譜澗泉，月浸夜深冷。"]'),
('a629cf19-a39f-4441-bd0e-8f2203358f81','翠微亭','張履信','宋','宋诗','song-poetry','','[]','朝朝烏北出，夜夜烏南歸。',60,'全唐诗/poet.song.174000.json','["朝朝烏北出，夜夜烏南歸。", "所謀在一食，所息在一枝。", "人生竟何得，與烏同此機。", "身世忽過慮，泉石良自怡。", "月上飛來峰，更誰登翠微。"]'),
('cb18c1ee-bca4-47be-84fb-af7c85231744','訪丹陽玉乳泉已變昏黑因賦詩','張履信','宋','宋诗','song-poetry','','[]','觀音寺裏泉經品，今日唯存玉乳名。',32,'全唐诗/poet.song.174000.json','["觀音寺裏泉經品，今日唯存玉乳名。", "定是年來無陸子，甘香收入柳枝缾。"]'),
('bca2295a-2635-4482-9ba2-11e1d39d8ab3','淳熙十三年六月中使奉德壽宮命捕金銀魚','胡某','宋','宋诗','song-poetry','','[]','千頃山高六十里，上有寒潭清且泚。',160,'全唐诗/poet.song.174000.json','["千頃山高六十里，上有寒潭清且泚。", "神龍久向此中蟠，作霖肯爲蒼生起。", "羣魚從之時浮沈，噞喁光彩歲月深。", "自然形質異凡鬣，或如美玉或如金。", "或青或紅或閒色，縱使丹青模不得。", "幾年潛伏少人知，一旦聲名動京國。", "皇家太平端好奇，麟欲效瑞鳳欲儀。", "白環銀甕爭走獻，豈得汝輩藏洿池。", "深山大澤多遺寶，紆餘卓犖皆娟好。", "願移網罟聊一施，嶄然頭角趨明時。"]'),
('64271c3e-6261-4a1d-bbfc-d47fa3fd31d8','題龍隠巖','王迤祖','宋','宋诗','song-poetry','','[]','龍蟠此地不知年，飛去穿成萬仞淵。',32,'全唐诗/poet.song.174000.json','["龍蟠此地不知年，飛去穿成萬仞淵。", "霖雨四方今欲遍，後人空自想蜿蜒。"]'),
('cedb1453-43ae-4d31-bd00-146ca2b34294','五言二首  其一','王淹','宋','宋诗','song-poetry','','[]','一雨日夜零，階前草更青。',24,'全唐诗/poet.song.174000.json','["一雨日夜零，階前草更青。", "西風忽蕭颯，殘月照空庭。"]'),
('5f3c6dff-814a-4bc4-b5d9-0e498ef5c340','五言二首  其二','王淹','宋','宋诗','song-poetry','','[]','鐘鼎山林事，都盧一夢中。',24,'全唐诗/poet.song.174000.json','["鐘鼎山林事，都盧一夢中。", "觀音門裏去，葉葉響悲風。"]'),
('42ece567-d645-4db1-b9f5-8b71ab24def6','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其一','王淹','宋','宋诗','song-poetry','','[]','秋風一夕來，木落江水波。',48,'全唐诗/poet.song.174000.json','["秋風一夕來，木落江水波。", "相將鴈南翔，奈有孤飛何。", "四海兄弟少，百年離別多。", "儻堅歸來心，富貴爾則那。"]'),
('8aa3e23d-266e-4b45-9cb7-146ded25a9d5','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其二','王淹','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','送君南浦上，風煙慘前知。',48,'全唐诗/poet.song.174000.json','["送君南浦上，風煙慘前知。", "當時長江水，已與滄溟期。", "海經遠山外，人在高樓時。", "潮來君莫忘，中有清淚滋。"]'),
('075a3d54-73bd-4cd0-97da-679d33a96b70','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其三','王淹','宋','宋诗','song-poetry','','[]','我家尺五天，行人指城東。',48,'全唐诗/poet.song.174000.json','["我家尺五天，行人指城東。", "老槐閲世故，高蔭自清風。", "叵量陵谷變，猶歎斤斧空。", "故國豈喬木，遂應人與同。"]'),
('fece8e07-99bd-4f10-8936-ff2a46e2a3e5','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其四','王淹','宋','宋诗','song-poetry','','[]','先人昔營菟，嵩少買別墅。',48,'全唐诗/poet.song.174000.json','["先人昔營菟，嵩少買別墅。", "後生久逸樂，稍識田家苦。", "平生十具牛，獨立方寸土。", "至今龍門灘，猶夢秋夜雨。"]'),
('f95bea5c-fb47-46b2-b2d0-47cbcb33f419','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其五','王淹','宋','宋诗','song-poetry','','[]','雨葉收餘音，寒蟲怨遥夜。',48,'全唐诗/poet.song.174000.json','["雨葉收餘音，寒蟲怨遥夜。", "向來十年燈，致論秦屢借。", "白頭錯料事，抱璞睎世價。", "出門已絕倒，一字不堪藉。"]'),
('2ec9f72a-4dfe-46b8-999e-6350b547876f','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其六','王淹','宋','宋诗','song-poetry','','[]','母慈懷遠音，積雨人未復。',48,'全唐诗/poet.song.174000.json','["母慈懷遠音，積雨人未復。", "朝來鳥鵲喜，門外書一幅。", "小邦王事繁，夜食忘歸沐。", "何處望飛鳬，山中酒初熟。"]'),
('4b934dca-f78b-4221-97d8-61d8aa259a3a','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其七','王淹','宋','宋诗','song-poetry','','[]','安道樂東山，少游志鄉里。',48,'全唐诗/poet.song.174000.json','["安道樂東山，少游志鄉里。", "二龍各同淵，屈信有彼此。", "何年金華客，異世赤松子。", "此謀非人决，頭顱當自揣。"]'),
('70be36bd-2f36-4b94-996c-9ee8f3b540c0','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其八','王淹','宋','宋诗','song-poetry','','[]','膏以明自銷，翟以文故翳。',48,'全唐诗/poet.song.174000.json','["膏以明自銷，翟以文故翳。", "兩蘇事業遠，卒與憂患對。", "夕陽西州道，江海愴餘悔。", "九折更徐驅，前有覆軌在。"]'),
('b1f3e370-0df9-4b84-938d-a15948b73bcd','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其九','王淹','宋','宋诗','song-poetry','','[]','田園久蕪沒，何適爲故鄉。',48,'全唐诗/poet.song.174000.json','["田園久蕪沒，何適爲故鄉。", "眷茲南陽阡，松柏日蒼蒼。", "但恨雲邊茅，無地安藜牀。", "采蕨飲江水，此人那得忘。"]'),
('4c0cf144-cca1-476f-8261-97deb2c29ccb','吾兄文夫宦遊天台余將官於江左不勝感離之情用韋蘇州那知風雨夜復此對牀眠爲韻作十詩以寄  其一○','王淹','宋','宋诗','song-poetry','','[]','小草有遠志，大樗可長年。',48,'全唐诗/poet.song.174000.json','["小草有遠志，大樗可長年。", "山林自相許，風雨堪獨眠。", "稍須三徑資，莫問五湖船。", "從今坐右銘，可刻招隠篇。"]'),
('dc8685ea-209c-403b-9e9c-c49e42ab8fce','寄仲子','王淹','宋','宋诗','song-poetry','','[]','汝生十七年，不離父母膝。',72,'全唐诗/poet.song.174000.json','["汝生十七年，不離父母膝。", "抗言求自試，立意堅且必。", "父母不汝拒，汝志誠少匹。", "束書下扁舟，挂席飛鳥疾。", "書來報善達，授館亦云佚。", "進修不多言，祝汝慎非一。"]'),
('092d51b3-6677-41c4-b110-c0c8e71a0c5a','秋浦見陸次川會其有廣德之役同游齊山而別既歸以詩寄之','王淹','宋','宋诗','song-poetry','','[]','我車疾驅無停輈，君馬既秣猶少留。',64,'全唐诗/poet.song.174000.json','["我車疾驅無停輈，君馬既秣猶少留。", "客懷那更見行色，勝地不能成縱遊。", "君去我愁歸路遠，黄葉霜風山意晚。", "幾時雲外有音來，早送文書遮病眼。"]'),
('86ac38d0-0aa9-406e-8cae-be25f90e8452','寄蔣季莊','王淹','宋','宋诗','song-poetry','','[]','桃花水起問行舟，時不能留迹自留。',64,'全唐诗/poet.song.174000.json','["桃花水起問行舟，時不能留迹自留。", "何有聲名呼子慎，儻能饑渴念之罘。", "前車或向中涂廢，古井難持短綆求。", "聞說下帷書已就，願從繁露識春秋。"]'),
('fc13b2c7-737b-4310-b0bc-c890baa953ad','次韻文夫兄病目新起','王淹','宋','宋诗','song-poetry','','[]','胸中眸子坦何疑，不見妖蟇歎月詩。',64,'全唐诗/poet.song.174000.json','["胸中眸子坦何疑，不見妖蟇歎月詩。", "牛背神光元我在，虎頭墨妙敢吾欺。", "競看投杖行成矩，會起彎弨滿中規。", "可惜平生憂國淚，眼明猶及見清時。"]'),
('c5228a8a-b092-486a-a11b-712825dace84','次袁尚書巫山十二峰二十五韻','錢鍪','宋','宋诗','song-poetry','','[]','文昌仙伯天人姿，愛山尋勝如書癡。',394,'全唐诗/poet.song.174000.json','["文昌仙伯天人姿，愛山尋勝如書癡。", "忽摩台符歷參井，麾幢泝峽春遲遲。", "山林川后總效職，萬壑千巖俱獻奇。", "就中巫山絕雄勝，插天紫翠相參差。", "神妃來下珮聲遠，駐此名地相安之。", "峰旋地轉自前後，屹立萬馬如追隨。", "兩山有川幻天巧，禹功到此神應疲。", "仰天照眼如匹練，舟行電掣翻雲旗。", "迅帆競惜峰巒過，艅艎望眼裳褰帷。", "懸崖下有欲落石，古木上有參天枝。", "龍登鶴聚仙既集，雲昇雨暗天如低。", "從來三峽號至險，高牙穩泛如遊嬉。", "揚旌一覽天下勝，詞源倒峽知優爲。", "嘗聞奇觀天亦惜，遇賢輒與因其時。", "少陵遇此雖窮寂，妙語驚人多在茲。", "彫鎸萬象發天閟，衙官屈宋聲爭馳。", "公今曳履星辰上，調元妙手行將施。", "天教來作東道主，歡聲和氣生江湄。", "公來頓覺雪山重，青城增氣聯峨眉。", "首驅巫陽入新句，一洗前作堪解頤。", "英詞從此徧蜀道，迥出塵表無纖緇。", "嘗憂此地難久駐，轉首絕境成嗟嘻。", "直欲使拂素練圖翠嶷，寫松巒起雲之狀，模翠屏棲鳳之嵋。", "終朝誦公有聲畫，却來看此無聲詩。"]'),
('54a49365-61d7-4cd9-b0df-7b323da2c046','大滌洞留題  其一','黄敏德','宋','宋诗','song-poetry','','[]','九鎖山深斷世蹤，雲霞堆裏著瑶宮。',64,'全唐诗/poet.song.174000.json','["九鎖山深斷世蹤，雲霞堆裏著瑶宮。", "千年地勝身纔到，一柱峰高路忽通。", "據石漱泉消俗念，捫蘿扣洞挹仙風。", "直疑凡骨今朝換，不假金丹屢轉功。"]'),
('a8760006-f656-4534-a6e7-ec2d0a1cf1fc','大滌洞留題  其二','黄敏德','宋','宋诗','song-poetry','','[]','憶昨朝真暫憇留，清宵澒洞乳泉流。',64,'全唐诗/poet.song.174000.json','["憶昨朝真暫憇留，清宵澒洞乳泉流。", "重來人在山尤好，剩喜凉生暑頓收。", "玉柱擎天高拔地，翠蛟擁日冷涵秋。", "蠅頭蝸角如飴美，林下誰能一轉頭。"]'),
('283df559-0ef3-456a-aa30-231aa77a3445','入洞霄九鎖路間','黄敏德','宋','宋诗','song-poetry','','[]','綠蘿垂地白日暗，落葉滿徑行人稀。',32,'全唐诗/poet.song.174000.json','["綠蘿垂地白日暗，落葉滿徑行人稀。", "青童走入報迎客，驚罷先生一局棋。"]'),
('dd33d61f-6f9f-4543-926c-ccaf4352fc27','舞翠亭觀泉','黄敏德','宋','宋诗','song-poetry','','[]','坐來毛骨覺蕭然，百尺飛流下碧天。',32,'全唐诗/poet.song.174000.json','["坐來毛骨覺蕭然，百尺飛流下碧天。", "杯酒未終身世換，盡移三峽到尊前。"]'),
('b057a2c1-7a6e-4a6f-9c87-dac1aedf4cb8','上李郎中嘉言二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','莽莽出北門，迢迢伍牙山。',96,'全唐诗/poet.song.174000.json','["莽莽出北門，迢迢伍牙山。", "伍牙何崔嵬，羣岑間孤巒。", "望之蔚然秀，豈無草與菅。", "中有百尺松，可憩不可攀。", "六月久不雨，祝融奮其官。", "行人渴欲死，班荆此盤旋。", "往來得所託，感慨爲長歎。", "况爾山上苗，久蔭無棄捐。"]'),
('cd708fcd-0202-4784-a256-22a60ba3f686','上李郎中嘉言二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','桐川出幽谷，等彼江漢深。',72,'全唐诗/poet.song.174000.json','["桐川出幽谷，等彼江漢深。", "修然一派橫，清澈寒士心。", "有時對日光，圭棱燦星金。", "沙礫謾自苦，安能蔽清泠。", "我行正寒風，欲滌如煩襟。", "念彼濯纓人，千載求知音。"]'),
('373b367e-bbe6-4dca-b48b-b4c0064c7eef','喜雪次倅車韻呈使君','曹彥約','宋','宋诗','song-poetry','','[]','使君軼何武，未去民先思。',132,'全唐诗/poet.song.174000.json','["使君軼何武，未去民先思。", "平生愛我意，玉立無玷疵。", "邇來祁寒咨，已賦白雪詞。", "陽春有脚來，雲意夜四垂。", "天公亦小兒，布置人未知。", "美滿豐年意，萬里光陸離。", "璇題庾亮樓，柳絮習家池。", "監州有佳思，往往似佺期。", "格律前緩聲，比興莫相疑。", "平分風月餘，時吟冰柱詩。", "明年朝雪宮，同上萬壽巵。"]'),
('087ee4da-6d1b-4135-91a8-b12cbd561dad','雪中同趙倉從之泛舟餞錢憲文季酒中劇談漢事臨別文季索詩賦四十韻以寄','曹彥約','宋','宋诗','song-poetry','','[]','冬序玄以冥，閉塞乃其職。',288,'全唐诗/poet.song.174000.json','["冬序玄以冥，閉塞乃其職。", "巧作六花飛，與天爲粉澤。", "初舞若狂然，既定稍真積。", "坐令宇宙間，萬象變顔色。", "霜肅特加厚，月皎更留迹。", "晚節答造化，有此足清白。", "今日此何日，雙艣鳴大舶。", "清溪照紅粧，醴酒障行客。", "莫言山水興，蕭散竟何益。", "莫作兒女戀，黯然空戚戚。", "有詔起聞人，意遠理可即。", "王所切經綸，言路倚忠直。", "鋤梃弄湘南，鐵甲泠河北。", "倉廩竭江外，蒙袂窘朝糴。", "隠憂關念慮，閒暇已偪仄。", "忽作一尺圍，此事費紬繹。", "先生持論高，踐履我所識。", "酒酣技已癢，漢事多發擿。", "仲舒智似愚，紓緩却端的。", "公孫巧乃拙，迎合屢傾側。", "縞衣紛陸離，見睍立消釋。", "惟有真實在，拍拍滿胸臆。", "雄辯醉得醒，溫言寒褪力。", "誰知百丈外，霏屑散珠璧。"]'),
('473dc57a-eacd-44b6-a153-903d51cff376','水北民家窗間有題夜深短檠燈功名平生心者戲成平側詩二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','詩書窮年燈，功名平生心。',48,'全唐诗/poet.song.174000.json','["詩書窮年燈，功名平生心。", "辛勤鶑遷喬，哀鳴猿投林。", "蘭膏誰爲容，朱絃無知音。", "安能如蜉蝣，隨時安其陰。"]'),
('92ccda41-2250-4e9e-80a7-74170f515d75','水北民家窗間有題夜深短檠燈功名平生心者戲成平側詩二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','竹外兩縣境，水北一草舍。',48,'全唐诗/poet.song.174000.json','["竹外兩縣境，水北一草舍。", "蔀屋日見斗，韞匵玉待價。", "禍福自倚伏，得失忽晝夜。", "子盍去墨守，我亦入遠社。"]'),
('c4f0983c-e97c-485e-8d43-c035a3f33edf','知縣次韻來復寄二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','亭亭青琅玕，冰霜崔嵬心。',48,'全唐诗/poet.song.174000.json','["亭亭青琅玕，冰霜崔嵬心。", "雖無桃李姿，知非柴荆林。", "凉風西南來，清圓彈空音。", "其誰齊彭殤，相從山之陰。"]'),
('fbd4e170-4ede-47fb-aeaa-e6cda7b1b789','知縣次韻來復寄二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','得志鳥擇木，失喜鵩入舍。',48,'全唐诗/poet.song.174000.json','["得志鳥擇木，失喜鵩入舍。", "但協孔氏性，忍索少室價。", "小草有遠志，積李欲縞夜。", "所覬匠伯顧，不復棄櫟社。"]'),
('4541f1f8-d1a2-4d12-9b72-44cc37129172','知縣再次韻不作平側體復次韻二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','步出山前坂，遥望徒驚心。',48,'全唐诗/poet.song.174000.json','["步出山前坂，遥望徒驚心。", "下無百尺流，上無千歲林。", "至人有遺言，三歎金玉音。", "莫飲盜泉水，莫息惡木陰。"]'),
('96ec477b-a682-4c8c-8178-84dd2968ed5b','知縣再次韻不作平側體復次韻二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','和氏得荆璞，眩走數百舍。',48,'全唐诗/poet.song.174000.json','["和氏得荆璞，眩走數百舍。", "謂足奉至尊，過眼不售價。", "有時置篋笥，光彩忽驚夜。", "持歸弄兒女，足以照里社。"]'),
('0289fc31-1c0c-4160-9b42-31f25533893b','贈日者','曹彥約','宋','宋诗','song-poetry','','[]','我本無能人，簡冊强纏繞。',48,'全唐诗/poet.song.174000.json','["我本無能人，簡冊强纏繞。", "饒舌苦譊譊，外貌似了了。", "應酬聊復爾，懶惰亦不少。", "眨眼鼻如雷，黄昏到天曉。"]'),
('0a51f8a8-5f3c-4e8d-96ac-ece46bee5fbc','上周益公','曹彥約','宋','宋诗','song-poetry','','[]','荒村建午月，斯螽動股鳴。',132,'全唐诗/poet.song.174000.json','["荒村建午月，斯螽動股鳴。", "借問暑方熾，何意作秋聲。", "自言本寒族，四海無令名。", "振羽每自歎，在野神屢驚。", "常恐向寒時，風霜莽飄零。", "憶昨寒谷中，春風全我生。", "贈我百草芳，遄我趯趯征。", "是時木未茁，及此堇向榮。", "感彼蟋蟀歌，日月遒以傾。", "促織未成章，淒切難爲聽。", "願言日載陽，有鳴隨倉庚。"]'),
('9c3f6e99-686d-41e3-a6cf-4094e0d85413','老梅晦父改韻見貽走筆奉和','曹彥約','宋','宋诗','song-poetry','','[]','有酒且莫斟，聽我歌一曲。',96,'全唐诗/poet.song.174000.json','["有酒且莫斟，聽我歌一曲。", "所歌無長語，江梅倚修竹。", "炯炯寒露冰，皎皎白駒谷。", "粲粲能賦人，日日對高躅。", "詩如何水曹，發興揚州牧。", "味入傅巖翁，調鼎國受福。", "桃李豈不華，入景混凡木。", "偃蹇有長松，窮年相照矚。"]'),
('5af46219-3073-4ae4-b408-4823533a5aff','贈別徐秀','曹彥約','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','出京纔四日，雨雪日一縣。',48,'全唐诗/poet.song.174000.json','["出京纔四日，雨雪日一縣。", "行徧淛江頭，夢識廬山面。", "相逢兄弟歡，莫作兒女戀。", "歸計動心旌，春風摇柳線。"]'),
('5e24b749-be5d-4c88-8f72-b9d49f317fff','贈別潘漢臣','曹彥約','宋','宋诗','song-poetry','','[]','宦薄魚上竿，地左猿擇木。',48,'全唐诗/poet.song.174000.json','["宦薄魚上竿，地左猿擇木。", "經過還似舊，笑語何時足。", "留君潘鬢在，許我曹裝趣。", "三年却歸來，此夢如何續。"]'),
('ce8cc7bb-bb40-4b67-9034-7c2e947d44d6','偶成','曹彥約','宋','宋诗','song-poetry','','[]','道心非動靜，學者何難易。',48,'全唐诗/poet.song.174000.json','["道心非動靜，學者何難易。", "癡雲欲掃除，迅霆無擬議。", "無妄而微疾，勿藥斯有喜。", "一輪秋月明，云爲豈思慮。"]'),
('8ab571ed-30c9-466f-a09b-a95f2a3b98fd','春日奉陪韓簽虞丞解監修禊事即席中所有蝦菜梨棗分韻得蝦字','曹彥約','宋','宋诗','song-poetry','','[]','雨餘春水壓堤沙，柳未花飛蒲茁芽。',320,'全唐诗/poet.song.174000.json','["雨餘春水壓堤沙，柳未花飛蒲茁芽。", "清流激湍石佛寺，崇山峻嶺野人家。", "大酉之山檀溪壑，秦俗未改書成車。", "居夷驟得羣賢集，惠風鼓動生精華。", "去年可疑張進士，市人物色爭矜誇。", "今年艤棹無所適，坐看孤鶩齊落霞。", "長官敏者唐吏部，八龍受種今渥洼。", "兩年分韻得此老，未覺景物相寵嘉。", "世南弄筆好商搉，宴客自許窮珍鮭。", "萬金鼎至我亦喜，便欲染指魚與蝦。", "漢司隸後最靜者，家有白璧無點瑕。", "扣之清越聲韻響，滿座失喜相歎呀。", "怪予窮陋一不有，冠者八九乃獨髽。", "歸而謀婦得斗酒，夜韭可剪魚可叉。", "偶欲占射酒似闕，自覺輩晚無肩差。", "暗中曹劉不易得，屈宋未死甘押衙。", "自從修禊卜師友，一洗萬古况兩蝸。", "但恐朝家用賢急，去我便立文石花。", "泮宮先生坐官舍，意此四子窮驕奢。", "年前共得石居士，留客嵌空到日斜。"]'),
('b3cccbc0-a3c1-4629-8d2b-165998a31c2a','帥相泛巨舟東下水淺不可進盤旋三日僅至菱黄浦率同行就此作別簡以小詩','曹彥約','宋','宋诗','song-poetry','','[]','半日鼕鼕離岸鼓，萬斛龍驤發南浦。',288,'全唐诗/poet.song.174000.json','["半日鼕鼕離岸鼓，萬斛龍驤發南浦。", "戈鋋照日牙纛明，百丈咿啞更雙艣。", "眼前突兀勝華屋，前廳中堂後圊浴。", "主人燕坐擁歌舞，晝捧金樽夜銀燭。", "吳人餘皇那可比，漢家樓船聊爾耳。", "有時但可濟舟師，無事只堪橫野水。", "太平州縣邊無譁，行所朝夕如居家。", "恩光草際碧弄色，心事柳梢黄茁芽。", "我亦同時浮一葉，葭葦作篙蒲作楫。", "坐久欠身頭觸篷，卧多輾轉衣成摺。", "旁瞻畫鷁如飛動，絕似茅茨望梁棟。", "春光嬌面秋月眉，爭妍不到書生夢。", "誰知淺水雞籠山，順風不下留驚灘。", "津人用盡如神力，長年三老忘朝餐。", "嗚呼材具各有用，秔稻不生穜稑種。", "涸轍聊濡鮒魚沫，大壑方觀巨鱗縱。", "我生簡便非憚煩，坐觀燕蝠爭晨昏。", "瞥然便轉子猷棹，明朝直到章江門。"]'),
('f15121dd-7c93-4b00-9b37-147e49b2e2bb','陪漕使春日吳江之集戲贈元理森父','曹彥約','宋','宋诗','song-poetry','','[]','垂虹夜吸吳儂水，畫鷁朝飛張翰里。',64,'全唐诗/poet.song.174000.json','["垂虹夜吸吳儂水，畫鷁朝飛張翰里。", "護客歸來玉節閒，隠隠春光動浮蟻。", "傾蓋鱸魚故交蠣，可人森父佳元理。", "著我中間醉却醒，舊管新收幾年紀。"]'),
('4caeccf5-43ea-4df8-8b6a-7e3612e8c8b0','次韻使君湖莊歌','曹彥約','宋','宋诗','song-poetry','','[]','使君德量湖水寬，和氣襲人春避寒。',64,'全唐诗/poet.song.174000.json','["使君德量湖水寬，和氣襲人春避寒。", "山川自古窮絕處，鑄鐵點頑成轉丹。", "頻作好詩醇似酒，妃子鬭妍西子醜。", "人生行樂只花時，更吸西江斟一斗。"]'),
('52fec0ea-8a98-46a9-9646-1eec0ae07fe5','次韻蔡元簡麒湖莊之句','曹彥約','宋','宋诗','song-poetry','','[]','雞本憚犧先斷尾，燕粗能巢聊葺壘。',64,'全唐诗/poet.song.174000.json','["雞本憚犧先斷尾，燕粗能巢聊葺壘。", "漫郎無用却歸來，得熟道傍真苦李。", "誰家買田綠當戶，何人種花紅照水。", "君詩讀罷已忘機，撲漉沙鷗隨處起。"]'),
('0f5bce24-5c75-4c15-b609-552156da61c0','大雪感懷','曹彥約','宋','宋诗','song-poetry','','[]','翻雲覆雨紛輕薄，萬瑞不如三白樂。',176,'全唐诗/poet.song.174000.json','["翻雲覆雨紛輕薄，萬瑞不如三白樂。", "歲事相關國重輕，天意亦知人忖度。", "前年不雨旱爲祟，今年不旱螟爲惡。", "造物與人著力深，一飽年來何落落。", "宜春先生古君子，撐腸萬卷一丘壑。", "吟哦乍擬柳飛絮，感慨相輝花有萼。", "商量雪意馳一騎，改變天容翔萬鶴。", "翻思五十乾道年，是非一律無今昨。", "日月逝矣幾豐耗，人物眇然增索寞。", "吹箎寡唱氣欲竭，陟屺何心淚猶閣。", "再拜珠璣卜來歲，十襲藏之富囊橐。"]'),
('6920ae56-537f-4a07-9dbf-843d93b8ff1c','季直經幹喜得三白次師繹韻見餉走筆奉和','曹彥約','宋','宋诗','song-poetry','','[]','三農一命如紙薄，已定蓋藏猶不樂。',176,'全唐诗/poet.song.174000.json','["三農一命如紙薄，已定蓋藏猶不樂。", "年來慳雪意如何，摶空歲事堪隃度。", "新誇兩白已呈祥，數日天工還作惡。", "栽培玉屑界瓊田，指顧同雲藏碧落。", "萬象改容龍戰野，滿船空載魚縱壑。", "詩才喚起金閨人，坡上傳香梅綴萼。", "明當改選歲又稔，揚州騎得纏腰鶴。", "家有靈光獨巋然，事感鴒原驚已昨。", "豈無他人和者寡，不有阿咸幾落寞。", "關心不見九華樓，舊遊莫歎登雲閣。", "與我新詩字字奇，珠玉盈懷分陸橐。"]'),
('c21f4181-6df9-40e5-bd48-178532dd0273','陪使者護客晚發京口','曹彥約','宋','宋诗','song-poetry','','[]','拖船鳥驚獸駭奔，追夫雷動雲作屯。',128,'全唐诗/poet.song.174000.json','["拖船鳥驚獸駭奔，追夫雷動雲作屯。", "前日生辰使者去，賀正又出丹陽門。", "欲上未上軍人馬，似響不響縣官喏。", "窮冬閘閉水不行，深夜火明山欲赭。", "尚書太尉傳語來，夫船未足官須催。", "敵使三節能幾耳，客載萬舸何爲哉。", "甘心事仇誰作俑，恥不自羞猶慫慂。", "古來秦禍不須胡，蒙恬斥外斯高寵。"]'),
('8b7ee420-1b3b-4e2c-b756-7d35d72a755b','次韻李晦父炎早梅','曹彥約','宋','宋诗','song-poetry','','[]','華顛淡色催人老，造化無功春不早。',64,'全唐诗/poet.song.174000.json','["華顛淡色催人老，造化無功春不早。", "翰林風月恣推排，萬馬一空三峽倒。", "冷暖從渠入世情，孤真爲我參幽抱。", "單于未覺鼎鼐催，不與人間障煩惱。"]'),
('3307f124-e4e0-40e4-aeee-5d2ec575db95','交代趙從之善石見和次韻奉答','曹彥約','宋','宋诗','song-poetry','','[]','詩來格律辭皆老，却恨有磚拋不早。',64,'全唐诗/poet.song.174000.json','["詩來格律辭皆老，却恨有磚拋不早。", "只因清興與花同，千詠昔聞今健倒。", "君家裝額要冰肌，我圃耐寒誇合抱。", "秀色孤根各自宜，玉堂茅舍俱相惱。"]'),
('6623cf2f-22ce-4ebe-97d0-bc005167708e','有懷昌谷老梅再次晦父韻兼贈仲元弟','曹彥約','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水邊籬落西湖老，結伴寒標歸計早。',64,'全唐诗/poet.song.174000.json','["水邊籬落西湖老，結伴寒標歸計早。", "月昏香動幅巾時，鐵石廣平猶壓倒。", "新來昌谷闢藩牆，密花疎榦添環抱。", "等閒詩酒奉周旋，何似文書頻苦惱。"]'),
('bfb3a0ec-06f1-4e47-88b1-c0dd803a04ba','泛舟蕭公陂','曹彥約','宋','宋诗','song-poetry','','[]','山水遶青鑪鞴紅，花開絮亂春欲空。',64,'全唐诗/poet.song.174000.json','["山水遶青鑪鞴紅，花開絮亂春欲空。", "太白酌酒塵世外，小舟蕩槳農事中。", "築堤溉田十里同，居民舉手稱蕭公。", "蕭公有惠何時窮，十里穮蔉無凶豐。"]'),
('c7faf007-7220-4c16-829e-4738737d672e','景仁寄和蕭公陂詩次其韻','曹彥約','宋','宋诗','song-poetry','','[]','照眼石榴裙褶紅，回頭浪蘂隨春空。',64,'全唐诗/poet.song.174000.json','["照眼石榴裙褶紅，回頭浪蘂隨春空。", "春歸湓浦風塵外，詩到淮南烟雨中。", "護田將綠一水同，造化奪巧非天公。", "錦囊不盡思無窮，我欲從之歌元豐。"]'),
('6ef80a27-9284-4184-9d58-0cb0eeba1e66','方南康席上觀贛妓秀英作墨梅竹','曹彥約','宋','宋诗','song-poetry','','[]','南州佳人號秀英，竊弄毛頴親儒生。',96,'全唐诗/poet.song.174000.json','["南州佳人號秀英，竊弄毛頴親儒生。", "解衣傍若無我輩，疎梅矮竹真天成。", "公主朝粧弄眉墨，誤作鉛華污宮額。", "此君劍器藏鋒鋩，張顛幻出公孫娘。", "我來忽見驚心目，張八何生魏何熟。", "酒酣耳熱且勿喧，爲我慇懃寫雙幅。"]'),
('92cd9757-ae77-401c-91d4-c1b3e7cbcd72','次韻魏君寶光黄雲觀古風','曹彥約','宋','宋诗','song-poetry','','[]','重湖鏡展心生凉，五老壁立背負芒。',96,'全唐诗/poet.song.174000.json','["重湖鏡展心生凉，五老壁立背負芒。", "中間只作如許屋，一觀雖小意堂堂。", "書生相業綫不絕，故侯墨妙燈不滅。", "與山三好孰四之，畢萬有孫胸次闊。", "拋梁不須偉兒郎，黄雲高舉天頡頏。", "從龍作霖皆是物，邇來一足飛商羊。"]'),
('c2d0f933-4b7f-4c83-b09b-10b31030edfb','次韻趙使君師夏謁白鹿遊棲賢長句','曹彥約','宋','宋诗','song-poetry','','[]','三峽移名澗響空，中著一橋如飲虹。',200,'全唐诗/poet.song.174000.json','["三峽移名澗響空，中著一橋如飲虹。", "旁連濺瀑龍所宮，謂佛有力真冥濛。", "非造物意無禹功，一綫偶達成巨谼。", "可怪一律人聵聾，助桀唱和更撞舂。", "或者誤信晨暮鐘，萬有一幸相際逢。", "吾儒自有名教蹤，壁立萬古澗底松。", "異端瑣細秋後蛩，一物不格皆妄庸。", "誰知健者此山中，樸實可亂田舍翁。", "出郊小隊不妨農，黄巖意與考亭通。", "長養此道如種穜，駿發爾私雨我公，穮蔉雖饉亦有豐。", "常行萬世無汙隆，行健不息人中龍。", "不妨更擊白鹿鼓，扣之大小皆舂容。"]'),
('7d3405a0-7335-426e-b4b0-6a2a12c5f3d3','同景輔登樓約集少陵句  其一','曹彥約','宋','宋诗','song-poetry','','[]','徐步移斑杖，登臨意惘然。',48,'全唐诗/poet.song.174000.json','["徐步移斑杖，登臨意惘然。", "雲霄遺暑濕，樓閤倚山巔。", "薄劣慚真隠，虛空不離禪。", "我生無倚著，自有一山川。"]'),
('432d58f9-3a4c-470d-859f-eebe01d6ab92','同景輔登樓約集少陵句  其二','曹彥約','宋','宋诗','song-poetry','','[]','開闢當天險，分明在眼前。',48,'全唐诗/poet.song.174000.json','["開闢當天險，分明在眼前。", "野橋齊度馬，森木亂鳴蟬。", "稠疊多幽事，凄凉憶去年。", "何時一樽酒，恣意向江天。"]'),
('c54abb7d-5d8e-498a-9f04-fa7755fe5d54','送十三郎赴尉漢陽二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','宦路今如此，親闈望已深。',48,'全唐诗/poet.song.174000.json','["宦路今如此，親闈望已深。", "是誰門戶責，慰我父兄心。", "鏡裏休頻看，杯中但淺斟。", "前賢官業處，端的要追尋。"]'),
('0d7e39cc-4ee4-4caa-99c4-9fc1ac0aa3cb','送十三郎赴尉漢陽二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','此地關情久，淳龐好士民。',48,'全唐诗/poet.song.174000.json','["此地關情久，淳龐好士民。", "向來同患難，今歷幾秋春。", "綵棒迎新尉，綈袍說舊人。", "爲言昌谷老，寄語益相親。"]'),
('97f14fb8-d1c8-42b6-b213-ee933c19d196','出郊偶成呈府判知縣三丈二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','奉行三尺令，問訊十分春。',48,'全唐诗/poet.song.174000.json','["奉行三尺令，問訊十分春。", "雞犬柴門曉，牛羊草徑新。", "遠投雙嶺寺，頻見耦耕人。", "我亦江南客，爲農頗識真。"]'),
('da1b3c63-d50d-4fab-801b-618bc602b1f7','出郊偶成呈府判知縣三丈二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','去郭喧囂遠，空江氣象寬。',48,'全唐诗/poet.song.174000.json','["去郭喧囂遠，空江氣象寬。", "柳舒含絮媚，梅褪著枝酸。", "物外登山好，公餘盡日歡。", "歸遲應犯夜，暝色占江干。"]'),
('94e0f918-3c95-4810-a8f5-8696f71580af','寒露日阻風雨左里詩','曹彥約','宋','宋诗','song-poetry','','[]','久謂熱當雨，茲來歸近家。',48,'全唐诗/poet.song.174000.json','["久謂熱當雨，茲來歸近家。", "露寒遲應節，天變勇飛沙。", "甕白應浮酒，籬黄可著花。", "一江三十里，直欲問仙槎。"]'),
('30b7a821-e67b-4ea9-8b1a-6951bf3ea31d','親友馮儀之運幹挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','聞道江西使，賓筵隕德星。',48,'全唐诗/poet.song.174000.json','["聞道江西使，賓筵隕德星。", "失聲歸士友，短氣動朝廷。", "屢選非無意，遲行若有靈。", "忍令清燕處，我輩尚談經。"]'),
('dbfcae89-b796-4210-93dc-ec117cfba05e','親友馮儀之運幹挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','有學關時用，無心與物馳。',48,'全唐诗/poet.song.174000.json','["有學關時用，無心與物馳。", "已稱黄髮老，猶似綵衣時。", "世道空機穽，襟期自坦夷。", "只今風月夜，猶足想清規。"]'),
('0da3227e-190b-4952-a5eb-91b29bc7a482','親友馮儀之運幹挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','子也吾嘗友，天乎獨異渠。',48,'全唐诗/poet.song.174000.json','["子也吾嘗友，天乎獨異渠。", "仕無通籍祿，家有厚齋書。", "講說來匡鼎，風騷藉子虛。", "爭榮森竇桂，訓不負蕃畬。"]'),
('59eeb19d-ae47-43c1-98cc-3ea7696ff33e','挽致政朝散王大夫章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','風流江左後，今不愧諸王。',48,'全唐诗/poet.song.174000.json','["風流江左後，今不愧諸王。", "弓冶儒非誤，衣冠晚見償。", "當時獨立處，千載狀元鄉。", "天定常如此，三槐有二郎。"]'),
('3508dc79-ce05-4e5b-bfd8-12c83e85b034','挽致政朝散王大夫章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','子貴人間有，親難及盛年。',48,'全唐诗/poet.song.174000.json','["子貴人間有，親難及盛年。", "出藩先使節，入從冠經筵。", "問政承顔日，歸鄉屬纊前。", "誰能碑有道，還合傳先賢。"]'),
('84d1f63a-44c0-45b5-9f9e-9d22b4b2a413','同知樞密程公挽章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','用盡文章力，多馳剸撥聲。',48,'全唐诗/poet.song.174000.json','["用盡文章力，多馳剸撥聲。", "一朝歸禁近，再歲即鈞衡。", "遇合功名迫，哀榮日月傾。", "鹽梅空有志，縮手未調羹。"]'),
('4b4032f8-ae3e-4f66-9bba-a2ef8a405720','同知樞密程公挽章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','憶昔都城會，論交戊午班。',48,'全唐诗/poet.song.174000.json','["憶昔都城會，論交戊午班。", "故書雖絕迹，晚景自貪閒。", "契闊形骸外，參差出處間。", "重來風作惡，黯淡寶蓮山。"]'),
('5642e6da-7820-4f54-a9d3-3fa2db8303ad','挽蔡祭酒詩二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','舊說乘驄老，新來衣繡人。',48,'全唐诗/poet.song.174000.json','["舊說乘驄老，新來衣繡人。", "眷方隆嗣聖，世已厭成均。", "景晚遲鵷序，邊秋憶虎臣。", "家聲傳慶曆，忠惠豈前身。"]'),
('c2306e8c-ab7a-46de-b774-a0ccf9e31c0b','挽蔡祭酒詩二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','昔締金昆好，慈恩有舊題。',48,'全唐诗/poet.song.174000.json','["昔締金昆好，慈恩有舊題。", "及今如社燕，與子共朝雞。", "未見星常北，相逢日易西。", "定應湖上路，塞色黯招提。"]'),
('97e8f513-3b39-4ba9-aede-90dd20822854','宿蘇坊','曹彥約','宋','宋诗','song-poetry','','[]','客久囂塵外，冬深驛舍前。',48,'全唐诗/poet.song.174000.json','["客久囂塵外，冬深驛舍前。", "亂山寬處日，野水暮時烟。", "契分新篘酒，生涯舊物氈。", "悠然歸興動，依約探梅天。"]'),
('a40de379-606b-4b18-938d-8d4b26fea7b8','致政檢法牛公挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','結屋明經好，經明身欲修。',48,'全唐诗/poet.song.174000.json','["結屋明經好，經明身欲修。", "平生倉廩實，不爲稻粱謀。", "宦路門方盛，容臺志已酬。", "莫言餘八袠，猶欠少遲留。"]'),
('9872d7c1-6a54-4ce3-94cf-356e3c2f59a3','致政檢法牛公挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','瘠甚都昌境，民無晚種田。',48,'全唐诗/poet.song.174000.json','["瘠甚都昌境，民無晚種田。", "樂輸雖欲速，乞糴最堪憐。", "帥閫施長技，王人改舊弦。", "本原誰任責，陰德至今傳。"]'),
('a0da48bf-79e4-40a4-99f4-8f77946bb667','致政檢法牛公挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','門戶關州縣，交游及弟昆。',48,'全唐诗/poet.song.174000.json','["門戶關州縣，交游及弟昆。", "每於尊俎後，窺見典刑存。", "豈不昏姻重，常疎藥石言。", "矧聞丹旐發，心緒正沄沄。"]'),
('9ceb7ab3-0f87-4550-b538-c6e2a8a3ca3d','夏日漫興','曹彥約','宋','宋诗','song-poetry','','[]','廣厦仍炎熱，疎慵疾病中。',48,'全唐诗/poet.song.174000.json','["廣厦仍炎熱，疎慵疾病中。", "賦詩當夏日，鼓棹近南風。", "自覺塵氛少，依然樂事同。", "夜來憑眺處，明月隠牆東。"]'),
('b173dc73-6019-4c25-93b3-e3f4d4eb419e','龍會遇雪','曹彥約','宋','宋诗','song-poetry','','[]','出門能幾里，風雪故相隨。',48,'全唐诗/poet.song.174000.json','["出門能幾里，風雪故相隨。", "新歲自有巧，舊寒猶絕癡。", "自天藏瓦礫，與客照鬚眉。", "甲冷殊關念，豐年却在茲。"]'),
('b1513fb1-d994-419d-ba55-3f6d9f2c3cfb','中和後一日吳門阻雪距春分纔三日','曹彥約','宋','宋诗','song-poetry','','[]','梅容慘不競，鳥語噤無聲。',48,'全唐诗/poet.song.174000.json','["梅容慘不競，鳥語噤無聲。", "二月朔已告，三日春當分。", "寒餘凌暖律，雪後更同雲。", "但恐嚴凝誤，陽和欲奏勳。"]'),
('b06ab6b6-1e8d-4f59-81a7-bf6076983a82','桂陽走筆呈以道','曹彥約','宋','宋诗','song-poetry','','[]','別後蓬丘老，分盃歲又闌。',48,'全唐诗/poet.song.174000.json','["別後蓬丘老，分盃歲又闌。", "髮因求道白，心但濟時丹。", "瘧鬼三秋熱，河魚六月寒。", "不圖梅影夜，對榻共平安。"]'),
('02ef12ca-904d-40ac-bb4d-3c4c3d584d3a','龍游道中得家信','曹彥約','宋','宋诗','song-poetry','','[]','幸自居家樂，何須遣信來。',48,'全唐诗/poet.song.174000.json','["幸自居家樂，何須遣信來。", "聲聞先隕穫，書至尚驚猜。", "問僕心方定，開緘色漸回。", "寄言重九日，掃凈玉京臺。"]'),
('dfc52598-f556-492e-a231-0a8567434cb6','聞官軍收復新息','曹彥約','宋','宋诗','song-poetry','','[]','降敵知無日，和戎事已休。',48,'全唐诗/poet.song.174000.json','["降敵知無日，和戎事已休。", "百年艱國步，九世憶家讎。", "獲蔡馳新捷，收京有定謀。", "可無蜂蠆慮，馬健更防秋。"]'),
('665ca209-37f5-493e-a52d-a09cff969d36','再至淮南','曹彥約','宋','宋诗','song-poetry','','[]','湓浦經從後，淮壖欲到時。',48,'全唐诗/poet.song.174000.json','["湓浦經從後，淮壖欲到時。", "江山春自改，風雨日相隨。", "泥滑禽猶訴，崖懸馬欲疑。", "解鞍聊間息，造物本無私。"]'),
('ed2fc098-cc2a-4e0b-a400-0c7282874686','書彭仲誠詩卷後','曹彥約','宋','宋诗','song-poetry','','[]','惠養無他務，廉勤以自持。',48,'全唐诗/poet.song.174000.json','["惠養無他務，廉勤以自持。", "能寬三邑責，不爲一州私。", "逮此來歸日，還如始至時。", "士民難借寇，唯有召棠思。"]'),
('9c38d237-83db-4fae-8a5d-6a656d589e26','冬至留滯舒州有懷歲旦泊舟平江門外','曹彥約','宋','宋诗','song-poetry','','[]','舒郡驚冬節，吳門憶歲時。',48,'全唐诗/poet.song.174000.json','["舒郡驚冬節，吳門憶歲時。", "天寒城閉早，凍合水行遲。", "再拜爲兄壽，同聲念母慈。", "窮年終是客，至日始題詩。"]'),
('f36abb53-0f5b-41fb-82e6-07a6e5afe593','驚蟄後雪訪徐孟堅不遇坐待甚久','曹彥約','宋','宋诗','song-poetry','','[]','忽忽弄明珠，紛紛擁塞酥。',48,'全唐诗/poet.song.174000.json','["忽忽弄明珠，紛紛擁塞酥。", "都忘春老大，復作冷工夫。", "甲拆遲先達，芳菲約後圖。", "興來還興盡，呵手復須臾。"]'),
('88062e0c-d93c-4be8-9d2a-484b1a7bd762','遣將追賊何公橋','曹彥約','宋','宋诗','song-poetry','','[]','遲爾停車久，偷生恐未然。',48,'全唐诗/poet.song.174000.json','["遲爾停車久，偷生恐未然。", "皇威三令後，民瘼萬端前。", "貔虎煙塵地，猩鼯雨霧天。", "監官有老眼，巢幕暫狂顛。"]'),
('3526ba12-ef90-49a7-b6d5-e3c40a8b6ff3','子敬作詩已久不以見示忽出一卷共有四十字乃相陪避暑三峽橋之作戲次其韻','曹彥約','宋','宋诗','song-poetry','','[]','乃有詩如此，清新思湧泉。',48,'全唐诗/poet.song.174000.json','["乃有詩如此，清新思湧泉。", "夤緣塵外景，發露性中天。", "舊事驚陳迹，新功喜盛年。", "當流欹枕處，醒得困時眠。"]'),
('0e1f8243-d635-4b71-a72d-ea180727478e','二郎之官房陵作五言唐律兩章送之  其一','曹彥約','宋','宋诗','song-poetry','','[]','入幕曾霑祿，之官始問津。',48,'全唐诗/poet.song.174000.json','["入幕曾霑祿，之官始問津。", "邊城甘冷淡，世路識艱辛。", "責重杯柈省，公餘簡冊頻。", "先人清白意，百世尚書紳。"]'),
('dbf64ae6-2bb7-4c6b-aec6-ab17ab807223','二郎之官房陵作五言唐律兩章送之  其二','曹彥約','宋','宋诗','song-poetry','','[]','制閫今梁棟，霜臺昔範模。',48,'全唐诗/poet.song.174000.json','["制閫今梁棟，霜臺昔範模。", "近書先問汝，遠念早寬吾。", "衆論宜遷木，官常合守株。", "房陵有佳處，穩穩問征涂。"]'),
('93047c4d-b9a2-406c-b039-304c6c3d086a','虞司理留同官麵飯','曹彥約','宋','宋诗','song-poetry','','[]','玉版初參後，桄榔半醉中。',48,'全唐诗/poet.song.174000.json','["玉版初參後，桄榔半醉中。", "誰知三里外，有此五人同。", "移座淋頭雨，開窗拂坐風。", "明朝公事了，假道訪虞公。"]'),
('7b66cd05-0b87-414f-8b5a-b3fe17a910fc','上巳日舍舟豐城','曹彥約','宋','宋诗','song-poetry','','[]','路出豐城縣，籃輿了夕陽。',48,'全唐诗/poet.song.174000.json','["路出豐城縣，籃輿了夕陽。", "何人共列坐，勝事憶流觴。", "帝里衣冠近，家山念慮長。", "慇懃樓下水，今夜到吾鄉。"]'),
('1573fae5-206d-4895-b881-836ccdac26a7','蕭散','曹彥約','宋','宋诗','song-poetry','','[]','風日倚餘勇，扶春不自由。',48,'全唐诗/poet.song.174000.json','["風日倚餘勇，扶春不自由。", "在家曾半面，隨我到他州。", "絮後酴醾約，鶑前杜宇愁。", "新來無吏責，蕭散更何求。"]'),
('e19fd8bb-e87b-444c-bd8e-ad673065e4df','雪中領客湖莊','曹彥約','宋','宋诗','song-poetry','','[]','天上瓊林會，人間瑞物圖。',48,'全唐诗/poet.song.174000.json','["天上瓊林會，人間瑞物圖。", "山藏真面目，地湧巧工夫。", "領客驚閭巷，携家窘僕奴。", "却思邊戍地，著鐵更彎弧。"]'),
('ff3f27bc-d47b-4fdc-a19d-a621f53b4b87','連雨坐湖莊','曹彥約','宋','宋诗','song-poetry','','[]','泥濘政如許，出門安所之。',48,'全唐诗/poet.song.174000.json','["泥濘政如許，出門安所之。", "龍公無倦日，老子有閒時。", "適意家常酒，忘懷獨自棋。", "困來饒一睡，百慮本何思。"]'),
('168c169f-a978-4dc7-b965-b8e86162889e','春問湖莊','曹彥約','宋','宋诗','song-poetry','','[]','問訊湖莊事，經年意若何。',48,'全唐诗/poet.song.174000.json','["問訊湖莊事，經年意若何。", "爲渠魂入夢，老我鬢添皤。", "雪霽春應好，山明水漸多。", "遣兒徵僕役，除道莫蹉跎。"]'),
('525c8e21-ec39-4e7b-82a5-e1bec1e93c55','深春挈家下湖莊  其一','曹彥約','宋','宋诗','song-poetry','','[]','去郭不三里，將家踰十年。',48,'全唐诗/poet.song.174000.json','["去郭不三里，將家踰十年。", "轉添身散誕，况乃足蹁躚。", "九疊春宜老，羣芳晚更妍。", "得閒無一事，倚杖看鞦韆。"]'),
('290f0592-ddb8-4d82-99a0-bf7da7b08fe2','深春挈家下湖莊  其二','曹彥約','宋','宋诗','song-poetry','','[]','我生聊自樂，人意適相隨。',48,'全唐诗/poet.song.174000.json','["我生聊自樂，人意適相隨。", "郊外有行處，春中無倦時。", "雖知攀折苦，未覺燕游衰。", "更欲添桃李，初心不在茲。"]'),
('0d12421c-ca50-466f-9f62-ca78bdda375f','師繹題宮姊夫惠示湖莊佳句輒次韻  其一','曹彥約','宋','宋诗','song-poetry','','[]','願學言詩賜，降心識字雄。',48,'全唐诗/poet.song.174000.json','["願學言詩賜，降心識字雄。", "絕塵嗟莫及，雅趣喜相同。", "任性天憐老，貪閒鬼笑窮。", "可堪香火分，誤入武陵中。"]'),
('d3e44810-f8e4-44e9-a07d-ebf6dfbb5e63','師繹題宮姊夫惠示湖莊佳句輒次韻  其二','曹彥約','宋','宋诗','song-poetry','','[]','車馬喧人境，茅茨棄道旁。',48,'全唐诗/poet.song.174000.json','["車馬喧人境，茅茨棄道旁。", "無心天外得，有玉匵中藏。", "領略煩詩將，勾收入醉鄉。", "會從盤谷老，野處日徜徉。"]'),
('7d397ef8-8e2c-49d8-be54-3d1672d1a623','湖莊雜詩  其一','曹彥約','宋','宋诗','song-poetry','','[]','萬頃蒼茫外，三年種植初。',48,'全唐诗/poet.song.174000.json','["萬頃蒼茫外，三年種植初。", "路回深吠犬，藻密暗遊鱼。", "舊酒春同盎，新茶雪不如。", "稍修遺老傳，忘答故人書。"]'),
('0d7f17dd-37bc-48b5-baa9-29b3d9865043','湖莊雜詩  其二','曹彥約','宋','宋诗','song-poetry','','[]','野水平湖闊，雲山疊嶂深。',48,'全唐诗/poet.song.174000.json','["野水平湖闊，雲山疊嶂深。", "一溪橫驛道，兩岸挾神林。", "亂石通人迹，孤舟繫客心。", "幾年茅葦地，松檜已侵尋。"]'),
('a136c09a-4751-4068-96cc-ea046c4365c8','故邕管安撫李思永挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','發廩寧憂歲，防邊不待秋。',48,'全唐诗/poet.song.174000.json','["發廩寧憂歲，防邊不待秋。", "古來漢循吏，今說李成州。", "勁氣橫關隴，神光射斗牛。", "竹林天下士，一第可無求。"]'),
('24b6f1ba-3ba6-4f19-b713-4b19df7de386','故邕管安撫李思永挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','義利明千古，躬行勇不疑。',48,'全唐诗/poet.song.174000.json','["義利明千古，躬行勇不疑。", "澗瀍窮正脈，張陸是吾師。", "仕與儒先會，官從黨論卑。", "所施纔一障，聲聞徹華夷。"]'),
('32af21a4-851c-4d25-958f-d1693cc0eeab','故邕管安撫李思永挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','念昔浮湘樂，論交一世豪。',48,'全唐诗/poet.song.174000.json','["念昔浮湘樂，論交一世豪。", "味同江左右，人忘品卑高。", "庇我渠渠屋，關心戀戀袍。", "延津龍化後，流水但空號。"]'),
('267253ad-3f13-4bde-ac4c-3895921ad867','和趙振文太社郵筒遠寄','曹彥約','宋','宋诗','song-poetry','','[]','天與容臺掾，田園早得歸。',48,'全唐诗/poet.song.174000.json','["天與容臺掾，田園早得歸。", "盃中寧有影，海上息忘機。", "世路閒身好，人生靜者稀。", "更於蘐草處，靜看老萊衣。"]'),
('bc217cbc-182a-4f9e-ae2b-d42215b81896','陳氏夫人挽章','曹彥約','宋','宋诗','song-poetry','','[]','受氏推玄女，來嬪得召南。',48,'全唐诗/poet.song.174000.json','["受氏推玄女，來嬪得召南。", "躬行其誡七，禮盡所從三。", "孝養衣皆綵，權輿色已藍。", "霜風吟木末，哀怨不能堪。"]'),
('835e1cbf-7dc3-41c6-a2d2-fb031ebef73e','送以道赴漢東兵官因呈繡使吳勝之同年兼簡李伯行檢法許定夫軍使三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','久入功名會，新携辟召書。',48,'全唐诗/poet.song.174000.json','["久入功名會，新携辟召書。", "忠勤曾策勵，奮迅此權輿。", "當路心知己，長城指望渠。", "只將真實地，持守足安居。"]'),
('7c05ba07-93ed-4be3-8769-a35fdb2ee5eb','送以道赴漢東兵官因呈繡使吳勝之同年兼簡李伯行檢法許定夫軍使三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','仗斧暴公子，酌泉吳隠之。',48,'全唐诗/poet.song.174000.json','["仗斧暴公子，酌泉吳隠之。", "斯人未易得，於我最相知。", "見義爲常勇，求賢信不疑。", "典刑今在此，此去有餘師。"]'),
('be51bdd4-e982-43e4-a4df-881e45063ef0','送以道赴漢東兵官因呈繡使吳勝之同年兼簡李伯行檢法許定夫軍使三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','李許相從久，時方混武文。',48,'全唐诗/poet.song.174000.json','["李許相從久，時方混武文。", "議刑新幕府，保塞舊將軍。", "二士俱人物，三賢更主君。", "春蘭秋菊意，他日共風雲。"]'),
('fbc3ac4e-56ad-4231-b987-5a9307a542f1','祕閣修撰雷文卿挽章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','殄瘁連鄉黨，凋零及老成。',48,'全唐诗/poet.song.174000.json','["殄瘁連鄉黨，凋零及老成。", "玉亡修水秀，星掩壽沙明。", "不上論思直，空餘餽饟名。", "蓋棺隆眷在，論譔見哀榮。"]'),
('748343f2-6a27-4cf6-819c-887c0a2fe444','祕閣修撰雷文卿挽章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','訪我鳴琴日，聞公吐屑言。',48,'全唐诗/poet.song.174000.json','["訪我鳴琴日，聞公吐屑言。", "循良臨武政，忠憤大奚冤。", "厥後依英簜，新來近達尊。", "却歸桑梓路，忍對建昌門。"]'),
('ebc4f162-e8ea-4908-ba56-46606a1246ac','右史殿撰吳之平挽章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','閫制恩威足，邊防戍守牢。',48,'全唐诗/poet.song.174000.json','["閫制恩威足，邊防戍守牢。", "政平多暇日，民費絕秋毫。", "豹尾天光近，螭頭地勢高。", "孰令黄石水，旦旦只空號。"]'),
('92cbd763-07af-4a37-a612-943034c3419b','右史殿撰吳之平挽章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','生長均江左，游從集豫章。',48,'全唐诗/poet.song.174000.json','["生長均江左，游從集豫章。", "官曹推掃溉，人望極軒昂。", "讜論暌違後，休聲涕淚傍。", "鳳池綸綍手，揮翰發幽光。"]'),
('dab21a9f-8961-4de0-94a7-0a79825a35be','故殿撰修史李舍人挽章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','四戒從誰得，忠勤與孝廉。',48,'全唐诗/poet.song.174000.json','["四戒從誰得，忠勤與孝廉。", "本原來簡冊，膏潤到閭閻。", "仕久機鋒熟，時來智慮添。", "平生真售用，家法有森嚴。"]'),
('13ae0f7d-70e4-4e90-ad0a-4d2fd1839343','故殿撰修史李舍人挽章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','丁未慈恩盛，從容最後來。',48,'全唐诗/poet.song.174000.json','["丁未慈恩盛，從容最後來。", "一從辭墨綬，三徙入鳥臺。", "記動時方好，持衡去不回。", "恩榮頻出綍，晚遇有餘哀。"]'),
('984d4592-6771-47d9-b8a3-9ee32c202f54','故福建提刑鍾編修挽章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','問俗周方國，推賢漢吏師。',48,'全唐诗/poet.song.174000.json','["問俗周方國，推賢漢吏師。", "立朝天有喜，仗節玉無疵。", "得自南軒學，親承北面師。", "更無工部句，可繼八哀詩。"]'),
('b6336766-8dcf-4cf5-92de-be309279b251','故福建提刑鍾編修挽章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','江漢迎歸客，瀟湘問故人。',48,'全唐诗/poet.song.174000.json','["江漢迎歸客，瀟湘問故人。", "錦衣新炫晝，繡使近行春。", "坐對長沙酒，空傷夜雨神。", "南樓風月下，霏屑易成塵。"]'),
('42a1b8bb-2b75-4815-b93e-61ad569a1f67','薛端明挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','講學聲名早，飛騰藹士林。',48,'全唐诗/poet.song.174000.json','["講學聲名早，飛騰藹士林。", "九重嗟見晚，諸老願交深。", "時有亨嘉會，天無平治心。", "每於當用處，梁父又重吟。"]'),
('f7101fab-cf72-4afb-932b-bcadcc3d6482','薛端明挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','諫諍嚴凝地，論思咫尺天。',48,'全唐诗/poet.song.174000.json','["諫諍嚴凝地，論思咫尺天。", "直弦宜問俗，曲突却臨邊。", "儒道終期用，皇威可得宣。", "視儀雖兩地，難到玉階前。"]'),
('4fe5be13-bb2b-4332-a159-b89ed3c81041','薛端明挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','客本何爲者，逢公幕府開。',48,'全唐诗/poet.song.174000.json','["客本何爲者，逢公幕府開。", "兵間雖有志，度外本非才。", "流水音何在，高風首屢迴。", "只今巖石望，寧忍泰山頹。"]'),
('adc0e9bd-47e5-4569-814a-63aa38aef4b1','故殿撰侍郎趙公挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','惠國垂芳久，瀘南錫第初。',48,'全唐诗/poet.song.174000.json','["惠國垂芳久，瀘南錫第初。", "詩書今有此，衣鉢正關渠。", "業大喧朝野，儒酸羨里閭。", "只言三桂盛，五桂尚權輿。"]'),
('13a8b29a-d0b2-43e2-93ca-94827df23a3a','故殿撰侍郎趙公挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','邊鎖求良牧，京華倚重臣。',48,'全唐诗/poet.song.174000.json','["邊鎖求良牧，京華倚重臣。", "撫摩中有備，發擿靜無塵。", "效著龍顔動，班疑豹尾真。", "訃聞遺憾見，進秩有明綸。"]'),
('4c550e4d-a597-40ba-bc88-543fe3190185','故殿撰侍郎趙公挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','早歲燈窗密，中年宦海遥。',48,'全唐诗/poet.song.174000.json','["早歲燈窗密，中年宦海遥。", "相看嗟落寞，晚復共漁樵。", "已矣耆英會，居然一葉凋。", "豈無朋友念，人物歎公朝。"]'),
('fe32b356-a6d8-4488-bd61-9714d16f8bf6','後溪先生劉閣學挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','早際龍光渥，中更貝錦傷。',48,'全唐诗/poet.song.174000.json','["早際龍光渥，中更貝錦傷。", "升沈關運數，變故識忠良。", "天定當持國，時來倚幹方。", "至今羊叔子，名繞峴山傍。"]'),
('ee80a98d-b1f1-4396-8163-859221627b4a','後溪先生劉閣學挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','任重行吾道，憂心屬鉅公。',48,'全唐诗/poet.song.174000.json','["任重行吾道，憂心屬鉅公。", "三朝千載遇，一代數人中。", "筆健心猶壯，名高晚更穹。", "差肩誰許似，八秩有初終。"]'),
('8a14af7b-665c-4a53-a51c-d68259af2c4f','後溪先生劉閣學挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','憶奉巴西燕，工歌到鹿鳴。',48,'全唐诗/poet.song.174000.json','["憶奉巴西燕，工歌到鹿鳴。", "西清多學士，南省舊門生。", "屬耳靈光在，驚心砥柱傾。", "湖莊空望眼，讀記若爲情。"]'),
('1e3f7ddd-cff8-4558-8b85-ace73d40998f','總領戶部楊公挽詩  其一','曹彥約','宋','宋诗','song-poetry','','[]','華顯世儒業，循良今吏師。',48,'全唐诗/poet.song.174000.json','["華顯世儒業，循良今吏師。", "未應州縣薄，能簡廟堂知。", "沃轡歌周雅，含香問漢儀。", "經綸殊未展，曛景迫崦嵫。"]'),
('b397e566-a73f-4ae6-ba56-53121ef05e32','總領戶部楊公挽詩  其二','曹彥約','宋','宋诗','song-poetry','','[]','赬尾勞民久，青天轉粟艱。',48,'全唐诗/poet.song.174000.json','["赬尾勞民久，青天轉粟艱。", "三年流馬運，一笑狎鷗閒。", "天遠才多阨，功深報肯慳。", "勒銘周伏柱，何恨掩丘山。"]'),
('e0e78bc4-8b09-4525-a082-fa652ae37220','總領戶部楊公挽詩  其三','曹彥約','宋','宋诗','song-poetry','','[]','二昆同唱第，短世不堪言。',48,'全唐诗/poet.song.174000.json','["二昆同唱第，短世不堪言。", "生晚欣親炙，謙撝過撫存。", "里門重擁篲，秀野祇空園。", "零落西歸藁，誰能作九原。"]'),
('662dd1fb-a606-4453-a175-ebc37a5b2cf5','故經略華文趙郎中崇憲挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','國是歸宗相，儒科看嫡傳。',48,'全唐诗/poet.song.174000.json','["國是歸宗相，儒科看嫡傳。", "與時常落落，持論極拳拳。", "柄用無韓范，師承有澗瀍。", "衣冠何足論，父子世稱賢。"]'),
('b38d19c2-bc48-40bf-a029-6b7fab03bdd5','故經略華文趙郎中崇憲挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','出處權輕重，幾微見老成。',48,'全唐诗/poet.song.174000.json','["出處權輕重，幾微見老成。", "我官渾漫浪，公道要分明。", "忠定名先正，奸諛魄自驚。", "翻思元祐事，千古欠哀榮。"]'),
('df2b04a6-5c39-49d2-9ad0-f38423e86236','故經略華文趙郎中崇憲挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','世路平平好，民庸處處高。',48,'全唐诗/poet.song.174000.json','["世路平平好，民庸處處高。", "入朝寧却步，及物自忘勞。", "係望人宗主，爲儀國羽毛。", "修文纔下壽，天亦負英豪。"]'),
('47422357-0c34-4036-9482-f5c4ec49acd3','挽寧宗皇帝詞二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','百六消氛霧，東南立際蟠。',48,'全唐诗/poet.song.174000.json','["百六消氛霧，東南立際蟠。", "統傳三聖後，枕奠百年安。", "不識遊畋樂，深知稼穡難。", "何人青史上，敢作漢唐看。"]'),
('05111616-8f1b-4dbf-bda2-1da2deba281c','挽寧宗皇帝詞二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','混一開羣策，憂勤損萬年。',48,'全唐诗/poet.song.174000.json','["混一開羣策，憂勤損萬年。", "衣冠藏禹穴，歷數襲堯天。", "密定詒謀議，難留厭世仙。", "烏號攀莫及，有淚徹淵泉。"]'),
('f08678a9-f396-4165-b0dc-1b7d9ea11f3c','故丞相忠定趙沂公挽章三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','對策飛龍日，宗卿夙所期。',48,'全唐诗/poet.song.174000.json','["對策飛龍日，宗卿夙所期。", "時來人激烈，身定國危疑。", "一德三朝老，孤忠百世師。", "是非空貝錦，銘篆有鐘彝。"]'),
('e193d1f5-0f9e-4013-8aff-587dba639057','故丞相忠定趙沂公挽章三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','鹽筴寬閩甚，兵權慮蜀多。',48,'全唐诗/poet.song.174000.json','["鹽筴寬閩甚，兵權慮蜀多。", "閩民今可矣，蜀事竟如何。", "便好尸而祝，初無玷可磨。", "繄誰求徑捷，行陸强風波。"]'),
('02b28526-86f3-4d7c-8a05-33f47605da5b','故丞相忠定趙沂公挽章三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','譾譾羣情便，嶤嶤俗眼驚。',48,'全唐诗/poet.song.174000.json','["譾譾羣情便，嶤嶤俗眼驚。", "此身無利鈍，於國要忠誠。", "得力平生學，求仁死後名。", "登門非雅素，持論略公平。"]'),
('f7ec8f75-4118-44f2-9e21-8e6b9a15dd9b','戲集少陵句','曹彥約','宋','宋诗','song-poetry','','[]','山晚浮雲合，天寒鶬鴰呼。',48,'全唐诗/poet.song.174000.json','["山晚浮雲合，天寒鶬鴰呼。", "世人共鹵莽，行路日荒蕪。", "衰謝身何補，低垂氣不蘇。", "所過憑問訊，似欲慰窮途。"]'),
('6b4769bd-58d7-4086-b00b-54c52b3f504d','郭承禧同年解倅印趨朝  其一','曹彥約','宋','宋诗','song-poetry','','[]','昔在慈恩會，交新意已親。',48,'全唐诗/poet.song.174000.json','["昔在慈恩會，交新意已親。", "相逢游宦處，不比後來人。", "共度衡陽夏，平分嶽麓春。", "夤緣如此少，欲別倍傷神。"]'),
('840e30ed-12bb-4d42-9b8e-52490d2c71aa','郭承禧同年解倅印趨朝  其二','曹彥約','宋','宋诗','song-poetry','','[]','仕路何曾樂，迎親却是榮。',48,'全唐诗/poet.song.174000.json','["仕路何曾樂，迎親却是榮。", "諸公新引類，難弟久專城。", "便恐班朝著，無勞仗友生。", "長沙風月夜，炯炯自清明。"]'),
('5e9b0595-ab50-4a42-a667-1710e0d5a96e','張行父大監出鎮章貢艤舟來索詩','曹彥約','宋','宋诗','song-poetry','','[]','頗覺邅迴甚，由來去就輕。',48,'全唐诗/poet.song.174000.json','["頗覺邅迴甚，由來去就輕。", "坐曹雖冷淡，出位極精明。", "我老猶貪祿，君行已問程。", "虎頭雖好郡，朝路憶崢嶸。"]'),
('aa589027-5295-44eb-bc0b-57d4a2be0df7','中秋後一夕獨卧月臺','曹彥約','宋','宋诗','song-poetry','','[]','分得秋容半，添來爽氣深。',48,'全唐诗/poet.song.174000.json','["分得秋容半，添來爽氣深。", "靜中無罣礙，此處好登臨。", "老景當風卧，平生愛月心。", "幾回烏鵲動，曉色上平林。"]'),
('8b60e23f-b35c-47c6-8965-a1df3ffb4d4c','春到湖莊','曹彥約','宋','宋诗','song-poetry','','[]','飽綠勻楊柳，殷紅茁海棠。',48,'全唐诗/poet.song.174000.json','["飽綠勻楊柳，殷紅茁海棠。", "將春到昌谷，及早下湖莊。", "祠事三年樂，邊心萬里長。", "新來和氣好，吉報已占祥。"]'),
('50ded0c6-084a-4dab-8cce-bd5fe8bad1d2','奉濟驛次杜老送嚴公韻','曹彥約','宋','宋诗','song-poetry','','[]','奉濟傳芳久，當年折柳情。',48,'全唐诗/poet.song.174000.json','["奉濟傳芳久，當年折柳情。", "來賡工部句，去作錦官行。", "詩妙將安倣，吾衰及此榮。", "草堂修舊否，得見慰平生。"]'),
('43313dc5-1dcf-4147-9464-18459fc1b2c7','江村散步','曹彥約','宋','宋诗','song-poetry','','[]','已落無邊木，猶誅不盡茅。',48,'全唐诗/poet.song.174000.json','["已落無邊木，猶誅不盡茅。", "沙光迎遠景，風力閙寒稍。", "牧處高低路，漁時遠近郊。", "竹籬茅舍外，門閉可推敲。"]'),
('77fa5764-cc46-4e68-b38f-09c951e18e7f','晚晴','曹彥約','宋','宋诗','song-poetry','','[]','賸水浸秋碧，餘霞占晚紅。',48,'全唐诗/poet.song.174000.json','["賸水浸秋碧，餘霞占晚紅。", "浩歌鳴鶴後，柔櫓泛鷗中。", "酒戒情難遣，詩吟老未工。", "懷哉真面目，助順企清風。"]'),
('1713efab-4b9e-4975-b6a2-55e75ac13b31','聞道旁有死於賊者','曹彥約','宋','宋诗','song-poetry','','[]','義氣窮羣策，妖氛慘一隅。',48,'全唐诗/poet.song.174000.json','["義氣窮羣策，妖氛慘一隅。", "分憂吾弗職，殊死爾何辜。", "智者連千慮，天乎媿匹夫。", "諸軍猶請戰，此道不榛蕪。"]'),
('7c079e2f-bc8a-4dce-a81a-527c1e3dd151','送真希元侍郎得祠西歸','曹彥約','宋','宋诗','song-poetry','','[]','願治方凝竚，求歸竟得閒。',48,'全唐诗/poet.song.174000.json','["願治方凝竚，求歸竟得閒。", "空令如我輩，忍媿尚朝班。", "望重忠嘉上，身輕去就間。", "渺然人物慮，少壯亦衰顔。"]'),
('1d69a96b-bfe1-44d6-a62a-24cd07ee5dc7','紅梅','曹彥約','宋','宋诗','song-poetry','','[]','雪月共高寒，求多意未闌。',48,'全唐诗/poet.song.174000.json','["雪月共高寒，求多意未闌。", "林逋五品服，宋璟九還丹。", "老友松筠健，賢宗鼎鼐酸。", "任渠蜂蝶閙，難作武陵看。"]'),
('6ba07a4b-d5aa-457b-b9a7-71b6d260161b','暮春','曹彥約','宋','宋诗','song-poetry','','[]','春盡無何耳，客行猶及之。',48,'全唐诗/poet.song.174000.json','["春盡無何耳，客行猶及之。", "水光風約束，山貌雨矜持。", "物態從前好，官身到底癡。", "只言餐秀色，十口政憂饑。"]'),
('aa9e63ba-6f4e-4240-93be-155c524c6a1e','社日熱甚中夜得雨','曹彥約','宋','宋诗','song-poetry','','[]','蛆蟻開新盎，雞豚落社鍋。',48,'全唐诗/poet.song.174000.json','["蛆蟻開新盎，雞豚落社鍋。", "草衰秋水浄，木脫暮山多。", "顥氣時應爽，驕陽老更苛。", "依然霖雨在，暑酷要消磨。"]'),
('043f26ba-674b-4747-92f4-028187f60710','得雨','曹彥約','宋','宋诗','song-poetry','','[]','跼蹐民無地，焦熬歲不天。',48,'全唐诗/poet.song.174000.json','["跼蹐民無地，焦熬歲不天。", "雨方寬趙日，數已入湯年。", "調餉今方爾，蠲租恐未然。", "古來勳業盛，根本諱沉綿。"]'),
('c281dd97-9cfd-4fa9-b1aa-d5e23d8bab48','舟中連雨','曹彥約','宋','宋诗','song-poetry','','[]','客裏逢連雨，龍公不貸人。',48,'全唐诗/poet.song.174000.json','["客裏逢連雨，龍公不貸人。", "一蓬遮晦朔，萬慮入悲辛。", "忽忽淹吾道，堂堂送此春。", "誰歟訟風伯，揮掃鑑中塵。"]'),
('bfc13859-b64f-413d-a814-635a7df4cf36','盤谷胡季隨挽章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','天地開南學，葵軒接五峰。',48,'全唐诗/poet.song.174000.json','["天地開南學，葵軒接五峰。", "淳熙亡一鑑，盤谷有真蹤。", "庭立心傳鯉，門乘玉潤龍。", "風流遮不斷，堂斧若爲封。"]'),
('7946e3fc-ebb7-48bc-987d-612179efa0fd','盤谷胡季隨挽章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','我負光華遣，君從懇請來。',48,'全唐诗/poet.song.174000.json','["我負光華遣，君從懇請來。", "人如九鼎重，席爲百泉開。", "梁壞帡幪屋，星移絳帳臺。", "湘西明在眼，欲渡不堪哀。"]'),
('eec773e0-57f9-44a4-9222-b219ebdfc9b1','陳伯量挽詩二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','樸茂開城府，師資足楷模。',48,'全唐诗/poet.song.174000.json','["樸茂開城府，師資足楷模。", "官卑雖晚境，子仕却亨途。", "不酒陳驚座，無金疏大夫。", "何人碑有道，老手看慈湖。"]'),
('81fca253-e599-4ff9-96dd-866ac7de9d2b','陳伯量挽詩二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','我晚慚初學，公才又壯年。',48,'全唐诗/poet.song.174000.json','["我晚慚初學，公才又壯年。", "同盟覺山寺，共飲玉溪泉。", "薄宦身常隔，高懷骨易仙。", "傷心風作惡，不助過湖船。"]'),
('2018afa1-b5c8-40fa-a028-cf9e4e7c7463','趙知宗挽詩三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','壯日民師帥，中年國典刑。',48,'全唐诗/poet.song.174000.json','["壯日民師帥，中年國典刑。", "六分名郡竹，兩粲使華星。", "綵戲方娛侍，丹旌忽篆銘。", "空餘泉一滴，萬古歎清泠。"]'),
('3038ea2a-b86e-4c20-84dd-85aba49c0128','趙知宗挽詩三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','三桂先猷遠，公來應瑞芝。',48,'全唐诗/poet.song.174000.json','["三桂先猷遠，公來應瑞芝。", "子能傳世業，令欲徧孫枝。", "笏盛牀應滿，端闓橐已持。", "掛冠猶進秩，天意卜深知。"]'),
('db31dc4f-7506-4010-8d8d-2aa94f777c31','趙知宗挽詩三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','匯水誇同邑，桐江事事賢。',48,'全唐诗/poet.song.174000.json','["匯水誇同邑，桐江事事賢。", "骨寒誰與地，言重却牋天。", "游宦常千里，歸來共一川。", "西門今日路，忍淚入資延。"]'),
('a832795c-0c49-4ae0-9506-9c18a6dfb45b','彭師泰挽章','曹彥約','宋','宋诗','song-poetry','','[]','家世文爲富，居寒地不寒。',48,'全唐诗/poet.song.174000.json','["家世文爲富，居寒地不寒。", "諸昆親受業，二祖昔闓端。", "屬耳青雲杳，驚心逝水湍。", "後來方屹立，天不誤儒冠。"]'),
('2ad31401-179a-4b93-af3b-4d93833ff518','黄季通挽章','曹彥約','宋','宋诗','song-poetry','','[]','世務經心早，鄉評好弟昆。',48,'全唐诗/poet.song.174000.json','["世務經心早，鄉評好弟昆。", "但爲三徑樂，無間一家言。", "已作賢關夢，爭如藻鑑冤。", "霜嚴中夏發，桑柘老南園。"]'),
('5dec4cf3-4958-48f8-8539-a97e7dea6550','讀乞歸不允詔','曹彥約','宋','宋诗','song-poetry','','[]','有赫絲綸寵，空貽老病羞。',48,'全唐诗/poet.song.174000.json','["有赫絲綸寵，空貽老病羞。", "命從今日下，事比去年愁。", "已向祠官去，猶爲講席留。", "誰知蝴蝶夢，栩栩到吾州。"]'),
('33a168a2-2a00-40d9-8eaa-0cc88a4e4943','課園丁洗竹','曹彥約','宋','宋诗','song-poetry','','[]','種竹年華晚，新添數百竿。',48,'全唐诗/poet.song.174000.json','["種竹年華晚，新添數百竿。", "低垂非我好，冗長要人刪。", "直節心期露，疎行眼界寬。", "從茲風月夜，清白足相安。"]'),
('0d2edb9e-af3d-48ec-a87d-51f397a47ed8','邵武趙使君挽章二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','近代金枝裏，何人桂籍傳。',48,'全唐诗/poet.song.174000.json','["近代金枝裏，何人桂籍傳。", "祖孫三世盛，文武兩科全。", "日月開宏業，山川哭盛年。", "天高無可問，有德在民編。"]'),
('7ebe0524-cdd1-491d-b6bd-f32f785802d4','邵武趙使君挽章二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','脫白同辛丑，蒼黄共丙寅。',48,'全唐诗/poet.song.174000.json','["脫白同辛丑，蒼黄共丙寅。", "京華誇俊逸，鄂渚話酸辛。", "謂上樵川最，還登要路津。", "鄰牆摧一柱，歲晚倍傷神。"]'),
('2fe7d544-ebc5-4c0b-8865-f725a309df33','道中遣興','曹彥約','宋','宋诗','song-poetry','','[]','游宦何曾樂，佳時又出門。',48,'全唐诗/poet.song.174000.json','["游宦何曾樂，佳時又出門。", "春深花處處，社近鼓村村。", "天地一羈旅，江山千吐吞。", "平生黄嬭誤，今日麴生尊。"]'),
('333df438-df92-4be3-9a6a-144bec978fdd','潘景泰知縣挽章','曹彥約','宋','宋诗','song-poetry','','[]','甚矣吾衰久，猶能誄故人。',48,'全唐诗/poet.song.174000.json','["甚矣吾衰久，猶能誄故人。", "愛賢高贊畫，造士憶同寅。", "道喪慳人物，才難泣搢紳。", "頗聞蘭玉秀，天不誤儒身。"]'),
('d35a2aba-55b6-413c-b502-4f0d9f49748b','岳德器遠來見訪袖出六年前所賦湖莊詩次韻答之','曹彥約','宋','宋诗','song-poetry','','[]','巴蜀歸才子，江湖枉使車。',48,'全唐诗/poet.song.174000.json','["巴蜀歸才子，江湖枉使車。", "久吟工部句，新寄子公書。", "面對花應笑，眉開柳爲舒。", "苦無杯酒暇，人事正紛如。"]'),
('fc271426-469b-48a4-a5b5-c5e705f0676f','羣山閣','曹彥約','宋','宋诗','song-poetry','','[]','萬里雲萍一酉陽，便將和氣壓荒凉。',64,'全唐诗/poet.song.174000.json','["萬里雲萍一酉陽，便將和氣壓荒凉。", "挽回梅萼依明燭，管領椒花入壽觴。", "笑裏不知熊軾重，醉餘猶記博山香。", "只因臘雪成佳集，等到春來味更長。"]'),
('4b55f371-5ac6-4919-a47a-509cb6fc32ba','雨後早行','曹彥約','宋','宋诗','song-poetry','','[]','鼓鉦攢點擔先行，未報平安睡已驚。',64,'全唐诗/poet.song.174000.json','["鼓鉦攢點擔先行，未報平安睡已驚。", "燈火避明天弄曉，鳥烏無樂雨慳晴。", "喚來野渡水新漲，飽得晨炊煙自橫。", "驛使嶺頭無一信，筍輿咿軋强貪程。"]'),
('5ad0cbba-67f6-43ee-b7c2-c211570cdb3c','和西園胡季履見寄  其一','曹彥約','宋','宋诗','song-poetry','','[]','衣冠葉葉著師儒，創見皇家異代無。',64,'全唐诗/poet.song.174000.json','["衣冠葉葉著師儒，創見皇家異代無。", "前事盛哉申國呂，近時繼者武夷胡。", "累朝經學堪貽厥，三世名家列友于。", "莫道新來凋一萼，西園老柏更清癯。"]'),
('bffc3af9-1dfc-4b8c-9af3-73c1dd8583b7','和西園胡季履見寄  其二','曹彥約','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','百年幾見弦三歎，萬事相違臂一交。',64,'全唐诗/poet.song.174000.json','["百年幾見弦三歎，萬事相違臂一交。", "道合不知身隠見，詩來如見手推敲。", "我儀圖此藏周廟，人實云何滯楚包。", "無奈廬山歸夢急，遣書空報白雲巢。"]'),
('22b377ab-285e-425e-be7b-79e22ba8351a','飲良父弟橫舟','曹彥約','宋','宋诗','song-poetry','','[]','簿書日月費消磨，華鄂歸來樂事多。',64,'全唐诗/poet.song.174000.json','["簿書日月費消磨，華鄂歸來樂事多。", "已涉一川舟自在，相安衆口麴平和。", "人生正好乘流止，塵世相逢對酒歌。", "欲泛五湖真浪語，浮家猶足鎮風波。"]'),
('f5085051-f5ce-49c6-b64c-76d074b51fb2','連雨中買歸舟','曹彥約','宋','宋诗','song-poetry','','[]','泛菊囊萸事已休，光陰無脚駛如流。',64,'全唐诗/poet.song.174000.json','["泛菊囊萸事已休，光陰無脚駛如流。", "更無出入消磨雨，只有悲凉斷送秋。", "戴屋未停持繖手，買舟先辦打篷頭。", "懸知明鏡重飛處，昵昵燈前問鄂州。"]'),
('d42f8a78-c012-45bf-973d-ada2ac69820b','迎寺丞舅歸舟','曹彥約','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','桂林使者赤松人，爭得匡廬自在身。',64,'全唐诗/poet.song.174000.json','["桂林使者赤松人，爭得匡廬自在身。", "蟬蛻一官驚俗子，鸛鳴雙艣壓江神。", "人生到此方爲樂，世路新來可具陳。", "開盡朱門無鎖鑰，滿城桃李萬家春。"]'),
('3aa714cf-7afb-40c2-a563-7ab25efcc456','送雷赴漕召  其一','曹彥約','宋','宋诗','song-poetry','','[]','詔書隠隠下穹窿，已覺朝廷後此翁。',64,'全唐诗/poet.song.174000.json','["詔書隠隠下穹窿，已覺朝廷後此翁。", "儒雅久稱唐吏部，典刑今對漢申公。", "薰風使者驅馳外，暇日斯民長養中。", "麥隴秧田政如許，定應歸報不言功。"]'),
('78517911-5062-4082-b415-cccf8b4f3557','送雷赴漕召  其二','曹彥約','宋','宋诗','song-poetry','','[]','幾年分閫作遨頭，又擁皇華歲兩周。',64,'全唐诗/poet.song.174000.json','["幾年分閫作遨頭，又擁皇華歲兩周。", "豈有休聲勤注倚，尚持英簜但咨諏。", "只今衮職須誰補，自古官身可自由。", "相業青徐寧有定，好將功業張吾州。"]'),
('db3160c6-5b47-4797-8b6f-071b0cac64a4','送雷赴漕召  其三','曹彥約','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','我生雖晚亦匡廬，得見先生喜有餘。',64,'全唐诗/poet.song.174000.json','["我生雖晚亦匡廬，得見先生喜有餘。", "止爲包荒安邸舍，敢將入幕論鄉閭。", "一官貪祿無他望，四海安身即定居。", "幽谷若因明主問，莫言臣邑有相如。"]'),
('87f08e5a-3d47-422a-80d8-b868dce78622','送蕭季然倅均州','曹彥約','宋','宋诗','song-poetry','','[]','持家遠與立朝同，善繼何人似迺翁。',64,'全唐诗/poet.song.174000.json','["持家遠與立朝同，善繼何人似迺翁。", "國史但書蕭傅直，鄉評更仰伯夷風。", "只今邊備艱難際，自古官箴謹飭中。", "四袠親朋今健者，尚看褒詔詫江東。"]'),
('e502356c-9cee-4591-8460-73894e64f219','送綿竹王主簿','曹彥約','宋','宋诗','song-poetry','','[]','渴想才名不計年，得詩甜處徹中邊。',64,'全唐诗/poet.song.174000.json','["渴想才名不計年，得詩甜處徹中邊。", "知君眼裏藏青白，託意盃中別聖賢。", "萬里偶逢多幸耳，一朝相別兩茫然。", "榮歸蜀道川涂穩，莫漫嚱吁信謫仙。"]'),
('e1ba658e-3cf3-4130-8fd4-0419deac17f0','送趙主簿','曹彥約','宋','宋诗','song-poetry','','[]','新詩燕婉似花繁，好在鵷行接羽翰。',64,'全唐诗/poet.song.174000.json','["新詩燕婉似花繁，好在鵷行接羽翰。", "一笑相逢江海客，三年猶老簿書官。", "見聞我闕猶干祿，矍鑠君能欲據鞍。", "却似岑參寮友會，陽春一曲和皆難。"]'),
('880a128e-3f0e-40c4-9bdf-856187d89d55','送易彥章以太學正召','曹彥約','宋','宋诗','song-poetry','','[]','涵養書生二百春，爲渠文物有經綸。',64,'全唐诗/poet.song.174000.json','["涵養書生二百春，爲渠文物有經綸。", "只今領袖賢關地，疇昔錙銖舍法人。", "吾道年來多落落，士風從此却彬彬。", "不應小折陳蕃角，謾謂朝家棄直臣。"]'),
('c72e1314-d2ec-4d31-90b0-f16dcb4c2820','爲謝府題製錦堂','曹彥約','宋','宋诗','song-poetry','','[]','錦江新製奪春妍，物采名堂意曉然。',64,'全唐诗/poet.song.174000.json','["錦江新製奪春妍，物采名堂意曉然。", "應有五紋供帝衮，曾無一縷費民編。", "年來撫字誰高手，古道循良此比肩。", "經緯一同餘事耳，清朝晝繡說家傳。"]'),
('0a1d3f72-2515-44d9-a85a-be3cc1d161e1','漫成寄朱伯海主簿','曹彥約','宋','宋诗','song-poetry','','[]','幸拜恩綸强自寬，窮居寒士忝微官。',64,'全唐诗/poet.song.174000.json','["幸拜恩綸强自寬，窮居寒士忝微官。", "風霜迢遞踰千里，晨夕間關歷萬端。", "一片山城常寂寞，幾宵燈火憶團欒。", "當年別後傷心處，極目君峰草木寒。"]'),
('3558cec9-7727-4677-be69-4def4358975d','陪總卿路鈐相麥觀花修出郊故事','曹彥約','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','二月春光最惱人，不禁春惱更尋春。',64,'全唐诗/poet.song.174000.json','["二月春光最惱人，不禁春惱更尋春。", "關心秀入青青隴，適意紅臨灧灧津。", "開闔雨晴天氣巧，鋪張桃李世情均。", "病夫已作廬山夢，尚擁籃輿託後塵。"]'),
('bfb09c71-5675-44b5-8188-57151dcaf2b6','秋日出郊','曹彥約','宋','宋诗','song-poetry','','[]','早是清和便束裝，只今庭葉報新凉。',64,'全唐诗/poet.song.174000.json','["早是清和便束裝，只今庭葉報新凉。", "山應險盡饒寬大，水欲平來尚激昂。", "已服官常猶潦草，未紓民力要商量。", "鮮于司馬經行處，文物彬彬意緒長。"]'),
('0dc136c5-42f6-429d-b510-d300f6e0a163','送湖口尉王德高解印東歸','曹彥約','宋','宋诗','song-poetry','','[]','笑解龜符指鄭鄉，應從鳳口得書忙。',64,'全唐诗/poet.song.174000.json','["笑解龜符指鄭鄉，應從鳳口得書忙。", "平生璧水功名志，壯歲鍾山姓字香。", "惡少何人窺甕牖，長官無事燕琴堂。", "從今我亦南州吏，乞取梅仙已驗方。"]'),
('fe13746c-f50c-4620-a4aa-ced128edde0d','程宰虞簿和縣庠老桂詩見貽再賦以謝','曹彥約','宋','宋诗','song-poetry','','[]','風流人物冠瀛寰，折桂曾驚咫尺顔。',64,'全唐诗/poet.song.174000.json','["風流人物冠瀛寰，折桂曾驚咫尺顔。", "肯賦摽梅深有味，已標仙籍正相關。", "一枝笑入絃歌裏，千古名傳俎豆間。", "欲攪枯腸追妙語，飛來雙鶴杳難攀。"]'),
('84cc964f-7fe3-4c4e-ad36-df97fbfda558','龍游道中即事','曹彥約','宋','宋诗','song-poetry','','[]','幾年舟楫便吾曹，步入龍游記所遭。',64,'全唐诗/poet.song.174000.json','["幾年舟楫便吾曹，步入龍游記所遭。", "激水代舂城旦坐，叉松親爨店人勞。", "屏除車馬肩輿冗，料理泥沙甃甓高。", "忙裏著晴天意好，坐令行客興滔滔。"]'),
('5929b04c-f926-4be6-af53-502658f63382','送臘','曹彥約','宋','宋诗','song-poetry','','[]','謂向年前稍自寬，惱人時序故多端。',64,'全唐诗/poet.song.174000.json','["謂向年前稍自寬，惱人時序故多端。", "幾回水落還添浦，百樣天晴却轉寒。", "未有梅開供探討，若無酒遣太衰殘。", "明朝便是春來處，暖律丁寧著眼看。"]'),
('77fc64c1-c0cb-49ec-a801-03f05b402257','家本譙人得奉祠亳州喜賦述懷','曹彥約','宋','宋诗','song-poetry','','[]','宦游隨喜亦云聊，筆橐何官晚見招。',64,'全唐诗/poet.song.174000.json','["宦游隨喜亦云聊，筆橐何官晚見招。", "已定秦關無論蜀，好恢湯亳却歸譙。", "雪邊廬嶽雲千嶺，雨後湖莊水一腰。", "買得扁舟能著我，便無西子也逍遥。"]'),
('af5c5c61-8760-4d1d-8b54-d2ca04c197fd','送錢文季國博赴召  其一','曹彥約','宋','宋诗','song-poetry','','[]','每向招賢看典刑，中間人物似零丁。',64,'全唐诗/poet.song.174000.json','["每向招賢看典刑，中間人物似零丁。", "只因朋黨排諸老，無復紛綸任五經。", "一節何如歸帝所，賜環元不爲郎星。", "古來官職論車斗，只有忠嘉可篆銘。"]'),
('740a2e27-51fe-4de7-b392-9c0de33636ef','送錢文季國博赴召  其二','曹彥約','宋','宋诗','song-poetry','','[]','衝暑相迎慰寂寥，忍寒爲別助蕭條。',64,'全唐诗/poet.song.174000.json','["衝暑相迎慰寂寥，忍寒爲別助蕭條。", "笑談但喜頻揮麈，夢想何嘗到續貂。", "已辦犁鋤供老圃，尚乘軺傳託公朝。", "班聯若問官聯舊，說與思歸不自聊。"]'),
('7d04f863-9e05-481a-81e6-6e34d16809cb','春到湖莊','曹彥約','宋','宋诗','song-poetry','','[]','堤南堤北水溶溶，旁倚羣山不礙風。',64,'全唐诗/poet.song.174000.json','["堤南堤北水溶溶，旁倚羣山不礙風。", "收拾田園供老境，栽培桃李課新功。", "牆頭向長千章聳，潤下潛流一線通。", "脚力尚堪行樂在，年來天不負衰翁。"]'),
('dcfd5b57-cab8-4369-889d-83f395806af0','湖莊述懷  其一','曹彥約','宋','宋诗','song-poetry','','[]','昌谷喧聲漸屏除，湖莊新意亦空疎。',64,'全唐诗/poet.song.174000.json','["昌谷喧聲漸屏除，湖莊新意亦空疎。", "遠栽夏木來鳴鳥，短截寒谼縱小魚。", "架有空籤聊貯藥，樓無他用只儲書。", "病來得惰因成趣，此外於人百不如。"]'),
('ccc7f569-c4b6-401f-ab29-00606018dee1','湖莊述懷  其二','曹彥約','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','門無賓客愧朋儕，冷淡何人諒此懷。',64,'全唐诗/poet.song.174000.json','["門無賓客愧朋儕，冷淡何人諒此懷。", "隨意作詩無唱和，等閒沽酒不安排。", "每扶短杖行方穩，欲泛扁舟計未諧。", "訪得廬山與彭蠡，不論晴日雜陰霾。"]'),
('104cc6d1-373d-4253-ad1b-8995e11844e7','湖莊春晚','曹彥約','宋','宋诗','song-poetry','','[]','栽種成陰恰十年，水光山色靜無邊。',64,'全唐诗/poet.song.174000.json','["栽種成陰恰十年，水光山色靜無邊。", "杏桃賞徧春容老，松竹添多晚力堅。", "向有味中求冷淡，好寬懷處且盤旋。", "干戈漸說邊塵息，朽木因依得晝眠。"]'),
('cc5abf18-bd15-47ec-b688-64cba6de14e1','使君領客訪湖莊分簡齋茂林當日映羣賢之句得羣字','曹彥約','宋','宋诗','song-poetry','','[]','風流人物總能文，洗我榛蕪久離羣。',64,'全唐诗/poet.song.174000.json','["風流人物總能文，洗我榛蕪久離羣。", "意氣掃除投老障，浩歌驚起住山雲。", "風迎小隊春三月，天與湖莊景十分。", "七子賦詩皆寵武，刳腸猶不報慇懃。"]'),
('0899efdb-7c16-4190-9529-58725c377d39','九日領諸子同季明泛舟之湖莊','曹彥約','宋','宋诗','song-poetry','','[]','爲酬佳節訪江臯，短棹能寬脚力勞。',64,'全唐诗/poet.song.174000.json','["爲酬佳節訪江臯，短棹能寬脚力勞。", "把菊未遑憂歲惡，愛松相與歎風饕。", "雨餘得水三湖闊，天靜無塵九疊高。", "老病不將詩領會，新來能賦屬兒曹。"]'),
('3e37a9dc-1b6b-46f2-897e-7854006d2230','十月一日陪使君領客之湖莊','曹彥約','宋','宋诗','song-poetry','','[]','鸛鳴雙艣壓中流，斷送餘分不盡秋。',64,'全唐诗/poet.song.174000.json','["鸛鳴雙艣壓中流，斷送餘分不盡秋。", "石罅有聲轟壯語，風驕無計尼真游。", "江神自合供如願，艇子尤能送莫愁。", "却笑湖莊真落莫，但留斜日照歸騶。"]'),
('99b523ec-e943-4339-a8e5-4b9f64df2df4','送權次翁赴湖北計幕','曹彥約','宋','宋诗','song-poetry','','[]','萬竈貔貅趣上邊，皇華新遣墨猶鮮。',64,'全唐诗/poet.song.174000.json','["萬竈貔貅趣上邊，皇華新遣墨猶鮮。", "何人共了飛芻事，有客同稱入幕賢。", "舉酒便驚分袂處，掛帆直到賞音前。", "不妨勳業高前哲，却與山寮作後編。"]'),
('f3e6f6ca-64c3-42b1-82c4-308928b4dd22','送章致遠賢良赴招撫司機幕','曹彥約','宋','宋诗','song-poetry','','[]','窮經知國更知兵，梁楚中間播此聲。',64,'全唐诗/poet.song.174000.json','["窮經知國更知兵，梁楚中間播此聲。", "唐幕亟招溫處士，漢廷徐策董先生。", "平時未識人賢否，用處方關國重輕。", "露布便多機事少，寄書因到武昌城。"]'),
('5e4153db-a191-47b9-b4bb-b571bdbae1c0','答傅憲','曹彥約','宋','宋诗','song-poetry','','[]','妙語差肩落燕泥，亨塗驤首化龍堤。',64,'全唐诗/poet.song.174000.json','["妙語差肩落燕泥，亨塗驤首化龍堤。", "敢酬閣老慚非杜，適見夷吾不爲齊。", "趣覲可無三節召，送行那有一錢齎。", "功名自是平生志，旃罽爲庭正可犁。"]'),
('98ad7c05-fae2-49c2-97a9-de26b9efebd4','次耿令君藥名韻','曹彥約','宋','宋诗','song-poetry','','[]','賦分微官即忍冬，衣單無計可防風。',64,'全唐诗/poet.song.174000.json','["賦分微官即忍冬，衣單無計可防風。", "四方遠志從頭去，一水空青到底窮。", "地骨自寒誰與祛，天門欲到愧無功。", "是誰直上凌羊角，却更從容使脫空。"]'),
('6d7d4d9e-7dc1-43b9-a6ba-613f3dd562f6','再次韻熟藥名','曹彥約','宋','宋诗','song-poetry','','[]','善保生經莫怨冬，心存和氣自消風。',64,'全唐诗/poet.song.174000.json','["善保生經莫怨冬，心存和氣自消風。", "誰能聚寶徒誇富，粗有千金不訴窮。", "未許二仙爲聖散，且將一字見神功。", "何時相對清凉飲，越舞齊謳酒不空。"]'),
('75cc588c-c9b4-41ff-b01f-87b8f4fc5819','雨雪中歲享卧病不能陪位令諸子代拜','曹彥約','宋','宋诗','song-poetry','','[]','歲事無多世事忙，病夫終日卧藤牀。',64,'全唐诗/poet.song.174000.json','["歲事無多世事忙，病夫終日卧藤牀。", "雪積易消春已近，雨來無節晝偏長。", "朝儀尚想三迴舞，歲享難持一瓣香。", "莫道蓋棺便無事，義方猶欲訓諸郎。"]'),
('65c8284b-0612-4e2e-8256-4d1154d281c8','首春課湖莊種植','曹彥約','宋','宋诗','song-poetry','','[]','買橘求杉答履端，尚虞霜雪重遮闌。',64,'全唐诗/poet.song.174000.json','["買橘求杉答履端，尚虞霜雪重遮闌。", "桃蹊上下全鋤麥，梅嶺中邊雜藝蘭。", "鉅竹栽成千百箇，野花留取兩三般。", "生平只有田園樂，晝短還須秉燭看。"]'),
('96a984a7-d73d-4f17-8caa-3528ac830df8','師繹再賦湖莊雨後佳句有惜春之意復次其韻','曹彥約','宋','宋诗','song-poetry','','[]','委曲東風滿萬家，家培桃李恣雄誇。',64,'全唐诗/poet.song.174000.json','["委曲東風滿萬家，家培桃李恣雄誇。", "先生客裏觀時態，老子詩中感物華。", "雨後有花須領略，春歸無策可攔遮。", "山行忘却芳菲趣，把玩珠璣到日斜。"]'),
('d91383c3-7e14-4ee2-811e-c6ae25f7d5fc','子山見和去年湖莊春晚詩仍次前韻','曹彥約','宋','宋诗','song-poetry','','[]','筆硯論交半百年，中間摇落更臨邊。',64,'全唐诗/poet.song.174000.json','["筆硯論交半百年，中間摇落更臨邊。", "尋盟花木春猶在，結友松筠晚益堅。", "雪霽萬峰開紫翠，江空一水恣回旋。", "何時共我湖莊樂，醒後吟詩醉後眠。"]'),
('96379811-56ed-4080-aede-0e064b934b8d','明之亦和詩來復次前韻','曹彥約','宋','宋诗','song-poetry','','[]','當年莫逆尚忘年，今日霜蓬入鬢邊。',64,'全唐诗/poet.song.174000.json','["當年莫逆尚忘年，今日霜蓬入鬢邊。", "已歃花盟猶習惰，驟迎詩敵敢攻堅。", "依棲有幸烏南繞，會合難并蟻左旋。", "著我畫圖添李邵，丹青那復起龍眠。"]'),
('4bd9f804-75a1-4dcc-84e4-39de3e87fd29','師繹諾湖莊之約畏風色不果來以詩見餉次其韻','曹彥約','宋','宋诗','song-poetry','','[]','宴集慚非左氏莊，妄行村落似猖狂。',64,'全唐诗/poet.song.174000.json','["宴集慚非左氏莊，妄行村落似猖狂。", "人生適意真難遇，天意慳晴未易量。", "可但客衣吹杲杲，只愁春色去堂堂。", "輟行句好猶追逐，駑蹇奔波怯乘黄。"]'),
('c677552e-e084-446e-9e52-9b160ad00d1f','送魏使君歸宛陵二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','姓名久已御屏間，合上鋒車入帝關。',64,'全唐诗/poet.song.174000.json','["姓名久已御屏間，合上鋒車入帝關。", "豈有薦書喧筆橐，但留聲價惠江山。", "簿書袖手詩還在，出處忘情意自閒。", "不分愛江樓下水，隔人無計可追攀。"]'),
('f06d359a-7db4-4cf3-a65f-2148ab4a92ca','送魏使君歸宛陵二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','我無郡績合歸與，君有時名孰舍諸。',64,'全唐诗/poet.song.174000.json','["我無郡績合歸與，君有時名孰舍諸。", "其事頗同人頗異，此心相照亦相疎。", "一時風力天容改，後夜月華雲氣舒。", "同是江南易回首，人來多寄一行書。"]'),
('b07d9d13-bf42-493c-acce-9c80a01c9cc2','次韻葛丞至節見邀踏雪','曹彥約','宋','宋诗','song-poetry','','[]','照人好語妙陽臺，佳節相隨七日來。',64,'全唐诗/poet.song.174000.json','["照人好語妙陽臺，佳節相隨七日來。", "甚欲去陪桃竹杖，可憐消盡豆稭灰。", "喜君天上星辰次，贈我人間錦繡堆。", "小試平章和氣動，他年台鼎要鹽梅。"]'),
('2bed3ed9-80da-4401-9dee-5ace3cc9e7e0','和衮子冰詩','曹彥約','宋','宋诗','song-poetry','','[]','畏折綿霜已不勝，加工寒裏立威棱。',64,'全唐诗/poet.song.174000.json','["畏折綿霜已不勝，加工寒裏立威棱。", "爭明日月天無色，遏住江湖曉作層。", "欲倚爲山憂晛見，不如吟柱得詩能。", "規恢可但滹沱事，只任賢能也中興。"]'),
('b248e915-9707-4b98-b9ed-e2a228d04b93','鹿鳴小集奉餞赴省諸公','曹彥約','宋','宋诗','song-poetry','','[]','便從場屋了經綸，看取朝家詔選掄。',64,'全唐诗/poet.song.174000.json','["便從場屋了經綸，看取朝家詔選掄。", "天賦忠良須努力，人生溫飽豈榮身。", "鼎來時事方憂國，到底儒冠不誤人。", "青紫拾來餘事耳，直應尊主庇斯民。"]'),
('0282af39-336a-47b4-a936-accc54d8ffbe','昌化朱浪潘子雲漢臣季子也漢臣既物故持其季父聖與詩來因問堪村徐季登其健如昔昔戊戌省試後道出昌化館于漢臣一日同訪季登遇榜下第于渡口今三紀矣因子雲告別有感前事作此章以餞之爲我謝聖與兼簡季登','曹彥約','宋','宋诗','song-poetry','','[]','朱浪山春啼杜鵑，溪南溪北刺舠船。',64,'全唐诗/poet.song.174000.json','["朱浪山春啼杜鵑，溪南溪北刺舠船。", "人生幾度年三十，世路重逢事百千。", "客已倦游今老矣，君須揖別故凄然。", "從容有問居閒意，爲說湖莊水一川。"]'),
('659fcf0d-3aa3-4525-b490-f5141aaa2b2a','送陳彥功入都','曹彥約','宋','宋诗','song-poetry','','[]','握手論心九歷年，中間多難不堪傳。',64,'全唐诗/poet.song.174000.json','["握手論心九歷年，中間多難不堪傳。", "相親幕府分襟後，說到銅官製錦前。", "訪我田園猶命駕，愛賢時節好加鞭。", "別懷莫問書疎數，老病無端日晝眠。"]'),
('15b34875-ebae-4383-86c6-85bcb15c22cc','方孚若惠端溪硯','曹彥約','宋','宋诗','song-poetry','','[]','不宜磨墨謾論車，風字偏坳玉斗斜。',64,'全唐诗/poet.song.174000.json','["不宜磨墨謾論車，風字偏坳玉斗斜。", "喜有山靈藏舊物，幻成蟾影照圓沙。", "活鸜眼好童謠誤，死馬肝真帝語賒。", "辜負海深天闊樣，玉堂何似竹籬家。"]'),
('6d61df61-ffc2-414e-86b2-5e23dcd2c4fe','題漢李固太尉廟','曹彥約','宋','宋诗','song-poetry','','[]','生死忠邪未易窮，其如國脈是非中。',64,'全唐诗/poet.song.174000.json','["生死忠邪未易窮，其如國脈是非中。", "誰知刺骨翻爲福，不念捐軀有此忠。", "一日太阿歸跋扈，百年黄鉞授姦雄。", "不然彼亦何爲者，敢肇兵端起鄴宮。"]'),
('350a2c18-58fb-4b98-ab7e-78b7c8591eda','同兒輩食雪和兗子韻','曹彥約','宋','宋诗','song-poetry','','[]','天然高潔淡爲真，似蜜增甜亦可人。',64,'全唐诗/poet.song.174000.json','["天然高潔淡爲真，似蜜增甜亦可人。", "不分瑶花驚俗眼，更招瓊液到吾唇。", "取來酒後團欒夜，壓盡人間瘴癘春。", "遥想嚼氈清到骨，古來持節要忠臣。"]'),
('40079811-e698-4491-b858-2b3c6758975b','子敬見和食雪詩仍次前韻','曹彥約','宋','宋诗','song-poetry','','[]','色如姑射未全真，消得新詩膾炙人。',64,'全唐诗/poet.song.174000.json','["色如姑射未全真，消得新詩膾炙人。", "冰不待藏須潔齒，凍何須解要濡唇。", "烹茶尚有虀鹽味，食蘗難誇麴米春。", "賸欲清凉非內熱，不應宴賞羨諸臣。"]'),
('a8a38d12-d8f7-42a5-80d1-3af0c893f5b0','病中有感欲落不落雪舊事偶成唐律','曹彥約','宋','宋诗','song-poetry','','[]','東皇雅欲破玄冥，滕六終懷可否情。',64,'全唐诗/poet.song.174000.json','["東皇雅欲破玄冥，滕六終懷可否情。", "豈不願豐招瑞氣，又虞加力困饑氓。", "柳雖閣絮心猶壯，梅不能粧意自傾。", "只恐玉龍禁不得，便輸鱗甲賦羣英。"]'),
('84aeae2a-fd94-483c-a8e9-632a7d87826a','驚蟄後雪作未已阻之湖莊','曹彥約','宋','宋诗','song-poetry','','[]','甲拆多應滿藥欄，跨騾心已拂輕鞍。',64,'全唐诗/poet.song.174000.json','["甲拆多應滿藥欄，跨騾心已拂輕鞍。", "正疑陰固仍飛雪，豈有春中却沍寒。", "啟蟄候蟲猶自閉，向陽梅子自能酸。", "誤成嚴冷非天意，說與人心作好看。"]'),
('c662231b-54ac-48f7-ad60-a0cb9de6ef44','登復州城','曹彥約','宋','宋诗','song-poetry','','[]','李子園邊水滿洲，當年桑土欠綢繆。',64,'全唐诗/poet.song.174000.json','["李子園邊水滿洲，當年桑土欠綢繆。", "城分南北平腰束，湖號東西拍面浮。", "馬健獨能全上幕，水清元不污賢侯。", "滿城山色春何在，小立無言萬象秋。"]'),
('a2535817-e1e5-44be-87fc-0be49db5951d','見梅有感','曹彥約','宋','宋诗','song-poetry','','[]','莫把夭妍等重輕，賦成千韻况難名。',64,'全唐诗/poet.song.174000.json','["莫把夭妍等重輕，賦成千韻况難名。", "看來好處非因色，敢向春前似有情。", "奈老不成三弄笛，濟時還擬一杯羹。", "清標實用何人可，只合差肩宋廣平。"]'),
('ffac0cc9-0be4-4197-b1c5-6684dd335eb7','次仁季詠梅韻','曹彥約','宋','宋诗','song-poetry','','[]','誤分符竹建星臺，官事縈心不到梅。',64,'全唐诗/poet.song.174000.json','["誤分符竹建星臺，官事縈心不到梅。", "粉面莫驚公主艷，鐵心曾對廣平開。", "託身冰雪剛而栗，取友松筠晚不回。", "已向箇中懷鼎味，直須魁占百花來。"]'),
('a0c56fce-8eb0-470f-8ea4-9f5190a23db8','再次仁季詠梅韻  其一','曹彥約','宋','宋诗','song-poetry','','[]','衙官桃李列芳臺，豈有凡花敢並梅。',64,'全唐诗/poet.song.174000.json','["衙官桃李列芳臺，豈有凡花敢並梅。", "雅健巧妨羣動息，參差能作數番開。", "爭先照眼春無限，索笑關心日幾回。", "莫道暗香非是雪，許多蜂蝶不知來。"]'),
('82a0f54a-8f25-496e-8783-20ee53fde472','再次仁季詠梅韻  其二','曹彥約','宋','宋诗','song-poetry','','[]','水邊得月共樓臺，此處風光可認梅。',64,'全唐诗/poet.song.174000.json','["水邊得月共樓臺，此處風光可認梅。", "萬態爭如疎影好，一尊何惜笑顔開。", "東君爲爾饒先著，俗子逢之倒射回。", "莫恨隴寒無驛使，江南衝暖望歸來。"]'),
('336d09e1-d1ee-4b86-b327-de3aaf3908f9','仁季再賦亦再賦二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','昔年遠訪鬰孤臺，止渴曾詢庾嶺梅。',64,'全唐诗/poet.song.174000.json','["昔年遠訪鬰孤臺，止渴曾詢庾嶺梅。", "別後只從忙裏過，到今多見旅中開。", "是非汩沒身添老，寒暑侵陵首屢回。", "却憶故園松竹外，朔風吹雪亞枝來。"]'),
('84d3ba29-1ec0-4c54-8c0a-4b3c82f04f0e','仁季再賦亦再賦二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','何物清高稱月臺，雪天佳客照江梅。',64,'全唐诗/poet.song.174000.json','["何物清高稱月臺，雪天佳客照江梅。", "謝家玉樹庭前發，后土瓊花歲裏開。", "朝日何郎吟未徹，晚風姑射宴方回。", "橫拋珠玉人間世，只恐花神駕鶴來。"]'),
('1c966449-b3fa-481a-8ccc-49a04576d12e','章泉言語妙天下知僕無詩能且未識面乃時以佳篇見餉何也不敢再虛盛意勉次韻二篇以謝  其一','曹彥約','宋','宋诗','song-poetry','','[]','珍重章泉辱寄書，應疑不復夢康廬。',64,'全唐诗/poet.song.174000.json','["珍重章泉辱寄書，應疑不復夢康廬。", "本無學術安時論，誤入班行拱帝居。", "老矣應招寧爲祿，時乎歸釣亦非漁。", "宦情山色常如此，欲去遲行媿二疏。"]'),
('c42f338f-8a95-413a-b015-212404f48947','章泉言語妙天下知僕無詩能且未識面乃時以佳篇見餉何也不敢再虛盛意勉次韻二篇以謝  其二','曹彥約','宋','宋诗','song-poetry','','[]','吟罷新詩却看書，先生必自愛吾廬。',64,'全唐诗/poet.song.174000.json','["吟罷新詩却看書，先生必自愛吾廬。", "天開上壽供椽筆，地出佳泉相廣居。", "自古莘耕懷道義，只今舜德起陶漁。", "直須大老歸來好，莫道高情與世疏。"]'),
('b9f1410f-dba8-4301-9565-6407b32e5fcb','况子沿檄來歸舟過淮右繡衣左國錄贈行以詩因及衰朽次韻奉酬三首  其一','曹彥約','宋','宋诗','song-poetry','','[]','况也來從班馬傍，泛舟千里尚醲香。',64,'全唐诗/poet.song.174000.json','["况也來從班馬傍，泛舟千里尚醲香。", "庭雖過鯉元無異，桴偶乘由得問强。", "親見治民如治眼，歸談勤賊定勤王。", "翻思父子寒如此，孤負珠璣富墨莊。"]'),
('0cc30b8c-916e-4366-8c72-5000a9205d9a','况子沿檄來歸舟過淮右繡衣左國錄贈行以詩因及衰朽次韻奉酬三首  其二','曹彥約','宋','宋诗','song-poetry','','[]','金石爲心錦作腸，案前合侍玉皇香。',64,'全唐诗/poet.song.174000.json','["金石爲心錦作腸，案前合侍玉皇香。", "只因淮蔡須裴度，不爲并州戲葛强。", "繡斧邇來新遣使，氈裘從此盡輸王。", "功成遠勒燕然石，閒却江西左氏莊。"]'),
('e5815204-3a26-4a3b-a956-c9ee4f5def18','况子沿檄來歸舟過淮右繡衣左國錄贈行以詩因及衰朽次韻奉酬三首  其三','曹彥約','宋','宋诗','song-poetry','','[]','憶昨相逢是豫章，笑談親接齒牙香。',64,'全唐诗/poet.song.174000.json','["憶昨相逢是豫章，笑談親接齒牙香。", "如今但有心期在，不似當初脚力强。", "投老頗能安晚境，祝釐聊以報明王。", "簡編未了平生債，冷淡猶能讀老莊。"]'),
('113ad9a7-9a77-4efa-ac9e-ec8a8957f33a','使君見示鹿鳴詩走筆奉和','曹彥約','宋','宋诗','song-poetry','','[]','眼明及見决科文，發策當書第一勳。',64,'全唐诗/poet.song.174000.json','["眼明及見决科文，發策當書第一勳。", "八句催行歌白雪，一言合意定青雲。", "君今去亦朝天上，主聖還須對夜分。", "遥想朱華傳敕處，九重春色醉朝曛。"]'),
('5a59c275-ce5f-4a7e-863f-ae0aeebfa2fe','四明趙添監連日惠詩不能盡繼匠手次唐律韻以謝','曹彥約','宋','宋诗','song-poetry','','[]','馬口爲銜不自寧，轍環唯筆可深耕。',64,'全唐诗/poet.song.174000.json','["馬口爲銜不自寧，轍環唯筆可深耕。", "門迎滄海襟期闊，地逼天潢句法清。", "吾道本無青白眼，世情休歎短長檠。", "珠璣肯袖來昌谷，不道陳人畏後生。"]'),
('b346d2c1-ad54-405d-a973-44c0a968cd52','陳倅寄惠四詩用昌黎和裴相韻愧不能當也走筆賦二章以謝  其一','曹彥約','宋','宋诗','song-poetry','','[]','兩歲驅馳馬首東，曾微一戰可論功。',64,'全唐诗/poet.song.174000.json','["兩歲驅馳馬首東，曾微一戰可論功。", "因人偶爾成擒蔡，無計降之媿伐崇。", "萬竈炊煙歸塞下，十分農事到湟中。", "酸寒伎倆纔如此，辜負新詩託至公。"]'),
('0a2bfb65-678a-493e-b225-41c040d62113','陳倅寄惠四詩用昌黎和裴相韻愧不能當也走筆賦二章以謝  其二','曹彥約','宋','宋诗','song-poetry','','[]','近來人物眇江東，况也書生責勇功。',64,'全唐诗/poet.song.174000.json','["近來人物眇江東，况也書生責勇功。", "痛定却思三策謬，歸來猶想萬山崇。", "誰從荀伯官寮裏，賦入昌黎句法中。", "戎事尚多心事少，苦無佳語可酬公。"]'),
('ca7df6b7-89e2-422c-a5aa-5b886f677237','偶成  其一','曹彥約','宋','宋诗','song-poetry','','[]','春入園林種種奇，化工施巧太精微。',64,'全唐诗/poet.song.174000.json','["春入園林種種奇，化工施巧太精微。", "山禽說我胸中事，煙柳藏他物外機。", "既遣杏桃空際發，又令蜂蝶近前飛。", "如何有眼無人見，只解西郊看落暉。"]'),
('642ffc70-9a33-42e0-9bbc-898652895342','偶成  其二','曹彥約','宋','宋诗','song-poetry','','[]','脚踏和風步步春，石魚樓上等閒人。',64,'全唐诗/poet.song.174000.json','["脚踏和風步步春，石魚樓上等閒人。", "興來衝口都成句，老去遊山不動塵。", "李白誰知他意思，桃紅漏洩我精神。", "忽逢借問難酬對，只恐流鶑說得真。"]'),
('542d0888-b097-417f-8735-b24693adcb87','攝守漢陽次韻項平父餞行之句','曹彥約','宋','宋诗','song-poetry','','[]','我計短於頭觸篷，公才高似目飛鴻。',64,'全唐诗/poet.song.174000.json','["我計短於頭觸篷，公才高似目飛鴻。", "已馳騅馬雄西楚，尚引蜉蝣綴國風。", "願伯明年終惠我，以曹爲解可無公。", "欲持枉尺歸繩墨，祇恐旁觀血指紅。"]'),
('fb1d35bc-b39a-42da-ad1e-56eb3d80be14','用四明劉聘君古風四韻賦唐律','曹彥約','宋','宋诗','song-poetry','','[]','錯落珠璣滿袖傾，百年初見媿生平。',64,'全唐诗/poet.song.174000.json','["錯落珠璣滿袖傾，百年初見媿生平。", "人從伊傅平頭數，句似陰何徹骨清。", "惠我善隣天有意，惜君橫道世無情。", "曲終狗尾那能續，欲附曹劉萬古名。"]'),
('4248cd8a-3c9c-4240-87d9-ed0f637a3523','章泉趙昌父頻數寄詩再次韻一首','曹彥約','宋','宋诗','song-poetry','','[]','斗南獨立章泉老，四海神交可得親。',64,'全唐诗/poet.song.174000.json','["斗南獨立章泉老，四海神交可得親。", "適意不忘新進客，作詩時託遠來人。", "報無瓊玖衰緣病，保此珠璣富不貧。", "命駕已孤千里志，掛冠今欲致爲臣。"]'),
('351d1498-8528-4d26-9f31-b60ad62d12d5','譚仁季以二詩見貽走筆次韻  其一','曹彥約','宋','宋诗','song-poetry','','[]','風聲久想杜陵珂，坐對忘年可爛柯。',64,'全唐诗/poet.song.174000.json','["風聲久想杜陵珂，坐對忘年可爛柯。", "但覺清談揮玉柄，也知文律敵金科。", "螳螂欲振難當轍，鼴鼠終微漫飲河。", "從此巽堂風月好，滿腔茅塞半消磨。"]'),
('65762ace-6bb7-459f-b4b5-d009969dc2ce','譚仁季以二詩見貽走筆次韻  其二','曹彥約','宋','宋诗','song-poetry','','[]','詩才清不羨滄浪，曾向歐曾接瓣香。',64,'全唐诗/poet.song.174000.json','["詩才清不羨滄浪，曾向歐曾接瓣香。", "萬里相逢書遜志，百年幾見易含章。", "君溫有脚開春盎，我暗無心得夜光。", "可奈文場催戰急，陣雲飛動正堂堂。"]'),
('1510096c-2903-4f68-a384-a35917d63302','次韻清卿用使君鹿鳴韻見貽','曹彥約','宋','宋诗','song-poetry','','[]','甲戌家聲僅有傳，等閒膏澤下雲天。',64,'全唐诗/poet.song.174000.json','["甲戌家聲僅有傳，等閒膏澤下雲天。", "苦無事業榮宗黨，强把忠勤了歲年。", "往事紛紜幾折角，後來奔軼要加鞭。", "得時自古無淹速，却與亨塗作壽仙。"]'),
('0f846878-abee-48d5-97d8-a3b1c5d68ba2','送友人','曹彥約','宋','宋诗','song-poetry','','[]','藥裹包回碾臼聲，得閒消息病先輕。',64,'全唐诗/poet.song.174000.json','["藥裹包回碾臼聲，得閒消息病先輕。", "謂予不信看舟楫，之死無他况利名。", "積雨晴邊花蔕耐，好風吹外葉聲平。", "只愁岸送檣留後，却憶湘南老友生。"]'),
('a88637e8-3612-4851-9616-80db36fec0c7','冬至伊邇滯留桂陽有感','曹彥約','宋','宋诗','song-poetry','','[]','如此生涯任轉蓬，幾年漂泊羨歸鴻。',64,'全唐诗/poet.song.174000.json','["如此生涯任轉蓬，幾年漂泊羨歸鴻。", "凄凉落日荒山外，黯澹愁雲暮靄中。", "叢菊乍殘秋色遠，嶺梅將放雪光融。", "枯腸索盡渾無事，詩句粗成付碧筒。"]'),
('1935079a-317f-4b32-aacb-c99c2227739e','憶歸口號  其一','曹彥約','宋','宋诗','song-poetry','','[]','壯年梁父粗成吟，亦謂逢時可盡心。',64,'全唐诗/poet.song.174000.json','["壯年梁父粗成吟，亦謂逢時可盡心。", "過了許多空日月，得來輕棄舊山林。", "平生簡冊心猶壯，晚歲規模力不任。", "何事一來何事去，去來端的要知音。"]'),
('42a75760-109b-4e05-a31a-caec48e6adfd','憶歸口號  其二','曹彥約','宋','宋诗','song-poetry','','[]','初無警策驟驚人，亦不媕婀巧進身。',64,'全唐诗/poet.song.174000.json','["初無警策驟驚人，亦不媕婀巧進身。", "每向經筵持正論，願於國脈奬忠臣。", "昔從新政趨嚴召，今爲衰年避要津。", "陛下果能行古道，雖閒猶是太平民。"]'),
('d2b1964e-787e-4499-a275-d386b63cdd6c','憶歸口號  其三','曹彥約','宋','宋诗','song-poetry','','[]','漫說湖莊水與山，不因松菊便求閒。',64,'全唐诗/poet.song.174000.json','["漫說湖莊水與山，不因松菊便求閒。", "月中休沐纔三日，殿外經從僅百間。", "但有心期思報主，苦無脚力强趨班。", "得歸便欲疎賓客，本意劉伶不閉關。"]'),
('0db0ed56-8645-43d3-8fff-cf69fdee96a3','春至','曹彥約','宋','宋诗','song-poetry','','[]','閏後陽和樂不禁，還將動靜印天心。',64,'全唐诗/poet.song.174000.json','["閏後陽和樂不禁，還將動靜印天心。", "借留臘意梅藏玉，指點春容柳轉金。", "冗奪漸疏詩領略，情鍾須索酒追尋。", "玉京山色䢼亭水，自與絲桐作賞音。"]'),
('4a9a04ad-91b0-497a-aea1-754476f58087','謝朱鶴皋招飲','曹彥約','宋','宋诗','song-poetry','','[]','里巷浮沉適自由，江城久住似菟裘。',64,'全唐诗/poet.song.174000.json','["里巷浮沉適自由，江城久住似菟裘。", "廣文活計貧無那，好客情懷挽不留。", "滿院竹風吹酒面，兩株榴火發詩愁。", "料應此外無佳致，人物相看總上游。"]'),
('03d923f6-a99c-4d7a-ad3d-486bb5a6bccc','旬休日遣懷招陳德溫飲','曹彥約','宋','宋诗','song-poetry','','[]','擁鼻南窗對晚陰，自憐終日坐蕭森。',64,'全唐诗/poet.song.174000.json','["擁鼻南窗對晚陰，自憐終日坐蕭森。", "相如未遂題橋志，工部虛勞戀闕心。", "儘辦赤心遭白眼，聊將綵服照青衿。", "東隣况有陳驚座，時得花前一盍簪。"]'),
('741e5574-af95-4cb1-949d-780e61734e6b','謝羅醴陵宏材樂府見寄','曹彥約','宋','宋诗','song-poetry','','[]','自別湘中首屢迴，漏傳春信一枝梅。',64,'全唐诗/poet.song.174000.json','["自別湘中首屢迴，漏傳春信一枝梅。", "固知我老何須此，不與時同亦壯哉。", "百里去思民父母，三年歸作國臺萊。", "更將餘力哦新調，三百篇中著意來。"]'),
('046192da-4dc0-4bdc-b903-d7f78d878a9d','雲隠李季可挽詩二首  其一','曹彥約','宋','宋诗','song-poetry','','[]','雲卷雲舒好靜觀，謂宜隠者似無端。',64,'全唐诗/poet.song.174000.json','["雲卷雲舒好靜觀，謂宜隠者似無端。", "誰知天上爲霖用，竟作人間出岫看。", "萬里功名當進步，諸昆時節合彈冠。", "只因自得無心趣，三度歸來現宰官。"]'),
('4788639d-fcde-4abd-8514-ac40a7cc39e7','雲隠李季可挽詩二首  其二','曹彥約','宋','宋诗','song-poetry','','[]','當年棋酒漫追攀，幕府承平白晝閒。',64,'全唐诗/poet.song.174000.json','["當年棋酒漫追攀，幕府承平白晝閒。", "帥事却來兵革後，官身唯冗簿書間。", "壯懷日者論交舊，末路天乎與壽慳。", "風急浪高雲黯淡，訃書新到落星灣。"]'),
('e549674c-9029-4d11-b9d0-994c15b83fd9','魏總幹嘉父以果齋求詩爲賦二章  其一','曹彥約','宋','宋诗','song-poetry','','[]','請言山下出泉蒙，蒙養從來有聖功。',64,'全唐诗/poet.song.174000.json','["請言山下出泉蒙，蒙養從來有聖功。", "三德知仁非好勇，六爻險止要時中。", "申棖有慾剛安在，曾子無仁毅不洪。", "以果名齋兼衆德，力行方見古人風。"]'),
('8a71259a-d256-46fe-9bd6-ec69185b3bb2','魏總幹嘉父以果齋求詩爲賦二章  其二','曹彥約','宋','宋诗','song-poetry','','[]','偶向齋名見一斑，其中蓄德尚多端。',64,'全唐诗/poet.song.174000.json','["偶向齋名見一斑，其中蓄德尚多端。", "講明自有安心要，出處還須中節看。", "持以贈君成我拙，歸而求此有兄難。", "當年射策封章意，暴虎如由膽亦寒。"]'),
('8bac99a6-91bc-4a4f-9100-bb7e72cda86b','遣吏約同官弈棋議事知有蘇山之游不果來晚使君載酒見過遂賦此詩','曹彥約','宋','宋诗','song-poetry','','[]','索居誰復共前籌，坐想蘇山最上頭。',64,'全唐诗/poet.song.174000.json','["索居誰復共前籌，坐想蘇山最上頭。", "並轡水兼天共遠，孤吟棋與酒皆愁。", "孰令客裏擠排老，不分軍前斷送秋。", "却有鄰翁驚笑語，夜來尊俎對賢侯。"]'),
('40ec9df8-f44b-47a3-a99d-5d21a613a30f','使君黄秘書上印有期聞嚴召已得好語賦唐律送之','曹彥約','宋','宋诗','song-poetry','','[]','五十萊衣宦海榮，每將忠讜報平生。',64,'全唐诗/poet.song.174000.json','["五十萊衣宦海榮，每將忠讜報平生。", "暫分竹去寬宵旰，又賜環歸近聖明。", "人物渺然須引類，東南竭矣願休兵。", "功名自重囊中物，感悟從來看積誠。"]'),
('aa6810e2-3929-428e-a6db-eeb3a162cf72','上湖廣總領趙郎中  其一','曹彥約','宋','宋诗','song-poetry','','[]','總角爲兒百未更，已陪先進識英名。',64,'全唐诗/poet.song.174000.json','["總角爲兒百未更，已陪先進識英名。", "慣聞似覺雄風近，因問從知看日明。", "千里未迎天子詔，一同先說長官清。", "吏師况有桐川舊，敢向題輿問去程。"]'),
('1b632b6a-0421-4c6a-a784-3ce50036bad3','上湖廣總領趙郎中  其二','曹彥約','宋','宋诗','song-poetry','','[]','春風湓浦駐行軒，獨許愚儒夜叩關。',64,'全唐诗/poet.song.174000.json','["春風湓浦駐行軒，獨許愚儒夜叩關。", "六路方迎新遣使，五年猶念舊登門。", "薄緣未許南樓分，歸夢唯驚丙夜魂。", "幸自秋江好天色，一帆風月際真源。"]'),
('fc1c6088-88fe-4e2a-a8a8-c9546ede4fad','上湖廣總領趙郎中  其三','曹彥約','宋','宋诗','song-poetry','','[]','豈無山水憚登臨，未話平生語欲清。',64,'全唐诗/poet.song.174000.json','["豈無山水憚登臨，未話平生語欲清。", "得馬經營今搏手，傷弓憂患幾驚心。", "所思未覺荆山遠，欲往寧辭沔水深。", "山水有情絃未絕，請從千里抱鳴琴。"]'),
('16d17464-3dee-4528-a001-a81d6d5c6867','次韻趙俞宣德石博山香臺','曹彥約','宋','宋诗','song-poetry','','[]','水骨苔痕洞穴開，龍騰波湧碧崔嵬。',64,'全唐诗/poet.song.174000.json','["水骨苔痕洞穴開，龍騰波湧碧崔嵬。", "煙雲靜向林中起，風雨飛從海上來。", "江外廬峰傾瀑布，日邊鼇頂對蓬萊。", "幾經兵火今猶在，拂拭還看貯劫灰。"]'),
('44c5fc04-3385-48a5-ac5e-61de6b44db35','送趙侍郎被召  其一','曹彥約','宋','宋诗','song-poetry','','[]','大纛高牙古帥垣，甘泉人物帝王孫。',64,'全唐诗/poet.song.174000.json','["大纛高牙古帥垣，甘泉人物帝王孫。", "文如賀白尤寒素，政似龔黄更本原。", "歲課未書先報政，詔封頻趣定調元。", "欲知惠愛今多少，水滿長川月滿村。"]'),
('bba421cb-afee-4e96-9582-3f22a9899537','送趙侍郎被召  其二','曹彥約','宋','宋诗','song-poetry','','[]','祇爲分憂輟近臣，不應持久費經綸。',64,'全唐诗/poet.song.174000.json','["祇爲分憂輟近臣，不應持久費經綸。", "暫來制閫無多日，歸去朝天及早春。", "紅旆綠油生羽翼，落霞秋水動精神。", "行行但說長安近，辜負攀留幾許人。"]'),
('6720fc68-85f9-45c6-9621-85b275117a48','送趙侍郎被召  其三','曹彥約','宋','宋诗','song-poetry','','[]','憶昨東來護印章，又從此去餞朝裝。',64,'全唐诗/poet.song.174000.json','["憶昨東來護印章，又從此去餞朝裝。", "辛勤行李知身老，幸會依蓮到骨香。", "五十功名猶落寞，百千懷抱轉荒唐。", "而今親見爲霖雨，野草幽花特地芳。"]'),
('40da01cd-35dd-4ff8-98c6-a33e55d5b616','薛侍郎移鎮合肥被命入覲賦唐律詩二章  其一','曹彥約','宋','宋诗','song-poetry','','[]','經濟蜚聲數十年，只今韞櫝固依然。',64,'全唐诗/poet.song.174000.json','["經濟蜚聲數十年，只今韞櫝固依然。", "老於思慮惟憂國，好在功名更守邊。", "人望鼎來須易地，春風早去便朝天。", "漢家老將輝千古，只有留屯服罕幵。"]'),
('39db652e-92eb-4637-a62b-c0a67f6c8560','薛侍郎移鎮合肥被命入覲賦唐律詩二章  其二','曹彥約','宋','宋诗','song-poetry','','[]','平生惟仰薛居州，病渴尋梅正所求。',64,'全唐诗/poet.song.174000.json','["平生惟仰薛居州，病渴尋梅正所求。", "風送有時參畫鷁，幕開無路到青油。", "百年萬事常交臂，一代數人今白頭。", "帷幄得賢如此好，貂蟬元不在兜鍪。"]'),
('c614dddd-9804-494b-88dd-ce9fa900db80','送胡倅辟書不遂復到選部','曹彥約','宋','宋诗','song-poetry','','[]','便飽蒲帆縱木蘭，王陽時節好彈冠。',64,'全唐诗/poet.song.174000.json','["便飽蒲帆縱木蘭，王陽時節好彈冠。", "官身臺歷星遲速，世路天香篆屈盤。", "人去邊頭三策在，春回天上五谿寒。", "歸飛未戢青冥翅，却與朝廷作羽翰。"]'),
('57220726-6cb1-4927-9abe-57c8049145ab','禱雨陽山  其一','曹彥約','宋','宋诗','song-poetry','','[]','暮投突兀浄爲坊，早踏崎嶇翠作岡。',64,'全唐诗/poet.song.174000.json','["暮投突兀浄爲坊，早踏崎嶇翠作岡。", "露氣失凉風带暑，嵐陰欺曉日韜光。", "不憂時事禽空語，可怪凶年草更芳。", "欲問行人祈禱意，日來鉦鼓漸淒涼。"]'),
('cb1204ca-d638-4433-99eb-85bca14071d8','禱雨陽山  其二','曹彥約','宋','宋诗','song-poetry','','[]','所以登山不憚煩，爲藏雲氣達泉源。',64,'全唐诗/poet.song.174000.json','["所以登山不憚煩，爲藏雲氣達泉源。", "多峰豈炫千巖秀，一綫纔通萬壑奔。", "其在茲乎須出岫，此時何不早翻盆。", "名高已到巖瞻地，只有爲霖可養尊。"]'),
('c4f2e9fe-3137-40a9-bf0d-3583943ee2c3','課花木','曹彥約','宋','宋诗','song-poetry','','[]','旋飾芳菲真草萊，强加湔祓敵塵埃。',64,'全唐诗/poet.song.174000.json','["旋飾芳菲真草萊，强加湔祓敵塵埃。", "春將紫翠籠丹桂，晚覺蒼黄植綠槐。", "鼻觀已通蜂蝶閙，酒盃頻到燕鶑猜。", "官居未勝閒居樂，乞得三年野興來。"]'),
('eb1a093f-ccc3-43d7-9e82-45577e260f2c','序齋丁主簿挽章','曹彥約','宋','宋诗','song-poetry','','[]','詩禮彬彬到古風，月橋人物序齋中。',64,'全唐诗/poet.song.174000.json','["詩禮彬彬到古風，月橋人物序齋中。", "鄭公宅畔鄉仍在，馬氏臺前帳已空。", "萬事可堪評夜旦，九泉終不蓋英雄。", "只今家學方如此，猶喜先生易未東。"]'),
('b6e3e96c-14dc-4798-82ff-c6953dd6090d','一碧萬頃堂','曹彥約','宋','宋诗','song-poetry','','[]','乞得湖光萬頃多，傍招九疊更嵯峨。',64,'全唐诗/poet.song.174000.json','["乞得湖光萬頃多，傍招九疊更嵯峨。", "百年未死須閒在，一日不來如景何。", "意遠已知貪雪月，身安猶欲鎮風波。", "只愁頑似雲間石，更有何人爲琢磨。"]'),
('e032dbb0-7113-4bf3-aa45-3f73bf5836b9','寶泰寺讀曾鴻父侍郎留題有感次韻作侍郎挽歌','曹彥約','宋','宋诗','song-poetry','','[]','斯人千古閟音塵，絕妙肝腸好受辛。',64,'全唐诗/poet.song.174000.json','["斯人千古閟音塵，絕妙肝腸好受辛。", "四袠升沉懸日月，百年修短誤君親。", "天邊尚記絲綸手，地上今無磊砢人。", "對此感懷非爲此，贖之空擬百其身。"]'),
('81d0a2f8-9422-4527-a1c2-3d0de363900d','陪總卿戎帥登高因至郊外','曹彥約','宋','宋诗','song-poetry','','[]','萬木陰陰覆女蘿，一川佳處寶峰多。',64,'全唐诗/poet.song.174000.json','["萬木陰陰覆女蘿，一川佳處寶峰多。", "因晴領客催萸菊，恐雨妨農訪麥禾。", "付我江山須領略，可人時節易蹉跎。", "心閒更了官中事，未必秋風奈老何。"]'),
('8b263463-e11c-4b8f-ae5d-af567302a21e','海棠  其一','曹彥約','宋','宋诗','song-poetry','','[]','彼美花兮宜晚春，柔姿淑艷是何人。',64,'全唐诗/poet.song.174000.json','["彼美花兮宜晚春，柔姿淑艷是何人。", "十分國色粧須淡，數點臙脂畫未勻。", "带雨容開渾是恨，出牆頭望恰如真。", "幾時謫下蓬萊島，霞染仙衣痕尚新。"]'),
('1add3f84-a5f8-48c6-80ad-5c233ad4a852','海棠  其二','曹彥約','宋','宋诗','song-poetry','','[]','一度相逢一度春，不知名姓是何人。',64,'全唐诗/poet.song.174000.json','["一度相逢一度春，不知名姓是何人。", "十分國色粧須淡，數點臙脂畫未勻。", "好把東皇爲上客，便堪宋玉作西鄰。", "臨邛道士今何在，說與唐宗是太真。"]'),
('141a4446-34e5-43b1-b64b-72f330f8b6f4','九江郡齋分韻送魏六兄好文遊鄂渚得陽字','曹彥約','宋','宋诗','song-poetry','','[]','倦客尋閒誤入忙，飄然上水擊潯陽。',64,'全唐诗/poet.song.174000.json','["倦客尋閒誤入忙，飄然上水擊潯陽。", "鈴齋有伴期三友，玉德何人似六郎。", "千里江山時聚散，滿城風月夜凄凉。", "西風隠作中秋會，莫戀南樓醉武昌。"]'),
('d6996e44-eab6-40ea-b264-a7d11b3a3a8d','送蓬丘山人張以道歸吉州','曹彥約','宋','宋诗','song-poetry','','[]','山人曾著宰官衫，了事還爲馬口銜。',64,'全唐诗/poet.song.174000.json','["山人曾著宰官衫，了事還爲馬口銜。", "別我三年無瞬息，思君一節尚巉巖。", "人生契合常如此，吾道年來見大凡。", "雨後只愁風力健，江空無計款歸帆。"]'),
('4231ebab-eca8-4296-927d-a4d172bbfd61','代送禮部楊侍郎帥江陵  其一','曹彥約','宋','宋诗','song-poetry','','[]','鼎鼐真才筆橐聲，清朝人物獨先生。',64,'全唐诗/poet.song.174000.json','["鼎鼐真才筆橐聲，清朝人物獨先生。", "從來馬老荆州望，可但元公禮部名。", "謀帥直須醫國手，輟賢何以慰人情。", "送春又數春回處，忍更堂堂背我行。"]'),
('67d41515-16aa-43ea-9a17-1fb0b5d06667','代送禮部楊侍郎帥江陵  其二','曹彥約','宋','宋诗','song-poetry','','[]','慈恩一集成三紀，朝路相從不半年。',64,'全唐诗/poet.song.174000.json','["慈恩一集成三紀，朝路相從不半年。", "託蔭身如松下草，願交身已社中蓮。", "一時事體公輕重，到處參辰我後先。", "折贈不須門外柳，病懷落寞正如綿。"]'),
('173d92f4-5328-4a16-9022-fe7bd2f4b5c8','弈棋戲作','曹彥約','宋','宋诗','song-poetry','','[]','人皆託物滌塵襟，我亦於棋了寸陰。',64,'全唐诗/poet.song.174000.json','["人皆託物滌塵襟，我亦於棋了寸陰。", "散誕不知身老大，從容聊與世浮沉。", "諸君誤作機關說，老子初無勝負心。", "收拾定應全局在，清風明月照書林。"]'),
('be6006f6-6ff1-4fd2-8920-680d7abf029d','次韻長沙鄭監廟公選  其一','曹彥約','宋','宋诗','song-poetry','','[]','先生清德徹寒泉，應俗周旋更折旋。',64,'全唐诗/poet.song.174000.json','["先生清德徹寒泉，應俗周旋更折旋。", "游宦向來徒溷耳，盛名今得孰多焉。", "詩嚴尚作蜂腰格，志大寧憂馬腹鞭。", "却似周公勤小物，亂揮珠玉擲忘年。"]'),
('46f7b687-425b-4bba-826e-146f33003a02','次韻長沙鄭監廟公選  其二','曹彥約','宋','宋诗','song-poetry','','[]','已廢詩壇罷酒兵，更無餘力敵分陰。',64,'全唐诗/poet.song.174000.json','["已廢詩壇罷酒兵，更無餘力敵分陰。", "兩章句好驚霏屑，千里神交信斷金。", "如弈棋然隨手著，效顰眉亦撚鬚吟。", "不圖病客甘投老，敢與詩人作賞音。"]'),
('ad5fe907-e40f-4d30-ae9a-9be0216856a0','喜晴  其一','曹彥約','宋','宋诗','song-poetry','','[]','捷書遲報已驚神，不分龍公巧障人。',64,'全唐诗/poet.song.174000.json','["捷書遲報已驚神，不分龍公巧障人。", "傾倒從頭慳澀雨，破除當面艷陽春。", "有園未賞陰連屋，無地言歸水拍津。", "報道纖埃歸洞壑，本來山色任橫陳。"]'),
('02810fa9-5bb3-4622-929a-daaac1e47f9a','喜晴  其二','曹彥約','宋','宋诗','song-poetry','','[]','醉入機緘喜不勝，幾多風雨一番晴。',64,'全唐诗/poet.song.174000.json','["醉入機緘喜不勝，幾多風雨一番晴。", "掃除氛祲乾坤大，拂試光輝日月明。", "萬計官逋紓吏責，十分燈夕看人情。", "熙熙不但春臺樂，從此東南說建平。"]'),
('371fd7d6-7e97-432a-96ef-3467007baf41','春雪初霽','曹彥約','宋','宋诗','song-poetry','','[]','已通消息變垂楊，又忍須臾困海棠。',64,'全唐诗/poet.song.174000.json','["已通消息變垂楊，又忍須臾困海棠。", "雪意疎時風自惡，雲根好處日爭光。", "威嚴冷到漢三輔，艷冶春歸唐六郎。", "四者欲并從古少，便將樽酒問羣芳。"]'),
('99ff1cb2-9fa8-4de6-80dd-232c7aa50198','雨中同官遊野園','曹彥約','宋','宋诗','song-poetry','','[]','忙了三年乍得閒，便乘風雨看溪山。',64,'全唐诗/poet.song.174000.json','["忙了三年乍得閒，便乘風雨看溪山。", "可憐過眼事多少，都不關心春往還。", "老至但驚霜上鬢，興來聊復酒開顔。", "如今便作遊人喚，更欲徜徉紫翠間。"]'),
('eae41125-eeac-44f4-8920-28f152cb0eb3','諸丈和野園之詩乃復次韻','曹彥約','宋','宋诗','song-poetry','','[]','驤首彌年閉六關，倦飛今日徧千山。',64,'全唐诗/poet.song.174000.json','["驤首彌年閉六關，倦飛今日徧千山。", "也知心醉非從事，頓覺身輕有大還。", "酒債人生頻檢點，宦情山色正孱顔。", "不須作惡悲兒女，更放羈人到席間。"]'),
('3a147c12-993f-4297-ba5c-82542d0b397a','陪李監稅飲劉園','曹彥約','宋','宋诗','song-poetry','','[]','剩栽花木閙低牆，滿刻詩文榜畫堂。',64,'全唐诗/poet.song.174000.json','["剩栽花木閙低牆，滿刻詩文榜畫堂。", "郁李齊開枝尚弱，牡丹垂謝蕊猶香。", "書生野趣人間少，遊子佳時客裏忙。", "準擬燈前兒女問，得君全不負春光。"]'),
('d2d76649-44b7-4c6f-ac8a-c8772a4672e9','重陽湖莊無菊走筆招趙季清黄一之登高','曹彥約','宋','宋诗','song-poetry','','[]','摇落江村菊就荒，苦無節物報重陽。',64,'全唐诗/poet.song.174000.json','["摇落江村菊就荒，苦無節物報重陽。", "病來欲廢傳盃舊，老去唯思著帽强。", "已變楓丹秋盡力，僅存萸紫晚添香。", "登高有景那能賦，喚取騷人趙與黄。"]'),
('40ab7535-d198-4c67-9587-9962355ebaab','次韻黄一之','曹彥約','宋','宋诗','song-poetry','','[]','蕪盡田園學亦荒，衰年無復夢張陽。',64,'全唐诗/poet.song.174000.json','["蕪盡田園學亦荒，衰年無復夢張陽。", "起予節裏心期合，及此年時脚力强。", "萬古推遷陵谷變，幾人登覽姓名香。", "欲追奔逸慚駑蹇，始信人間有乘黄。"]'),
('8a547461-c0df-4632-8aa9-d45e7087875d','九日遣興','曹彥約','宋','宋诗','song-poetry','','[]','散誕平生百不憂，未應摇落學悲秋。',64,'全唐诗/poet.song.174000.json','["散誕平生百不憂，未應摇落學悲秋。", "儻來節物知寒暖，泛應賓朋任去留。", "落帽粗豪非宿好，插花姿媚怯英游。", "不如只把茱萸看，免歎尊前歲月流。"]'),
('ecd0160e-a0ea-490e-be59-112af8476298','次韻隆慶楊使君送別之章  其一','曹彥約','宋','宋诗','song-poetry','','[]','傾蓋星橋憶去年，官聯預說使君賢。',64,'全唐诗/poet.song.174000.json','["傾蓋星橋憶去年，官聯預說使君賢。", "別來風送空中月，此去雲開劍裏天。", "治效龔黄方側耳，交情嵇呂好差肩。", "相逢便作陽關曲，數日銷魂正黯然。"]'),
('fb9b8670-80d3-432e-8599-6faf78801b4b','次韻隆慶楊使君送別之章  其二','曹彥約','宋','宋诗','song-poetry','','[]','細讀君詩字字新，巧將鹽豉入羹蒓。',64,'全唐诗/poet.song.174000.json','["細讀君詩字字新，巧將鹽豉入羹蒓。", "也知世路催行客，更遣工歌勞使臣。", "千里身心空晤對，五經懷抱想紛綸。", "他年宛水昭亭外，把玩猶能絕點塵。"]'),
('814254bb-0f1a-4df9-86ca-14707f8273aa','春同伯中之櫟田','曹彥約','宋','宋诗','song-poetry','','[]','涖卜他年正首丘，尚乘風日逐英游。',64,'全唐诗/poet.song.174000.json','["涖卜他年正首丘，尚乘風日逐英游。", "平分正月春猶淺，斷送元宵冷未休。", "藕斷山鍾黄蘗外，枝分水轉石榴頭。", "卷簾隠几俱爲樂，付與涪翁悶得不。"]'),
('0572dccd-416f-4b0a-8990-9723420f33d6','東菴新闢雲棧','曹彥約','宋','宋诗','song-poetry','','[]','步出東門葦不航，以雲名棧正相當。',64,'全唐诗/poet.song.174000.json','["步出東門葦不航，以雲名棧正相當。", "地臨空闊天成險，水到回旋石作梁。", "萬頃波濤一丘壑，百年官吏幾循良。", "古來勿翦甘棠意，此地風流未可量。"]'),
('06ae9d68-d4a2-473a-aa5e-d7474f8cd449','送趙安卿召除考功  其一','曹彥約','宋','宋诗','song-poetry','','[]','秉節歸來乍賜環，握蘭高處自催班。',64,'全唐诗/poet.song.174000.json','["秉節歸來乍賜環，握蘭高處自催班。", "身趨地禁嚴凝上，名在湘清欵乃間。", "萬竈艱難寬國步，一星咫尺近天顔。", "席前若問長沙事，只有深仁滲百蠻。"]'),
('83b0c97b-88a9-4e5b-8d07-7390adf060df','送趙安卿召除考功  其二','曹彥約','宋','宋诗','song-poetry','','[]','五老重湖一腐儒，强令隨牒應時須。',64,'全唐诗/poet.song.174000.json','["五老重湖一腐儒，强令隨牒應時須。", "杜陵身世霜前鬢，陶令田園雨後蕪。", "梅菊滿懷憂歲晚，松楸關念怯春濡。", "知音自是調元手，乞與還山護命符。"]'),
('e791f67e-fd00-462f-9ecf-ddd42377aa6b','次知縣花名詩韻','曹彥約','宋','宋诗','song-poetry','','[]','天不長春又入冬，可能含笑拒霜風。',64,'全唐诗/poet.song.174000.json','["天不長春又入冬，可能含笑拒霜風。", "凌霄器宇隨時見，茉莉生涯到處窮。", "但可憐花成後約，莫將荳蔻掩前功。", "人生且進薔微露，滴滴金錢總是空。"]'),
('346e8810-fdf6-487c-bbd2-814c8e3c139f','晚登縣陴','曹彥約','宋','宋诗','song-poetry','','[]','樓櫓寬閒事力勞，新來人物舊蓬蒿。',64,'全唐诗/poet.song.174000.json','["樓櫓寬閒事力勞，新來人物舊蓬蒿。", "占留古意梅根老，壓斷寒聲樠木高。", "地迥山川含鼓角，夜明星斗助弓刀。", "當時愛得蓮無恙，一段清流繞屋敖。"]'),
('288e1e4a-7730-4648-8fee-86477c824813','廖子晦以通書及龜山道鄉晦庵帖見惠','曹彥約','宋','宋诗','song-poetry','','[]','文公垂憲墨淋浪，鼎立龜山更道鄉。',64,'全唐诗/poet.song.174000.json','["文公垂憲墨淋浪，鼎立龜山更道鄉。", "家有一焉猶冠絕，寶茲三者見珍藏。", "來從疊嶂層巒裏，置在光風霽月傍。", "收拾兵戎無一物，滿船空載有歸裝。"]'),
('e7301848-12e0-4463-a507-df8c891bb969','雨行宿高岡人家戲成口號','曹彥約','宋','宋诗','song-poetry','','[]','過了一坡更一坡，中間田道水成渦。',64,'全唐诗/poet.song.174000.json','["過了一坡更一坡，中間田道水成渦。", "雨來更驟擔肩重，泥滑不休行步多。", "奈老杉松猶偃蹇，趨時桃李暫蹉跎。", "炊煙戀屋不肯出，夜宿人家燒薜蘿。"]'),
('7f2431ce-3db3-48ed-9dd5-60a031378faa','靜坐對茶花偶作','曹彥約','宋','宋诗','song-poetry','','[]','菊後梅前冷落時，剪檀雕蠟酪爲肌。',64,'全唐诗/poet.song.174000.json','["菊後梅前冷落時，剪檀雕蠟酪爲肌。", "人從老處親平淡，花向無中補闕虧。", "地暖不憂春近遠，窗空惟映月參差。", "病夫久廢盧仝椀，鼻觀從容聖得知。"]'),
('3027f680-263a-47d7-8284-0c6024de14bf','次韻晦父喜雨詩','曹彥約','宋','宋诗','song-poetry','','[]','何處鳴鳩只好音，誰家孝婦有冤心。',64,'全唐诗/poet.song.174000.json','["何處鳴鳩只好音，誰家孝婦有冤心。", "古來禋祀關仍叔，今日兵饑憶華歆。", "王制不堪乖用仂，春秋從此却書霖。", "君詩好似靈湫水，清絕無人測淺深。"]'),
('b7e9846c-737e-4b64-9b8b-3384673b8354','同官約賦紅梅成五十六字','曹彥約','宋','宋诗','song-poetry','','[]','淡中著色似狂顛，心與梅同迹不然。',64,'全唐诗/poet.song.174000.json','["淡中著色似狂顛，心與梅同迹不然。", "奪我焉支寧免俗，豈無膏沐獨爭先。", "辨桃認杏何人拙，壓雪欺霜政自妍。", "只恐東君招不得，好修猶在竹籬邊。"]'),
('5860f244-a209-46d1-abcd-c83d4b709a3d','落星寺','曹彥約','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','好風好雨舊關情，落在江心不强名。',64,'全唐诗/poet.song.174000.json','["好風好雨舊關情，落在江心不强名。", "地盡匡廬猶變現，水連彭蠡略崢嶸。", "金山但設魚龍險，灧澦空聞象馬驚。", "爭似清暉樓上好，重湖九疊互分明。"]'),
('c0fe4bc1-ec85-4482-91a6-ef80a2dccde9','送子通司法之官括蒼','曹彥約','宋','宋诗','song-poetry','','[]','議禮蠲租兩有聲，老坡元不計身榮。',64,'全唐诗/poet.song.174000.json','["議禮蠲租兩有聲，老坡元不計身榮。", "爲民受屈今誰似，有子能傳近得名。", "此去掾曹無暖席，是中科律定持衡。", "公餘更欲翻經籍，古道時才孰重輕。"]'),
('aba029cd-5473-4ff0-a523-2add30a290c4','答趙守見貽之韻','曹彥約','宋','宋诗','song-poetry','','[]','已報新題下紫泥，尚留佳讖築新隄。',64,'全唐诗/poet.song.174000.json','["已報新題下紫泥，尚留佳讖築新隄。", "一心國事忉忉在，萬口民歌剪剪齊。", "惜去轍須田父卧，催歸詔有內臣齎。", "舍人若問朝天日，割盡黄雲水滿犁。"]'),
('77718f38-f92a-4d27-88f5-34c97bbe6a47','送趙戶侍出守鎮江','曹彥約','宋','宋诗','song-poetry','','[]','都人車馬閙城闉，似惜民曹更牧民。',64,'全唐诗/poet.song.174000.json','["都人車馬閙城闉，似惜民曹更牧民。", "到處忠勤無粉飾，入朝言語有經綸。", "只今次輔須賢帥，自古維城必懿親。", "報政不須三五月，姓名端的記嚴宸。"]'),
('9bcb2059-2c49-4100-8318-d88eec6c7a4e','和三十郎蠟梅韻','曹彥約','宋','宋诗','song-poetry','','[]','官黄新賜極恩榮，花不同梅與共名。',64,'全唐诗/poet.song.174000.json','["官黄新賜極恩榮，花不同梅與共名。", "頗謂寒中宜作伴，想因開早更爲兄。", "世間何物疑真蠟，海上新來染碎瓊。", "體得自香天分好，金塗銅砌却崢嶸。"]'),
('1f534c9c-d3f7-4566-8573-cda0c01b2e9a','久雨歎','曹彥約','宋','宋诗','song-poetry','','[]','誰爲戎首起邊功，萬里生靈一擲中。',64,'全唐诗/poet.song.174000.json','["誰爲戎首起邊功，萬里生靈一擲中。", "天爲憂之連作雨，人無識者驟歌風。", "所期闢地今城守，不善因糧却火攻。", "古道君師意深遠，改絃端的奏膚公。"]'),
('ea8b3f57-b840-41ef-9cfb-cfcaab61b9ac','秋分後十日得暴雨','曹彥約','宋','宋诗','song-poetry','','[]','負固驕陽不忍回，執迷凉意誤驚猜。',64,'全唐诗/poet.song.174000.json','["負固驕陽不忍回，執迷凉意誤驚猜。", "傾盆雨勢疑飛瀑，揭地風聲敵迅雷。", "階下决明添意氣，庭前甘菊賸胚胎。", "可憐歲事今如此，麥壠蔬畦尚可培。"]'),
('91acb011-9108-4bc6-9c56-d169ce0909e7','豫章賀丁漕建臺宴口號','曹彥約','宋','宋诗','song-poetry','','[]','車馬盈門撥不開，綵衣新著繡衣來。',64,'全唐诗/poet.song.174000.json','["車馬盈門撥不開，綵衣新著繡衣來。", "壯懷風月歸英簜，滿意江山入酒盃。", "便覺陽和通嶰竹，已知春信到官梅。", "西江豈是留人處，築得沙堤喚得回。"]'),
('1e54ab35-4230-4d53-8ba3-ac53cd274a4e','晚梅','曹彥約','宋','宋诗','song-poetry','','[]','去年浮月動微薰，隕籜憂寒正雜羣。',64,'全唐诗/poet.song.174000.json','["去年浮月動微薰，隕籜憂寒正雜羣。", "今日得春張萬玉，采繁迎煖尚從軍。", "花時十月連正月，歲事三分占一分。", "酒煮和羹還好在，預除蕪穢莫紛紛。"]'),
('13b25a39-91b8-4359-97c2-2286f180a3cd','湖莊謝客','曹彥約','宋','宋诗','song-poetry','','[]','漸撤疎籬短作垣，與春期約老田園。',64,'全唐诗/poet.song.174000.json','["漸撤疎籬短作垣，與春期約老田園。", "晴多易得花開早，地迥難藏鳥語喧。", "我欲偷安頻謝客，人誰見許數敲門。", "定知桃李平生誤，下已成蹊漫不言。"]'),
('5105512f-2c80-44ad-bea7-4a8b9cdd38ba','朔日迎客之章諸賢多有和者使君再賦仍次韻以謝','曹彥約','宋','宋诗','song-poetry','','[]','霜清石出水分流，邂逅騷人得志秋。',64,'全唐诗/poet.song.174000.json','["霜清石出水分流，邂逅騷人得志秋。", "落日斷霞增逸氣，小窗低戶媿英游。", "苦無酒量能陪飲，只有詩盟可避愁。", "此地何哉添此瑞，建章新識九牙騶。"]'),
('d692781b-ca55-4f2b-b2a1-d3279df52017','飄飄臺','曹彥約','宋','宋诗','song-poetry','','[]','清風怒折腰，斷送斜川歸。',24,'全唐诗/poet.song.174000.json','["清風怒折腰，斷送斜川歸。", "吾今已歸了，無用頻吹衣。"]'),
('40528e4c-efd7-4449-9d3d-3da356d3c2ec','經丘臺','曹彥約','宋','宋诗','song-poetry','','[]','尋壑初不憚，經丘亦忘疲。',24,'全唐诗/poet.song.174000.json','["尋壑初不憚，經丘亦忘疲。", "人見崎嶇處，不知心坦夷。"]'),
('0c2d6bb1-7aca-484d-ba28-e8cf1eccf495','祁門道中即事  其一','曹彥約','宋','宋诗','song-poetry','','[]','識面山川尚可尋，跳丸日月更相侵。',32,'全唐诗/poet.song.174000.json','["識面山川尚可尋，跳丸日月更相侵。", "語音改道家山近，行色不知春事深。"]'),
('4f2d9b1e-3d11-4b01-b27e-ddd5506fbefe','祁門道中即事  其二','曹彥約','宋','宋诗','song-poetry','','[]','社雨初晴舊燕歸，春膏潜動小鮮肥。',32,'全唐诗/poet.song.174000.json','["社雨初晴舊燕歸，春膏潜動小鮮肥。", "桃花未必隨人去，飛向行人行處飛。"]'),
('e29bd11f-a2e1-47cf-9ec6-80f3c48b270c','祁門道中即事  其三','曹彥約','宋','宋诗','song-poetry','','[]','餠餌商量全孕麥，衣裳消息半芽桑。',32,'全唐诗/poet.song.174000.json','["餠餌商量全孕麥，衣裳消息半芽桑。", "山堂草色夢魂遠，官路柳絲心緒長。"]'),
('e6739b27-2681-4e28-a286-a7037c3b88a2','祁門道中即事  其四','曹彥約','宋','宋诗','song-poetry','','[]','爲愛幽鄉度遠村，支頤竚立愛山礬。',32,'全唐诗/poet.song.174000.json','["爲愛幽鄉度遠村，支頤竚立愛山礬。", "栗留尚惜輕求友，反舌紛紛亦巧言。"]'),
('5a1cf8d8-dbf2-40c0-b43e-2929090c3ae1','祁門道中即事  其五','曹彥約','宋','宋诗','song-poetry','','[]','修竹圍牆草護階，賞花庭院已安排。',32,'全唐诗/poet.song.174000.json','["修竹圍牆草護階，賞花庭院已安排。", "洛陽忠孝家何在，不貢姚黄更緬懷。"]'),
('14161fde-4d10-468d-941e-1178a5fc0110','祁門道中即事  其六','曹彥約','宋','宋诗','song-poetry','','[]','嶂疊巒層巧送青，一溪幽處小園亭。',32,'全唐诗/poet.song.174000.json','["嶂疊巒層巧送青，一溪幽處小園亭。", "誰能換得王維手，洗我塵埃作畫屏。"]'),
('308379cc-2686-4b6a-96e2-fa50b6ebdaef','祁門道中即事  其七','曹彥約','宋','宋诗','song-poetry','','[]','絃誦琅琅兩岸聞，此風尤足張吾軍。',32,'全唐诗/poet.song.174000.json','["絃誦琅琅兩岸聞，此風尤足張吾軍。", "兒童相顧驚相問，莫是當年舊主人。"]'),
('fa914dfb-e6e4-4e22-865f-a3cf07998e52','祁門道中即事  其八','曹彥約','宋','宋诗','song-poetry','','[]','山木陰陰繫晚牛，水田漠漠任春鷗。',32,'全唐诗/poet.song.174000.json','["山木陰陰繫晚牛，水田漠漠任春鷗。", "長歌大笑却歸去，長在農家今白頭。"]'),
('1a50db14-7330-4198-bc67-b253eb8420bb','祁門道中即事  其九','曹彥約','宋','宋诗','song-poetry','','[]','半淪溪谷半山岡，地狹民多盡蓋藏。',32,'全唐诗/poet.song.174000.json','["半淪溪谷半山岡，地狹民多盡蓋藏。", "爭道去年小豐稔，至今租米正輸王。"]'),
('4455927d-1d58-41ae-8548-e2f15b2cea90','祁門道中即事  其一○','曹彥約','宋','宋诗','song-poetry','','[]','古來遺逸野人家，石磴崎嶇閣道斜。',32,'全唐诗/poet.song.174000.json','["古來遺逸野人家，石磴崎嶇閣道斜。", "犬吠人行都不問，杉籬空掩刺桐花。"]'),
('aa6f9677-e926-4122-ab0d-4a85cc86ba12','夜坐','曹彥約','宋','宋诗','song-poetry','','[]','道人心事略幽閒，落在星流羽檄間。',32,'全唐诗/poet.song.174000.json','["道人心事略幽閒，落在星流羽檄間。", "吏退燈明書到眼，袖爐烘煖鷓鴣斑。"]'),
('fc0f58b2-41a6-42e0-9871-bb7cb91517f7','偶成  其一','曹彥約','宋','宋诗','song-poetry','','[]','曩疑先賢嗇于言，何不明明細細傳。',32,'全唐诗/poet.song.174000.json','["曩疑先賢嗇于言，何不明明細細傳。", "今省從前都錯認，更加詳後即紛然。"]'),
('2072fc3c-ad6e-4108-aa0d-ad703260d33a','偶成  其二','曹彥約','宋','宋诗','song-poetry','','[]','夫子文章不用爲，從心到口沒參差。',32,'全唐诗/poet.song.174000.json','["夫子文章不用爲，從心到口沒參差。", "咄哉韓子休汙我，却道詩葩與易奇。"]'),
('f98b6100-ad4a-4d66-8d98-0cd978dd14d8','偶成  其三','曹彥約','宋','宋诗','song-poetry','','[]','雪月風花總不知，雕奇鏤巧學支離。',32,'全唐诗/poet.song.174000.json','["雪月風花總不知，雕奇鏤巧學支離。", "四時多少閒光景，無箇閒人領略伊。"]'),
('c4eedd8d-a5a9-4b9c-8191-93c929ef9e7b','偶成  其四','曹彥約','宋','宋诗','song-poetry','','[]','勿學唐人李杜癡，作詩須作古人詩。',32,'全唐诗/poet.song.174000.json','["勿學唐人李杜癡，作詩須作古人詩。", "世傳李杜文章伯，問著關雎恐不知。"]'),
('ecc62db3-1dce-4132-bbaf-f019012f63a4','偶成  其五','曹彥約','宋','宋诗','song-poetry','','[]','詩癡正自不煩攻，只爲英才輒墮中。',32,'全唐诗/poet.song.174000.json','["詩癡正自不煩攻，只爲英才輒墮中。", "今日已成風俗後，後生箇箇入樊籠。"]'),
('91330b01-37f3-4bf6-9f6d-da3b97c070e7','偶成  其六','曹彥約','宋','宋诗','song-poetry','','[]','儒風一變至于道，此是堯夫未識儒。',32,'全唐诗/poet.song.174000.json','["儒風一變至于道，此是堯夫未識儒。", "除却儒風如更有，將馿騎了復尋馿。"]'),
('a4909ab0-1ee2-45f0-87db-7a79a678caa3','偶成  其七','曹彥約','宋','宋诗','song-poetry','','[]','當敬不敬謂之悖，當正不正謂之諛。',32,'全唐诗/poet.song.174000.json','["當敬不敬謂之悖，當正不正謂之諛。", "是中適莫俱難著，意態微生已覺疏。"]'),
