('c9a3818e-5a92-4259-ae03-5dce66b504bf','蜀海棠','曹彥約','宋','宋诗','song-poetry','','[]','西蜀佳人巧欲言，紅酣猶带醉時魂。',32,'全唐诗/poet.song.174000.json','["西蜀佳人巧欲言，紅酣猶带醉時魂。", "子規叫斷黄昏後，却憶鄉情染露痕。"]'),
('cd3df1cc-53e3-4c31-8df3-1e146ae59f7b','餘干史子固本知縣趨朝便舟見訪以四絕句敘舊次其韻  其一','曹彥約','宋','宋诗','song-poetry','','[]','再拜新篇極主臣，詠真何必更尋真。',32,'全唐诗/poet.song.174000.json','["再拜新篇極主臣，詠真何必更尋真。", "論心十八年前事，詩律交情更可人。"]'),
('8956a4d5-d246-4927-9bb9-60ebc9d4aa0c','餘干史子固本知縣趨朝便舟見訪以四絕句敘舊次其韻  其二','曹彥約','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','虎榜初傳淡墨名，饒山何重泰山輕。',32,'全唐诗/poet.song.174000.json','["虎榜初傳淡墨名，饒山何重泰山輕。", "日邊未得春風力，江右惟高月旦評。"]'),
('31132718-ee44-4467-b14b-97287561021b','餘干史子固本知縣趨朝便舟見訪以四絕句敘舊次其韻  其三','曹彥約','宋','宋诗','song-poetry','','[]','仕已都無喜慍三，有弦不解但操南。',32,'全唐诗/poet.song.174000.json','["仕已都無喜慍三，有弦不解但操南。", "歸來穩上論思直，政爾民情已熟諳。"]'),
('455deeab-40d2-4bf4-a691-6addebdc89d0','餘干史子固本知縣趨朝便舟見訪以四絕句敘舊次其韻  其四','曹彥約','宋','宋诗','song-poetry','','[]','豈無魚鴈懶傳書，枯枿春風不用噓。',32,'全唐诗/poet.song.174000.json','["豈無魚鴈懶傳書，枯枿春風不用噓。", "只有簡編遮眼在，馬牛猶得遠襟裾。"]'),
('84ea1771-cfb9-4c9a-8e79-bb5d503ee99f','迎春花  其一','曹彥約','宋','宋诗','song-poetry','','[]','錦作薰籠越樣新，迎春猶及送還春。',32,'全唐诗/poet.song.174000.json','["錦作薰籠越樣新，迎春猶及送還春。", "花時色與香如此，花後娟娟更可人。"]'),
('380606d6-2cfd-45ce-baf6-b8be149a2edc','迎春花  其二','曹彥約','宋','宋诗','song-poetry','','[]','睡入華胥日未曛，博山何在寶香聞。',32,'全唐诗/poet.song.174000.json','["睡入華胥日未曛，博山何在寶香聞。", "覺來但有南窗靜，葉瘦花肥醉錦薰。"]'),
('77774e30-2f1c-4f8b-adfa-3af338247728','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其一','曹彥約','宋','宋诗','song-poetry','','[]','照人精采駐元戎，與我驅馳錄近功。',32,'全唐诗/poet.song.174000.json','["照人精采駐元戎，與我驅馳錄近功。", "想見玉簫聲遠夜，亂芟篁竹剉春葱。"]'),
('f29634b9-da0d-4a1c-8c10-3715dca744c4','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其二','曹彥約','宋','宋诗','song-poetry','','[]','新來鈇鉞授當才，嶽下浮雲日日開。',32,'全唐诗/poet.song.174000.json','["新來鈇鉞授當才，嶽下浮雲日日開。", "易得成功難更好，鼎和諸將熟栽培。"]'),
('bbb8b5f9-40f8-4cfd-8c1e-ff4341314672','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其三','曹彥約','宋','宋诗','song-poetry','','[]','謾捐儋耳非長策，便戮先零亦少恩。',32,'全唐诗/poet.song.174000.json','["謾捐儋耳非長策，便戮先零亦少恩。", "整了六師須禁暴，本朝元氣要長存。"]'),
('e797ec80-e801-48e0-abe0-2985d1b761d0','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其四','曹彥約','宋','宋诗','song-poetry','','[]','深居處女靜無粧，脫兔飛時勢莫當。',32,'全唐诗/poet.song.174000.json','["深居處女靜無粧，脫兔飛時勢莫當。", "已捷不須三舍避，便將戰處入耕桑。"]'),
('db644fd2-8e47-44a1-b055-5a40d204edbd','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其五','曹彥約','宋','宋诗','song-poetry','','[]','爭先報國恥非夫，過後論功失故吾。',32,'全唐诗/poet.song.174000.json','["爭先報國恥非夫，過後論功失故吾。", "志士斗量賢士少，赤松遊處智名無。"]'),
('f481ad9d-f6c2-42f2-a313-e046e8565b67','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其六','曹彥約','宋','宋诗','song-poetry','','[]','並轡遊人任往來，透牆春色已安排。',32,'全唐诗/poet.song.174000.json','["並轡遊人任往來，透牆春色已安排。", "花時却記梅前事，秀水如何不永懷。"]'),
('aac885fd-507c-4356-89a9-36926eb2773b','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其七','曹彥約','宋','宋诗','song-poetry','','[]','憂世愁腸轉斷蓬，趨時好色上芳藂。',32,'全唐诗/poet.song.174000.json','["憂世愁腸轉斷蓬，趨時好色上芳藂。", "古來只有春平直，披拂年來也不公。"]'),
('5fa6a8bb-ffb9-49a6-81f8-9725b9dc0574','奉陪黄帥機訪問元夕戰場歸塗見人家園池花木相與歎息既帥機書前所作八詩示滕審言不及予也枕上不能記韻傚唐人和詩體自賦八絕句因以寓意  其八','曹彥約','宋','宋诗','song-poetry','','[]','爲渠著姓黄山谷，結友齊名杜審言。',32,'全唐诗/poet.song.174000.json','["爲渠著姓黄山谷，結友齊名杜審言。", "領略殘膏沾丐我，彊書酬唱入坡門。"]'),
('1c625563-e1e1-4a66-8228-67020e4072eb','催花','曹彥約','宋','宋诗','song-poetry','','[]','催花徑裏日千回，祗恐催開落又催。',32,'全唐诗/poet.song.174000.json','["催花徑裏日千回，祗恐催開落又催。", "老性只宜風雨後，綠陰青子款相陪。"]'),
('ca21de47-c58d-4076-8d91-ef2ffda8a0b3','道傍得熟人家','曹彥約','宋','宋诗','song-poetry','','[]','舊雨留煙飾短垣，淺沙催水撼衡門。',32,'全唐诗/poet.song.174000.json','["舊雨留煙飾短垣，淺沙催水撼衡門。", "旗帘動眼新迎客，䆉䅉關心故弄孫。"]'),
('814cff45-3e25-4e3f-a45f-f595e28c0558','縣郭新居人家','曹彥約','宋','宋诗','song-poetry','','[]','苟簡誅茅勝野盤，託身城郭愛平安。',32,'全唐诗/poet.song.174000.json','["苟簡誅茅勝野盤，託身城郭愛平安。", "五更人語驚雞犬，壁漏簷疎共一寒。"]'),
('299cff6f-8be1-4871-a758-f5017a6cc8cd','荷花','曹彥約','宋','宋诗','song-poetry','','[]','寫遍階頭萬葉紅，不成無味只書空。',32,'全唐诗/poet.song.174000.json','["寫遍階頭萬葉紅，不成無味只書空。", "絳綃剝盡紅酥凸，給與煩襟作冷風。"]'),
('ad134c1f-3f5b-43d6-a7ed-d65d734402ce','漢陰縣驛有連理山茶舊嘗遠送上官擾及百姓根條槎牙鄰於戕賊乾道初有使者沮其事今婆娑蓊蔚爲一邑壯觀因見何令壁間所書賦二十八字','曹彥約','宋','宋诗','song-poetry','','[]','逞艷呈祥祇自殲，何人攫取更趨炎。',32,'全唐诗/poet.song.174000.json','["逞艷呈祥祇自殲，何人攫取更趨炎。", "只將勿剪看君子，愛物安民處己廉。"]'),
('fe45b429-566b-4cfa-a510-b924b5976410','謝朱鶴皋招飲四詩  其一','曹彥約','宋','宋诗','song-poetry','','[]','過雨桃花墜晚紅，及時庭草翠翻風。',32,'全唐诗/poet.song.174000.json','["過雨桃花墜晚紅，及時庭草翠翻風。", "倚窗細究天人理，六籍元無一字空。"]'),
('84ba7ae1-e8c0-4892-9efd-28502e82d1d3','謝朱鶴皋招飲四詩  其二','曹彥約','宋','宋诗','song-poetry','','[]','東皇無意染青紅，長養猶資五日風。',32,'全唐诗/poet.song.174000.json','["東皇無意染青紅，長養猶資五日風。", "收拾英華入新句，祥雲藹藹媚春空。"]'),
('77f4f592-39f1-4518-8b37-0a7144a4cc7d','謝朱鶴皋招飲四詩  其三','曹彥約','宋','宋诗','song-poetry','','[]','石火能留幾許紅，人生南北馬牛風。',32,'全唐诗/poet.song.174000.json','["石火能留幾許紅，人生南北馬牛風。", "春光倒指無多日，相遇休辭酒盞空。"]'),
('f8219d37-ff50-4b77-bb36-bb0a69058961','謝朱鶴皋招飲四詩  其四','曹彥約','宋','宋诗','song-poetry','','[]','六年奔走汗顔紅，此日行吟兩袖風。',32,'全唐诗/poet.song.174000.json','["六年奔走汗顔紅，此日行吟兩袖風。", "俗慮湔磨有詩冊，凈看明月照長空。"]'),
('7f539ff0-ffc3-41aa-b812-ca7a721c50e0','偶作  其一','曹彥約','宋','宋诗','song-poetry','','[]','此天然處不亦妙，費盡思量却不到。',48,'全唐诗/poet.song.174000.json','["此天然處不亦妙，費盡思量却不到。", "有時父召急趨前，不覺不知造淵奧。", "此時合勒承認狀，從古癡頑何不曉。"]'),
('33a6e545-cbd6-4d68-b42c-d36fc5dd0bfb','偶作  其二','曹彥約','宋','宋诗','song-poetry','','[]','太極奚河圖，河圖非太極。',96,'全唐诗/poet.song.174000.json','["太極奚河圖，河圖非太極。", "矧復贅無極，哀哉何太息。", "何不觀古聖，一一已默識。", "□湖爲作圖，交擾而曲屈。", "是孰知五行，五行皆妙質。", "不可離合論，渾渾體自一。", "安得孔子生，邪說俱蕩滌。", "哀哉復哀哉，太息復太息。"]'),
('25bc2258-e1a3-4c38-a591-a56469a9bc5a','朝梳怨','曹彥約','宋','宋诗','song-poetry','','[]','朝梳九疊雲，到暮不成雨。',72,'全唐诗/poet.song.174000.json','["朝梳九疊雲，到暮不成雨。", "一日變千絲，只作愁機杼。", "愁至雲成幕，小雨和絲落。", "愁去臉成霞，雨霽庭下花。", "折花愁雨濕，護惜鮫綃立。", "蜂蝶愛花紅，花心應未同。"]'),
('ec926232-f084-48f0-b384-1b9e2932b703','酬楊伯洪','曹彥約','宋','宋诗','song-poetry','','[]','扁舟下峽七經年，猶憶西民困備邊。',64,'全唐诗/poet.song.174000.json','["扁舟下峽七經年，猶憶西民困備邊。", "已病一夫空有議，誤謀元帥本非賢。", "公朝慮蜀天常近，之子憂時火未然。", "遇合却留經濟用，此行應不媿登仙。"]'),
('f30987bf-ac15-41ef-9091-2bf10914685a','借詩話於應祥弟有不許點抹之約作詩戲之','危稹','宋','宋诗','song-poetry','','[]','我有讀書癖，每喜以筆界。',180,'全唐诗/poet.song.174000.json','["我有讀書癖，每喜以筆界。", "抹黄飾句眼，施朱表事派。", "此手定權衡，衆理析畎澮。", "歷歷燦可觀，開卷如畫繪。", "知君篤友于，因從借詩話。", "過手有約言，不許一筆壞。", "自語落我耳，便覺意生械。", "明朝試靜觀，議論頗澎湃。", "讀到會意處，時時欲犯戒。", "將舉手復止，火側禁搔疥。", "技癢無所施，悶懷時一噫。", "只可捲還君，如此讀不快。", "千駟容可輕，君抱亦少隘。", "昨問雞林人，尚有此編賣。", "典衣須一收，吾炙當痛嘬。"]'),
('2d8281aa-21f4-4bae-938b-5dedc5e3d1b8','上隆興趙帥','危稹','宋','宋诗','song-poetry','','[]','買宅須買千萬鄰，季雅喜得王僧珍。',288,'全唐诗/poet.song.174000.json','["買宅須買千萬鄰，季雅喜得王僧珍。", "買山百萬復誰與，襄陽節度真主人。", "我生兀兀鑽蠹簡，不肯低頭植資産。", "綴名虎榜二十年，依舊酸寒廣文飯。", "綠鬢半作星星華，豈堪風雨猶無家。", "大鵬小鷃各自適，只有鴻鴈長汀沙。", "弟昆團欒雖足樂，老屋蕭條不堪著。", "玉堂便是無骨相，也合專儂一丘壑。", "近來卜築窮冥搜，十里而近依松楸。", "驪龍塘上鄧家丘，半山老人所釣遊。", "半山天下文章伯，鄧家聲名亦輝赫。", "斷碑猶在古牆陰，好句曾經寫山色。", "買鄰得此天所予，獨欠山資無覓處。", "平生駡錢作阿堵，倉卒呼渠寧肯顧。", "君侯地位高入雲，筆所到處皆成春。", "萬間廣厦芘許遠，豈無一室棲貧身。", "王鄧故處爲鄰曲，更得趙侯錢買屋。", "便哦詩句謝山神，飲水也勝樽酒綠。"]'),
('3456ea98-8751-4f9e-b31a-55594f2a87e7','鶴','危稹','宋','宋诗','song-poetry','','[]','楚楚雪衣明，煙霞徑裏行。',48,'全唐诗/poet.song.174000.json','["楚楚雪衣明，煙霞徑裏行。", "不管陶令野，有節伯夷清。", "一見消塵慮，相親長道情。", "秋風著梧葉，時作九臯聲。"]'),
('4388a467-fe8c-461a-8939-1a56de8a4ebd','王架閣夙有棋癖嘗於和篇中譏其不工架閣頗諱惡其說復次韵戲之','危稹','宋','宋诗','song-poetry','','[]','劉伶耽於酒，淵明玩於菊。',168,'全唐诗/poet.song.174000.json','["劉伶耽於酒，淵明玩於菊。", "君乃癖於文，愛棋尤更篤。", "文高新掌故，棋只前祕讀。", "我昨却萊兵，書法謹夾谷。", "不知君諱之，護名如護玉。", "耻鼓趙王瑟，欲舉漸離筑。", "明發疾呼予，開枰數反覆。", "盛氣欲吞敵，厲響亦驚俗。", "失利頳湊頰，得雋喜填腹。", "勢固健於常，手終弱於僕。", "君名高天下，此特一不足。", "小負毋重爭，旁觀有靜矚。", "大明昧於小，月固不勝燭。", "切勿罪劉五，此筆兢所錄。"]'),
('8114a8bd-5b2d-4557-bf97-4c465464329c','題楊妃牙痛圖','危稹','宋','宋诗','song-poetry','','[]','痛入香齦是不禁，三郎心痛亦何深。',32,'全唐诗/poet.song.174000.json','["痛入香齦是不禁，三郎心痛亦何深。", "當時更有唇亡處，自是君王不動心。"]'),
('34892716-155a-42d8-b2f1-93a56e9113e9','挽同年胡司門','危稹','宋','宋诗','song-poetry','','[]','期集盟惟舊，交承契更深。',48,'全唐诗/poet.song.174000.json','["期集盟惟舊，交承契更深。", "雨聲春共酌，燈影夜同吟。", "接武方堯殿，招魂遽楚音。", "尤憐哭君日，來納惜時金。"]'),
