('bd9638ec-87f1-4cbf-b9d9-0db6df21165b','聞鶑','危稹','宋','宋诗','song-poetry','','[]','天上金衣侶，還能貺草萊。',48,'全唐诗/poet.song.174000.json','["天上金衣侶，還能貺草萊。", "風流晉王謝，言語漢鄒枚。", "公等久安在，今從何處來。", "山禽正嘈雜，慰我日徘徊。"]'),
('fb6940cd-8cca-4224-9290-f2dc25df55a7','送孫行之出守衡陽','危稹','宋','宋诗','song-poetry','','[]','日日江頭送客行，況聞君去作專城。',64,'全唐诗/poet.song.174000.json','["日日江頭送客行，況聞君去作專城。", "心存臣子無中外，士繫朝廷有重輕。", "諫疏滿懷催上道，中原萬事想關情。", "戎葵到底還傾日，側耳衡陽來鴈聲。"]'),
('5bafdeab-dbc2-46c2-bb76-d7ac5bb5340b','挽月湖二首  其一','危稹','宋','宋诗','song-poetry','','[]','天胡奪我老先生，軒冕叢中玉雪清。',64,'全唐诗/poet.song.174000.json','["天胡奪我老先生，軒冕叢中玉雪清。", "英石數拳歸艇重，月湖千頃世緣輕。", "雲山買得無餘俸，句法流將不盡名。", "頭白賈生非不遇，所言向已略施行。"]'),
('4c1500a3-e26c-4065-8265-f50bdf41ea23','挽月湖二首  其二','危稹','宋','宋诗','song-poetry','','[]','詔書屢趣入承明，黄閣前頭不肯登。',64,'全唐诗/poet.song.174000.json','["詔書屢趣入承明，黄閣前頭不肯登。", "苦欲歸休同野老，本來清浄是禪僧。", "苔生文塔今成古，影掛山房喚不譍。", "猶想經行泉石處，倚巖憔悴一枯藤。"]'),
('3b5df7bd-a32f-4d04-b605-4356ebbd106b','送晁告院得南康','危稹','宋','宋诗','song-poetry','','[]','我是康廬舊冷官，夢魂今尚憶雲端。',64,'全唐诗/poet.song.174000.json','["我是康廬舊冷官，夢魂今尚憶雲端。", "山將草色到天碧，泉带松聲出谷寒。", "仙觀幾年留鶴隠，古潭有日起龍蟠。", "史君肯著詩料理，乞我蠻牋半幅看。"]'),
('1835a3c6-a06c-459b-8067-d57780f10dc7','上趙總領','危稹','宋','宋诗','song-poetry','','[]','一見煩公道眼明，懸知徹底五湖清。',64,'全唐诗/poet.song.174000.json','["一見煩公道眼明，懸知徹底五湖清。", "豈期天上張公子，猶記當年劉更生。", "幾度夜深流水操，無人心認斷腸聲。", "平生不面却相識，黄鶴樓前今一鳴。"]'),
('ef31c078-1455-4c8d-887c-a100c54eab6a','接客篇','危稹','宋','宋诗','song-poetry','','[]','接客接客，高亦接，低亦接。',61,'全唐诗/poet.song.174000.json','["接客接客，高亦接，低亦接。", "大兒穩善會傳茶，小兒踉蹡能作揖。", "家人不用翦髻雲，我典唐書充饌設。", "唐書典了猶可贖，賓客不來門戶俗。"]'),
('d343b078-08be-4769-a485-e0b64ce7561f','郭公篇','危稹','宋','宋诗','song-poetry','','[]','郭公郭公，聞爾失國春秋時，何事到此猶悲啼。',77,'全唐诗/poet.song.174000.json','["郭公郭公，聞爾失國春秋時，何事到此猶悲啼。", "郭公前言亡國故，當時只緣臣子誤。", "百年社稷不得歸，而今家住柘岡西。", "滿目春風都是恨，聲聲說與齊侯知。", "國亡矣，君勉之。"]'),
('5e52864e-0a65-4eaa-8fde-533b3555c59d','婦歎','危稹','宋','宋诗','song-poetry','','[]','記得蕭郎登第時，謂言即日鳳皇池。',32,'全唐诗/poet.song.174000.json','["記得蕭郎登第時，謂言即日鳳皇池。", "而今老等閒官職，日欠人錢夜欠詩。"]'),
('58074127-f221-4502-b2aa-b042a8094317','牽牛花','危稹','宋','宋诗','song-poetry','','[]','青青柔蔓遶修篁，刷翠成花著處芳。',32,'全唐诗/poet.song.174000.json','["青青柔蔓遶修篁，刷翠成花著處芳。", "應是折從河鼓手，天孫斜插鬢雲香。"]'),
('490fdd82-620f-4ce9-859a-a5eda89eb72c','送柴中行出守章貢','危稹','宋','宋诗','song-poetry','','[]','力爲君王乞得州，補天未了石還收。',64,'全唐诗/poet.song.174000.json','["力爲君王乞得州，補天未了石還收。", "人才自係國輕重，吾道亦關公去留。", "殿角纔辭槐影日，船頭便轉荻花秋。", "競誇祖帳都門外，誰識眉攢杜甫愁。"]'),
