('a58831a6-924c-4f6c-9ff7-de6bbc6d8f9a','省齋吟','金朋說','宋','宋诗','song-poetry','','[]','修己師曾子，爲人謀必忠。',24,'全唐诗/poet.song.174000.json','["修己師曾子，爲人謀必忠。", "信誠交以道，傳習熟加工。"]'),
('7096e1be-c943-4db9-a9b5-cfba09d2474e','夏日山居','金朋說','宋','宋诗','song-poetry','','[]','時當夏日臨，酷暑避無地。',24,'全唐诗/poet.song.174000.json','["時當夏日臨，酷暑避無地。", "唯對碧巖山，清凉又安逸。"]'),
('1ee528a8-26a2-477f-be32-dc2297b6ce3f','種豆吟','金朋說','宋','宋诗','song-poetry','','[]','南畝種豆苗，苗稀草猶勝。',24,'全唐诗/poet.song.174000.json','["南畝種豆苗，苗稀草猶勝。", "農人費鋤耘，凶穢何不凈。"]');
